-- Poems batch 288
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('cca308d3-10fd-45cf-ba45-fcde53d06f95','題吳寺','傅夢得','宋','宋诗','song-poetry','','[]','不到吳墳久，重來又七春。',48,'全唐诗/poet.song.253000.json','["不到吳墳久，重來又七春。", "山巒如舊識，猿鶴復相親。", "往事皆成夢，清游不厭頻。", "倦行難喚酒，信步出湖濱。"]'),
('5966728a-c1d0-45bf-98b5-40b19cd7a4db','讀夷齊傳','傅夢得','宋','宋诗','song-poetry','','[]','要使清風激懦頑，餓夫寧死首陽山。',32,'全唐诗/poet.song.253000.json','["要使清風激懦頑，餓夫寧死首陽山。", "當年若食周家粟，未必名垂萬古間。"]'),
('0fbba44d-a5df-4120-9e2c-541d96720c83','食河豚','周晞稷','宋','宋诗','song-poetry','','[]','君不見楚王渡江萍如日，剖而食之甜似蜜。',194,'全唐诗/poet.song.253000.json','["君不見楚王渡江萍如日，剖而食之甜似蜜。", "河魨本自食楊花，花結浮萍萍結實。", "又不見越王食鱠遺其餘，中流化作王餘魚。", "河魨本是當年物，尚带西子胸前酥。", "春紅摇摇波頭暖，蔞蒿蒙茸蘆筍短。", "嫩肥初破鼈裙重，膩白細挑羊腦滿。", "嗟予二年留江城，嗜此不去遲吾行。", "鱸鮮便覺官可棄，雁美却得人呼卿。", "鄰翁勸我知機早，有毒傷人如鴆鳥。", "世間萬事是機穽，此外傷人亦非少。", "我生有命懸乎天，飽死終勝饑垂涎。", "君看子美牛炙嚴武尤可憐。"]'),
('46f65a5e-41c6-4c6e-b161-39b263158851','麴君','史安叔','宋','宋诗','song-poetry','','[]','冥搜渾不見詩蹤，却在陶然一醉中。',32,'全唐诗/poet.song.253000.json','["冥搜渾不見詩蹤，却在陶然一醉中。", "到得醒來詩又去，麴君那有許神通。"]'),
('d2796f22-26de-4194-bd50-608d31f32632','和惜梅','史安叔','宋','宋诗','song-poetry','','[]','雪飛渾不管梅嗔，都把寒來障却春。',32,'全唐诗/poet.song.253000.json','["雪飛渾不管梅嗔，都把寒來障却春。", "直恐雪欺渾凍損，那知雪後越精神。"]'),
('e8350e43-9b9a-4c63-9f8d-c5151a257d75','問梅','史安叔','宋','宋诗','song-poetry','','[]','瘦藤拄曉覓寒梅，着蕊南枝開未開。',32,'全唐诗/poet.song.253000.json','["瘦藤拄曉覓寒梅，着蕊南枝開未開。", "祇我往來亭下路，芒鞋顛倒印蒼苔。"]'),
('bca8c5f5-428f-4630-8b8a-e5688b294bc4','曉亭','史安叔','宋','宋诗','song-poetry','','[]','短褐衝風立曉亭，無端物物攪詩情。',32,'全唐诗/poet.song.253000.json','["短褐衝風立曉亭，無端物物攪詩情。", "梅邊正被寒山惱，又聽松梢衮雪聲。"]'),
('627583a7-281c-4778-9e49-61e9def13cfa','靜治堂書懷','史安叔','宋','宋诗','song-poetry','','[]','長揖薰風詠式微，譸張山鳥怪儒衣。',64,'全唐诗/poet.song.253000.json','["長揖薰風詠式微，譸張山鳥怪儒衣。", "竹君伴我尋詩瘦，梅子從誰學道肥。", "先自宦情如霧薄，可堪鄉夢與雲飛。", "支林堂下波光好，鷺笑鷗嗔胡不歸。"]'),
('b04c4ca8-1c32-456b-8298-36e16e0cb15a','謾成','史安叔','宋','宋诗','song-poetry','','[]','閑較新詩意未降，吟髭撚斷數莖霜。',32,'全唐诗/poet.song.253000.json','["閑較新詩意未降，吟髭撚斷數莖霜。", "忽然得句笑聲發，驚起花間蝶也狂。"]'),
('e54af6dd-e595-467f-b831-1c3fb4b61791','干丹陽宰乞米','史千','宋','宋诗','song-poetry','','[]','知君愛物與人民，敢造琴堂訴在陳。',32,'全唐诗/poet.song.253000.json','["知君愛物與人民，敢造琴堂訴在陳。", "斗水果能相活否，今年猶甚去年貧。"]'),
('b226ed0d-9c09-4c72-bf78-b8b72f59fd8a','素曲送酒','謝安國','宋','宋诗','song-poetry','','[]','簾外春風正落梅，須求狂藥解愁回。',32,'全唐诗/poet.song.253000.json','["簾外春風正落梅，須求狂藥解愁回。", "煩君玉指輕攏撚，慢撥死灰送一杯。"]'),
('bb3272ea-f27d-45b9-a332-0292ac707fc6','次韻智伯寄茶報酒三斗','謝安國','宋','宋诗','song-poetry','','[]','歡伯風流可解憂，疑君此外更何求。',32,'全唐诗/poet.song.253000.json','["歡伯風流可解憂，疑君此外更何求。", "揀芽投我真拋却，不是詩人薛許州。"]'),
('72dce045-caf0-4861-b188-12584c1dc6c0','止酒','呂耐軒','宋','宋诗','song-poetry','','[]','終年不舉酒，愛漱玉池津。',48,'全唐诗/poet.song.253000.json','["終年不舉酒，愛漱玉池津。", "自謂醒時好，誰知醒者嗔。", "貧交滋味薄，老眠是非真。", "拚死成何事，劉伶輩誤人。"]'),
('f0f737cd-4c34-4967-b6ba-ee950c51d036','煎茶','王翊龍','宋','宋诗','song-poetry','','[]','春霆發蕾抽新馥，榷吏窮搜不容粟。',64,'全唐诗/poet.song.253000.json','["春霆發蕾抽新馥，榷吏窮搜不容粟。", "是誰千金收寸芽，烹鼎車聲繞斜谷。", "白雲飄落甘露椀，清風吹破玉川屋。", "平生此腹負將軍，空攬十年燈火讀。"]'),
('3873a1bb-7f1b-4cfb-a2c5-f6e29c3cc833','謝王繡使同二教舉充講賓','王翊龍','宋','宋诗','song-poetry','','[]','繡衣玉斧下青冥，端爲斯文主夏盟。',64,'全唐诗/poet.song.253000.json','["繡衣玉斧下青冥，端爲斯文主夏盟。", "師道更全雙璧白，講堂初奏六莖清。", "秦灰不燼詩書種，孔壁猶鏗絲竹聲。", "惟有漁翁祇自嘆，談經敢望漢鴻生。"]'),
('e99d815c-4226-4c6b-ace3-2856bb5eaec2','懷胡怡齋府教','丁高林','宋','宋诗','song-poetry','','[]','未得多時別，無時不念君。',48,'全唐诗/poet.song.253000.json','["未得多時別，無時不念君。", "池深春草雨，天遠暮山雲。", "去雁情千里，殘蟬思十分。", "不知明月夜，曾復望鄉枌。"]'),
('d55cf27a-44b1-4c0b-9320-66d52c827acb','寄龍巖張節翁','丁高林','宋','宋诗','song-poetry','','[]','歸向龍巖巖下房，又添移竹種松忙。',64,'全唐诗/poet.song.253000.json','["歸向龍巖巖下房，又添移竹種松忙。", "江湖萬事孤燈夜，風月千篇滿鏡霜。", "日暮烏栖梧葉落，天晴雁過菊花香。", "誠知道義相忘處，豈恨雲山隔渺茫。"]'),
('7191b471-8e00-4806-8d8e-baf111c4c2a0','山','丁高林','宋','宋诗','song-poetry','','[]','東皇太一司花命，花落花開老歲華。',96,'全唐诗/poet.song.253000.json','["東皇太一司花命，花落花開老歲華。", "天地精英無着處，今朝開到牡丹花。", "千山桃李盡輿臺，獨有梅花是相材。", "定是傅巖傳得種，年年商正又花開。", "紅塵世界夢都迷，我正閑吟得意詩。", "夜氣清時天地別，梅花頭上看參旗。"]'),
('eaf86c11-a091-4b19-af9f-e1d700087ecd','山中吟','丁高林','宋','宋诗','song-poetry','','[]','萬紅千紫畫乾坤，綠染江南江北村。',32,'全唐诗/poet.song.253000.json','["萬紅千紫畫乾坤，綠染江南江北村。", "文鳥雙飛魚作隊，好花生子竹添孫。"]'),
('1ee334fe-d8ea-4e5d-8f7e-2a12f2684abf','村舍柳','丁高林','宋','宋诗','song-poetry','','[]','郵亭折盡爲分携，爭得長條拂地垂。',32,'全唐诗/poet.song.253000.json','["郵亭折盡爲分携，爭得長條拂地垂。", "何似竹籬茅舍畔，新年不減舊年枝。"]'),
('792c612a-ee9b-4178-a473-c17285e02712','對菊','丁高林','宋','宋诗','song-poetry','','[]','幾本僅成畦，山晴手自栽。',48,'全唐诗/poet.song.253000.json','["幾本僅成畦，山晴手自栽。", "花逢新過雁，根带舊移苔。", "正色通騷籍，清香入酒杯。", "儻無陶靖節，今古爲誰開。"]'),
('b26b1e66-0651-4ef7-8f80-58e230b3388e','卜居','丁高林','宋','宋诗','song-poetry','','[]','圯上求西舍，隆中買北鄰。',24,'全唐诗/poet.song.253000.json','["圯上求西舍，隆中買北鄰。", "種花行造化，移竹試經綸。"]'),
('67610bdd-9316-489f-aaa9-989c887eef8c','題石好山詩卷','丁高林','宋','宋诗','song-poetry','','[]','得趣貪山好，山翁清更癯。',48,'全唐诗/poet.song.253000.json','["得趣貪山好，山翁清更癯。", "琴詩立門戶，姓字出江湖。", "步月尋松子，鋤煙補菊株。", "相携多道義，誰可與同徒。"]'),
('f8b86356-2b2a-4bdf-bdab-5025637dee4b','月夜溪行懷富沙友','林石澗','宋','宋诗','song-poetry','','[]','溪光清淺碎瓊瑶，楊柳風柔酒漸消。',32,'全唐诗/poet.song.253000.json','["溪光清淺碎瓊瑶，楊柳風柔酒漸消。", "猶憶去年今夜月，照人同上水西橋。"]'),
('29635f06-7f08-4bba-aaba-38e821c134c0','雪中懷槐坡丹品','林石澗','宋','宋诗','song-poetry','','[]','昔同詩伴結清遊，亂折梅花當酒籌。',32,'全唐诗/poet.song.253000.json','["昔同詩伴結清遊，亂折梅花當酒籌。", "十二闌干風雪裏，玉人扶醉下西樓。"]'),
('20ac82f7-399b-4398-b36d-4f39e4599c21','潮後','林石澗','宋','宋诗','song-poetry','','[]','潮後菰蔣半带泥，隔林遥聽午時雞。',64,'全唐诗/poet.song.253000.json','["潮後菰蔣半带泥，隔林遥聽午時雞。", "江天漠漠雲帆遠，野日荒荒春鳥啼。", "石壁倒垂枯樹老，沙田平接亂山低。", "經行好處須摹取，收入詩囊付小奚。"]'),
('378f0660-4a1c-4adb-8158-23b75556b22b','燕','林石澗','宋','宋诗','song-poetry','','[]','年年因社到，海闊翅飛低。',48,'全唐诗/poet.song.253000.json','["年年因社到，海闊翅飛低。", "故國傷新別，空梁憶舊棲。", "暮簾疏竹雨，春岸落花泥。", "紅線今何在，香愁滿綉閨。"]'),
('1c1afc92-15a4-4cef-9b26-f20394ac094c','雜詠','林石澗','宋','宋诗','song-poetry','','[]','蓂莢階前日月飛，羹牆惆悵望堯眉。',32,'全唐诗/poet.song.253000.json','["蓂莢階前日月飛，羹牆惆悵望堯眉。", "三千年笑巢由錯，不見勳華揖遜時。"]'),
('f2c0eb57-c5bd-4788-9576-acd1c73a45f9','戲筆','林石澗','宋','宋诗','song-poetry','','[]','碧雲芳草兩悠悠，望斷天涯此倚樓。',32,'全唐诗/poet.song.253000.json','["碧雲芳草兩悠悠，望斷天涯此倚樓。", "莫遣閑愁似江海，潮生潮落幾時休。"]'),
('0a321d2b-7d98-420d-baf0-e3aa37fb4706','送友人西上','林石澗','宋','宋诗','song-poetry','','[]','祖席歌雲散，春風助馬飛。',48,'全唐诗/poet.song.253000.json','["祖席歌雲散，春風助馬飛。", "到京三月盡，爲客幾時歸。", "雨驛梨花瘦，煙村荻筍肥。", "倚門有慈母，莫負老萊衣。"]'),
('6e3e0b9c-7be3-4343-8842-15d222c4aa5e','題清芬閣  其一','吳升之','宋','宋诗','song-poetry','','[]','先生曾此濯塵纓，七里寒灘分外清。',64,'全唐诗/poet.song.253000.json','["先生曾此濯塵纓，七里寒灘分外清。", "少日决科雖失意，全家肥遯豈無成。", "蛟龍窟宅身如寄，泉石膏肓詩有聲。", "雖與子陵同一律，不將絲線釣虛名。"]'),
('b5546892-2506-4105-961d-f825b8fec288','題清芬閣  其二','吳升之','宋','宋诗','song-poetry','','[]','辟書既上不霑恩，拂袖歸來閉里門。',64,'全唐诗/poet.song.253000.json','["辟書既上不霑恩，拂袖歸來閉里門。", "聊取江山助篇什，盡將軒冕付兒孫。", "紛紛利害真能擇，擾擾光塵豈易論。", "儻使乘時拜遺補，未應千古配嚴尊。"]'),
('849ed194-4f74-4654-8014-6ebcb4daf188','贈張師','陳振甫','宋','宋诗','song-poetry','','[]','富貴不可縶，瀟然脫塵羈。',48,'全唐诗/poet.song.253000.json','["富貴不可縶，瀟然脫塵羈。", "神氣自涵養，巖壑方棲遲。", "山中有宰相，物外多仙師。", "蓬萊定不達，節操請堅持。"]'),
('9c3a0e54-69d0-46c8-b79d-76e7f8e85a80','贈沖虛齋朱道士','陳振甫','宋','宋诗','song-poetry','','[]','玉室金堂世有人，龍眠龜息鶴精神。',32,'全唐诗/poet.song.253000.json','["玉室金堂世有人，龍眠龜息鶴精神。", "暑風吹起塵三丈，城市出來閑采真。"]'),
('497b1334-ce87-409d-956a-74745d37ee3c','醉贈宮主許存道','陳振甫','宋','宋诗','song-poetry','','[]','我到洞天雙眼明，憑虛不覺骨毛輕。',32,'全唐诗/poet.song.253000.json','["我到洞天雙眼明，憑虛不覺骨毛輕。", "更有清幽許存道，爲寫高山流水聲。"]'),
('94ccfcca-c561-4e48-a3ad-3db265c2a996','贈徐月道士','張簡','宋','宋诗','song-poetry','','[]','病骨癯然鶴一般，相陪夜坐萬松間。',64,'全唐诗/poet.song.253000.json','["病骨癯然鶴一般，相陪夜坐萬松間。", "乾坤清氣皆歸月，湖海高人半在山。", "吟苦心從天漢轉，琴清身與嶺雲閑。", "杯茶預約中秋節，五老峰頭說大還。"]'),
('04ae732a-8612-4a1d-a915-a004d13368da','寄浙西倉曹東甽','張簡','宋','宋诗','song-poetry','','[]','骨凡緣欠大還丹，飽食人間行路難。',64,'全唐诗/poet.song.253000.json','["骨凡緣欠大還丹，飽食人間行路難。", "燈火半生詩鬢老，江湖九月客衣單。", "拈將紅葉書愁思，摘得黄花當晚餐。", "莫向吳松江上宿，夢魂偏怯雁聲寒。"]'),
('d2494a9d-e915-4c8b-b2ff-3222a74ffeb0','讀劉阮傳','張簡','宋','宋诗','song-poetry','','[]','俗緣未斷念家鄉，回首仙源竟渺茫。',32,'全唐诗/poet.song.253000.json','["俗緣未斷念家鄉，回首仙源竟渺茫。", "野鳥自啼春自好，桃花應是怨劉郎。"]'),
('2b6fb1ed-70fd-41f1-86c1-e7741f241c51','禪窩','張簡','宋','宋诗','song-poetry','','[]','草窩雙樹下，借與定僧居。',24,'全唐诗/poet.song.253000.json','["草窩雙樹下，借與定僧居。", "會得虛空境，坐卧總從渠。"]'),
('e486bad3-64cb-4205-8f44-b69441baa727','天津橋月夜','張簡','宋','宋诗','song-poetry','','[]','行闕獨崔嵬，垂楊夾道栽。',48,'全唐诗/poet.song.253000.json','["行闕獨崔嵬，垂楊夾道栽。", "河通桃葉渡，門對雨花臺。", "世事棋千變，人生夢一回。", "誰知今夜月，曾照六朝來。"]'),
('dba3696a-8156-4c4b-8764-530275f46a27','贈長安趙先生母','無名氏','宋','宋诗','song-poetry','','[]','牙髪重生黑，延齡三事因。',48,'全唐诗/poet.song.253000.json','["牙髪重生黑，延齡三事因。", "至誠遵道友，精謹奉高真。", "靜意摛猿馬，清心聚氣神。", "處端聊拜上，稽首壽長人。"]'),
('967263c2-4cc0-4ff9-a91a-5cb568d06fe8','贈周書記','李誨言','宋','宋诗','song-poetry','','[]','早悟功名歲月空，衲衣何處不從容。',64,'全唐诗/poet.song.253000.json','["早悟功名歲月空，衲衣何處不從容。", "幾回渡水自尋鶴，豈但買山方種松。", "麾玉固嘗聞咳唾，擲金未盡寫心胸。", "與君能隔幾多地，薄暮一聲湖上鐘。"]'),
('42ad6f44-c11a-43b4-ba9c-4390f5d88136','送永嘉張德載歸','李誨言','宋','宋诗','song-poetry','','[]','一書催客棹，興已落天涯。',48,'全唐诗/poet.song.253000.json','["一書催客棹，興已落天涯。", "詩捲愁中景，人歸夢裏家。", "山田耕過雨，谿水釣殘霞。", "茆屋容身老，文章不足誇。"]'),
('61456f83-7868-432c-bb31-abff5765922c','贈鄭稼田','阮委心','宋','宋诗','song-poetry','','[]','非稼亦非田，生香萃簡編。',48,'全唐诗/poet.song.253000.json','["非稼亦非田，生香萃簡編。", "所耕皆實地，何慮不豐年。", "華秀充諸己，收藏樂此天。", "揠苗求助長，毋若宋人然。"]'),
('a8ba9114-e475-4b5a-b209-9be6e402442f','寄聖水照講師','趙東閣','宋','宋诗','song-poetry','','[]','聖水水深山亦深，寺前三十里清陰。',32,'全唐诗/poet.song.253000.json','["聖水水深山亦深，寺前三十里清陰。", "一僧趺坐松間石，不是安禪定苦吟。"]'),
('c8fa7985-e005-4bb3-ac76-e7d092637ff6','凌霄花爲復上人作','趙東閣','宋','宋诗','song-poetry','','[]','嫋嫋枯藤淺絳葩，夤緣直上照殘霞。',32,'全唐诗/poet.song.253000.json','["嫋嫋枯藤淺絳葩，夤緣直上照殘霞。", "老僧不作依附想，將謂青松自有花。"]'),
('fd9fa6e7-8c7b-40f0-a7e0-b2d500f5dd06','春山堂','趙東閣','宋','宋诗','song-poetry','','[]','山在畫堂西，鈎簾靜對時。',48,'全唐诗/poet.song.253000.json','["山在畫堂西，鈎簾靜對時。", "林高日落早，巷僻客來遲。", "抱病獨不飲，愛閑君所知。", "階前碧梧葉，片片可題詩。"]'),
('18d2d520-07b3-48e0-9f19-a482dbf139b4','漁家','趙東閣','宋','宋诗','song-poetry','','[]','衡嶽夜來雨，湘江增綠波。',48,'全唐诗/poet.song.253000.json','["衡嶽夜來雨，湘江增綠波。", "小舟浮似屋，香草結爲簑。", "水定見魚影，夜深聞櫂歌。", "悠悠百年內，醒少醉時多。"]'),
('3ec94bae-fbd7-4ec6-8ca9-06771e1fe0ca','寄友','陳鱗','宋','宋诗','song-poetry','','[]','雙魚書不至，江上又空還。',48,'全唐诗/poet.song.253000.json','["雙魚書不至，江上又空還。", "芳草去時路，暮雲何處山。", "吟牀花片積，釣石蘚痕斑。", "惟有思君夢，迢迢夜度關。"]'),
('d5a36f85-6d86-4cc6-a9ac-2186a99d9f60','寄劉易隠','章仙巖','宋','宋诗','song-poetry','','[]','着身塵世易遭魔，是是非非可奈何。',64,'全唐诗/poet.song.253000.json','["着身塵世易遭魔，是是非非可奈何。", "心地一生如日月，人情千變自風波。", "但從正直天須見，到底關防事轉多。", "所以古來真隠者，貂蟬不肯換漁蓑。"]'),
('71f809bf-9754-46f5-bb72-8992a6fbccdd','六和塔','章仙巖','宋','宋诗','song-poetry','','[]','六和塔上一登臨，當景江山入興深。',67,'全唐诗/poet.song.253000.json','["六和塔上一登臨，當景江山入興深。", "雲出雲歸天自在，潮來潮去水無心。", "東南船{舟覽}風方順，西北樓臺日向陰。", "壯矣帝居吳越舊，未甘河洛久湮沉。"]'),
('2e0b16ff-d111-4b1f-be90-2f994e3bb236','和高斯立見寄','蘇竹里','宋','宋诗','song-poetry','','[]','少年浩蕩子長遊，回首人間道路修。',64,'全唐诗/poet.song.253000.json','["少年浩蕩子長遊，回首人間道路修。", "納納乾坤日西下，悠悠江漢水東流。", "如知往事皤青鬢，應把華年伴白鷗。", "惆悵半生飛動意，看人騎馬覓封侯。"]'),
('04e017e4-a2e2-444f-ae42-57299d1f5db3','答曾節推','王名遂','宋','宋诗','song-poetry','','[]','夫君真自淦川來，書種相承教有台。',64,'全唐诗/poet.song.253000.json','["夫君真自淦川來，書種相承教有台。", "蓬閬得時宜直上，金焦無地却空回。", "薦書共喜從天下，詩句誰能带雨催。", "細數平生歸計是，待耕明月種寒梅。"]'),
('a854d8ee-00cb-4d57-b0ee-fd99c192ed83','歲寒亭成題柱自警','王名遂','宋','宋诗','song-poetry','','[]','松榮梅竹秀，三徑但含滋。',48,'全唐诗/poet.song.253000.json','["松榮梅竹秀，三徑但含滋。", "不與乾坤老，難令霜雪欺。", "交情存淡薄，世治識艱危。", "前路留教遠，終身以自期。"]'),
('38dcb68e-a37a-4e7c-a223-7a6b8d1d622a','謝石守留度歲','余力齋','宋','宋诗','song-poetry','','[]','歲近歸程夢裏忙，可憐一日九回腸。',64,'全唐诗/poet.song.253000.json','["歲近歸程夢裏忙，可憐一日九回腸。", "雪中飲酒難爲醉，梅下吟詩易得香。", "無愧我心何毀辱，休將世事論行藏。", "相逢柳已開青眼，共對東風舞一場。"]'),
('155f7991-f8ee-4b07-9d4d-e3c00dfa9f38','奉謝徐獻子','無名氏','宋','宋诗','song-poetry','','[]','入得青山第幾重，龍蟠鳳舞着仙宗。',64,'全唐诗/poet.song.253000.json','["入得青山第幾重，龍蟠鳳舞着仙宗。", "九關雲鎖疑無地，數步天開又一峰。", "大滌洞中丹作井，昊穹殿下石爲松。", "我來自結真人伴，杖屨蹁躚是指蹤。"]'),
('ea3fb4d4-3c84-4065-995d-d803a49c1a3f','木犀','何橘潭','宋','宋诗','song-poetry','','[]','露洗金蟲一半開，層層碧玉映樓臺。',32,'全唐诗/poet.song.253000.json','["露洗金蟲一半開，層層碧玉映樓臺。", "西風昨夜吹香過，人在欄干待月來。"]'),
('f682bad0-a152-40ac-9b44-b42ca94e2721','詠梅','何橘潭','宋','宋诗','song-poetry','','[]','千古甘心冷淡中，却於春事不相同。',32,'全唐诗/poet.song.253000.json','["千古甘心冷淡中，却於春事不相同。", "東風祇解吹花落，吹得花開是北風。"]'),
('4b157438-e732-47ab-866f-d753fa4b76de','柳','李靜獨','宋','宋诗','song-poetry','','[]','顔色鮮明能幾時，未辭黄葉已辭枝。',32,'全唐诗/poet.song.253000.json','["顔色鮮明能幾時，未辭黄葉已辭枝。", "都緣愛管閑離別，多恨多愁故早衰。"]'),
('3470bbf2-2187-4f5c-b4d6-bdf1c5f1eae2','回舟即事','李靜獨','宋','宋诗','song-poetry','','[]','羞將塵土鬢，重上釣魚舟。',48,'全唐诗/poet.song.253000.json','["羞將塵土鬢，重上釣魚舟。", "閑對湖山曉，靜觀天地秋。", "鼓鐘雲外寺，歌舞水邊樓。", "興盡歸心急，荷花勸少留。"]'),
('7d42bba9-f568-4116-8b3c-a3e0f81bc26e','柳','薛海隠','宋','宋诗','song-poetry','','[]','不問章臺與楚樓，一根半樹亦風流。',32,'全唐诗/poet.song.253000.json','["不問章臺與楚樓，一根半樹亦風流。", "看來的是多情物，愛殺春光怕殺秋。"]'),
('57e15886-1bc2-46f0-98fe-790c30a8960f','蓼花','拾遺','宋','宋诗','song-poetry','','[]','分紅間白汀州晚，拜雨揖風江漢秋。',32,'全唐诗/poet.song.253000.json','["分紅間白汀州晚，拜雨揖風江漢秋。", "看誰耐得清霜去，却是蘆花先白頭。"]'),
('b7708d80-3c12-4342-a33b-5e71235e643e','琵琶','拾遺','宋','宋诗','song-poetry','','[]','夜深琵琶聲似裂，一曲霓裳一庭月。',32,'全唐诗/poet.song.253000.json','["夜深琵琶聲似裂，一曲霓裳一庭月。", "曲終人影在西階，困倚東風步摇折。"]'),
('c77b71b5-b08c-4378-8504-8cc643369553','梅','王石室','宋','宋诗','song-poetry','','[]','靜參香影句，獨向野橋行。',48,'全唐诗/poet.song.253000.json','["靜參香影句，獨向野橋行。", "數點水邊白，十分天下清。", "嫩條尤勁直，老樹更晶明。", "冰雪窮冬裏，春風頼爾生。"]'),
('513d0e14-c418-4711-8c0d-fc6f523d624a','梅  其一','李嘯軒','宋','宋诗','song-poetry','','[]','笛譜從來有落梅，梅花那怕笛聲哀。',32,'全唐诗/poet.song.253000.json','["笛譜從來有落梅，梅花那怕笛聲哀。", "幾回笛裏看花處，曲自凄凉花自開。"]'),
('2ae95399-425a-4bea-88c2-7e94882e6fc5','梅  其二','李嘯軒','宋','宋诗','song-poetry','','[]','傲寒特地占春光，不是東皇用意偏。',32,'全唐诗/poet.song.253000.json','["傲寒特地占春光，不是東皇用意偏。", "只恐百花羞見面，故教回避艷陽天。"]'),
('7787cd5e-8457-454f-94e5-58e190cd2f25','登姑蘇臺','李嘯軒','宋','宋诗','song-poetry','','[]','規模高敞俯城池，未必斯臺是故基。',64,'全唐诗/poet.song.253000.json','["規模高敞俯城池，未必斯臺是故基。", "風月祇招人感慨，江山不管國興衰。", "幾年勾踐讎思復，終日吳王醉不知。", "却使五湖烟浪裏，扁舟一葉載西施。"]'),
('4d522221-4aea-464e-bbf3-ffe19f00da53','梅花','劉月房','宋','宋诗','song-poetry','','[]','骨格孤高太瘦生，民門霜雪鬭晶明。',32,'全唐诗/poet.song.253000.json','["骨格孤高太瘦生，民門霜雪鬭晶明。", "後開桃李千門滿，纔染東風便不清。"]'),
('d38f58d2-e539-428c-a2fc-1c9e458f93eb','清華園','劉月房','宋','宋诗','song-poetry','','[]','水光摇入碧窗寒，兩岸斜陽照亂山。',32,'全唐诗/poet.song.253000.json','["水光摇入碧窗寒，兩岸斜陽照亂山。", "纔一吟詩便多事，只消靜對綠陰閑。"]'),
('43fb5e11-59bd-4eb9-9118-2bf7f241281c','葉','方南山','宋','宋诗','song-poetry','','[]','高低庭樹晚風吹，脫葉應難戀舊枝。',32,'全唐诗/poet.song.253000.json','["高低庭樹晚風吹，脫葉應難戀舊枝。", "莫向秋深怨零落，春深還有綠陰時。"]'),
('9fb82021-5cc7-46f1-b46c-9cb2232e9966','畫角辭','何麟瑞','宋','宋诗','song-poetry','','[]','莫吹角，吹得梅花片片落。',92,'全唐诗/poet.song.253000.json','["莫吹角，吹得梅花片片落。", "朝吹暮吹吹不了，盤古不知坐成老。", "童男童女求蓬山，何如此器束之高閣間。", "金盤擎露仙人掌，何如敕斷此聲勿用響。", "不知今日復明日，兩鬢常常黑如漆。", "莫吹角，天寒歲晚情更惡。"]'),
('ff1bc180-b665-41ff-bbcd-a9252a376ca7','天馬歌','何麟瑞','宋','宋诗','song-poetry','','[]','崑崙高哉二千五百餘里，日月相隠避。',267,'全唐诗/poet.song.253000.json','["崑崙高哉二千五百餘里，日月相隠避。", "黄河發源下有渥洼水，大宛群馬飲其澨。", "天馬下與群馬戲，産駒一日可千里。", "滴汗化作燕支水，國人縛藁爲人置水際。", "久與馬習不經意，一朝却被人馽繫。", "張騫使還報天子，天子不惜金珠與重幣，期以此馬可立致。", "大宛使人欺漢使，致煩浞野樓蘭七百騎，攻虜其王馬始至。", "此馬初入天廄時，一十二閑無敢嘶。", "萬乘臨觀動一笑，盛氣從此無四夷。", "君王神武不世出，天産神物相追隨。", "高皇手提三尺劍，蹙秦誅項一指麾。", "天下馬上得，不聞取馬外國爲。", "龍如可豢龍亦物，馬果龍種豈受羈。", "徒令物故過半不補失，輪臺一詔悔已遲。", "此詩欲學旅獒可，光武一牛亦足噓漢火。"]'),
('c5c5fbfd-fcad-442f-b638-3e6cbdb9fef4','後天馬歌','何麟瑞','宋','宋诗','song-poetry','','[]','建元天子不世出，天相神武産異物，有馬出在月氏窟。',206,'全唐诗/poet.song.253000.json','["建元天子不世出，天相神武産異物，有馬出在月氏窟。", "寶劍之精，乾龍之靈。", "足如奔電，目如耀星。", "汗血雨洒，騣肉飆輕。", "渴吻一飲，黄河塵生。", "昂首一鳴，天雷收聲。", "曾爲伏羲出河負八卦，曾隨穆王遠與西母會。", "鸞旂屬車相後先，龍盾虎韔八寶韉。", "萬乘親臨拜甘泉，穩馱玉輅壇壝前。", "兀鼎勒兵十八萬，天子自將孰敢戰。", "駿氣橫出立陣前，百萬聞嘶股俱顫。", "笑此馬，神哉沛。", "西極龍媒□望退。", "天子作歌暢皇明，四夷竭蹙咸來庭。", "天馬來，帝作歌，漢時此馬今更多。"]'),
('3fd9cdb0-c5f8-4b1b-9d86-ab0031155fcb','鏡','杜樗隠','宋','宋诗','song-poetry','','[]','鑄就揩磨不計工，豈量資質本頑銅。',32,'全唐诗/poet.song.253000.json','["鑄就揩磨不計工，豈量資質本頑銅。", "面前毫髪曾無隠，背後看來便不同。"]'),
('ca1fbaed-75ce-471b-aed8-6b709b0adbc4','石寶蓋','怡然','宋','宋诗','song-poetry','','[]','圓頂環珠幡，久與石俱化。',24,'全唐诗/poet.song.253000.json','["圓頂環珠幡，久與石俱化。", "我執黄庭經，跏趺坐其下。"]'),
('83102c09-bb0a-405d-b55c-8bc89f522f39','翠蛟亭  其一','怡然','宋','宋诗','song-poetry','','[]','縈紆九鎖山，稜層幾疊水。',24,'全唐诗/poet.song.253000.json','["縈紆九鎖山，稜層幾疊水。", "誰令翻其源，銀濤迸石髓。"]'),
('452df61a-8e8b-448f-88db-e0264f38dd00','翠蛟亭  其二','怡然','宋','宋诗','song-poetry','','[]','擘石鬬雷霆，蛟乎爾□怒。',24,'全唐诗/poet.song.253000.json','["擘石鬬雷霆，蛟乎爾□怒。", "會當捲銀河，凌空瀉甘澍。"]'),
('cdd56ce5-d300-4d75-8c68-2e02d42047c0','隔凡柱','怡然','宋','宋诗','song-poetry','','[]','一柱懸通衢，可望不可進。',24,'全唐诗/poet.song.253000.json','["一柱懸通衢，可望不可進。", "老仙指謂予，傍邊有捷徑。"]'),
('88a5811c-bccc-4dc0-8e22-4ad5b4617307','五更枕上','丁竹巖','宋','宋诗','song-poetry','','[]','一着非時一局非，山房愁到曉鐘時。',32,'全唐诗/poet.song.253000.json','["一着非時一局非，山房愁到曉鐘時。", "楠榴枕上平生事，聽雨聽風聽子規。"]'),
('6a233de5-954e-4bd9-ac22-41ed650d2838','漁舟','雪巖','宋','宋诗','song-poetry','','[]','莫笑扁舟數尺長，幾經煙雨浸瀟湘。',32,'全唐诗/poet.song.253000.json','["莫笑扁舟數尺長，幾經煙雨浸瀟湘。", "紅船箇箇高於屋，未必荷花入夢香。"]'),
('145599fc-06d5-4436-aa08-cca2d8d5f903','對菊','雪巖','宋','宋诗','song-poetry','','[]','菊花相菊一長歎，公是公非話總難。',64,'全唐诗/poet.song.253000.json','["菊花相菊一長歎，公是公非話總難。", "以道義交堪傲俗，得漁樵趣不須官。", "紛紛落葉山初瘦，隠隠平沙雁已寒。", "天氣欲晴又欲雨，百年心事滿欄干。"]'),
('1e48fe03-2b05-43b8-928f-2959ff5c26af','舟行即事','吳子實','宋','宋诗','song-poetry','','[]','煙暗前村樹欲無，草簑篛笠一翁漁。',32,'全唐诗/poet.song.253000.json','["煙暗前村樹欲無，草簑篛笠一翁漁。", "無端風伯吹斜雨，濕却蓬窗數冊書。"]'),
('b8dd4e8e-b8f4-4b41-932c-836c12e19337','題張穫軒詩卷  其一','吳子實','宋','宋诗','song-poetry','','[]','中興踰百載，獨有放翁詩。',48,'全唐诗/poet.song.253000.json','["中興踰百載，獨有放翁詩。", "豪出謫仙右，妙惟工部知。", "鏡湖歸老日，劍閣入軍時。", "英氣今何在，九原千古悲。"]'),
('3ae62ec6-b10a-41ec-bc0e-db1df5160a2a','題張穫軒詩卷  其二','吳子實','宋','宋诗','song-poetry','','[]','句法親傳得，江湖老穫軒。',48,'全唐诗/poet.song.253000.json','["句法親傳得，江湖老穫軒。", "推敲深得趣，窮達可曾論。", "好爵無三字，清名有五言。", "還知絕奇處，難弟復難昆。"]'),
('46a04d3f-1555-489d-a39a-d16be6a65cfa','游棲真洞歸舟带月泊市橋  其一','章桂發','宋','宋诗','song-poetry','','[]','携手清苕去，高楓丹葉森。',48,'全唐诗/poet.song.253000.json','["携手清苕去，高楓丹葉森。", "漁樵九鎖外，風雨一窗深。", "索酒貪山月，添衣怯洞陰。", "鳳歸天柱曉，樓閣有鳴琴。"]'),
('5848a221-fa43-44c1-ad0c-563f8d9903fa','游棲真洞歸舟带月泊市橋  其二','章桂發','宋','宋诗','song-poetry','','[]','山嵐來夾案，泉急自穿渠。',48,'全唐诗/poet.song.253000.json','["山嵐來夾案，泉急自穿渠。", "密記東陽訣，高題上帝居。", "牙兒藏寶篋，山子走籃輿。", "曲折璣衡轉，溪坳可結廬。"]'),
('88d4605b-48d0-4db6-a8e5-eb1308366e96','泊舟','徐橫槊','宋','宋诗','song-poetry','','[]','短蓬靜坐月窺船，斗轉參橫水底天。',32,'全唐诗/poet.song.253000.json','["短蓬靜坐月窺船，斗轉參橫水底天。", "傳語篙工低着語，恐驚沙觜白鷗眠。"]'),
('9ab1fa5f-7c4a-466d-b92e-c30259ea8dbc','泊舟有懷','良史偉長','宋','宋诗','song-poetry','','[]','渺渺復迢迢，楓林带板橋。',48,'全唐诗/poet.song.253000.json','["渺渺復迢迢，楓林带板橋。", "沙寒初上月，浦暗已回潮。", "霜葦多先折，江花或後凋。", "今宵何處雁，相伴宿蘭橈。"]'),
('ae20121f-a25e-4e40-af26-98ed6ea7f537','夜乘航','吳仙湖','宋','宋诗','song-poetry','','[]','漁火穿蓬罅，僧鐘到夢邊。',48,'全唐诗/poet.song.253000.json','["漁火穿蓬罅，僧鐘到夢邊。", "水鄉多得月，野境遠連天。", "敗葦流螢集，荒林宿鳥喧。", "舟人苦無夜，未曉起炊煙。"]'),
('1b0df646-aa68-4678-975d-56976245236c','農家','吳仙湖','宋','宋诗','song-poetry','','[]','農家冬事足，何處不祈禳。',48,'全唐诗/poet.song.253000.json','["農家冬事足，何處不祈禳。", "煨芋分兒食，蒭醪喚客嘗。", "犬眠茅舍暖，犢跳野田荒。", "勿遣官租急，令渠樂歲康。"]'),
('79502499-acc0-4efb-a278-8e75c2342325','買鞭','武成','宋','宋诗','song-poetry','','[]','初買雖憐價甚微，駑駘便已化驦騛。',64,'全唐诗/poet.song.253000.json','["初買雖憐價甚微，駑駘便已化驦騛。", "幹長却想穿階直，節密應知受土肥。", "金賜夜寒敲月落，玉絲春裊拂花飛。", "提携莫笑無他用，萬里旌旗更指揮。"]'),
('992423eb-6692-4718-9a8a-c51e02ba7faf','萬年宮','張仲信','宋','宋诗','song-poetry','','[]','頻將衣食結圜圊，天樂旌幢降綵雲。',32,'全唐诗/poet.song.253000.json','["頻將衣食結圜圊，天樂旌幢降綵雲。", "二十四年功行滿，衆真推讓武夷宮。"]'),
('85ad80b2-5333-42fb-8ee8-b5291f906082','題萬年宮','李彥方','宋','宋诗','song-poetry','','[]','日華晴射武夷峰，湛碧溪流照玉驄。',64,'全唐诗/poet.song.253000.json','["日華晴射武夷峰，湛碧溪流照玉驄。", "行郡敢辭千里路，祝釐先拜萬年宮。", "山川歷歷神仙境，民物熙熙太古風。", "笑領霞觴雲子酒，姓名留在洞天中。"]'),
('844606a5-8419-40f5-afed-68b829d719ab','洞霄宮','鄭國輔','宋','宋诗','song-poetry','','[]','自憐蹤迹又塵埃，再見溪山眼便開。',64,'全唐诗/poet.song.253000.json','["自憐蹤迹又塵埃，再見溪山眼便開。", "野水縈紆通路過，閑花疏淡放春回。", "玉清緲緲排仙仗，金碧峨峨煥寶臺。", "十里暮雲橫九鎖，却如騎鶴下蓬萊。"]'),
('ace0b8d3-2ade-4252-bbe8-c44289e41e05','大滌洞','鄭國輔','宋','宋诗','song-poetry','','[]','去縣十八里，傳名千萬年。',48,'全唐诗/poet.song.253000.json','["去縣十八里，傳名千萬年。", "三山空隔海，一柱獨擎天。", "驂馭歌司馬，燒丹扣葛仙。", "誰云塵俗骨，亦得嗣前賢。"]'),
('0c84727c-eeb3-4a0f-8bb2-58364eba5d31','瀑布','鄭國輔','宋','宋诗','song-poetry','','[]','終日湍流怒作聲，憑欄便覺耳根清。',32,'全唐诗/poet.song.253000.json','["終日湍流怒作聲，憑欄便覺耳根清。", "龍君雅欲助奇觀，故把銀瓶瀉水晶。"]'),
('abb2a2c4-a0fc-42ec-bac1-897f6fccb11e','雲根石  其一','鄭國輔','宋','宋诗','song-poetry','','[]','輪囷一片出無心，未許蒼苔久見侵。',32,'全唐诗/poet.song.253000.json','["輪囷一片出無心，未許蒼苔久見侵。", "六月旱田天不雨，願將膚寸霈爲霖。"]'),
('f31fe60b-e379-4927-82a8-a64e2b7f66ca','雲根石  其二','鄭國輔','宋','宋诗','song-poetry','','[]','滿耳環珮聲，雲根綫寒玉。',24,'全唐诗/poet.song.253000.json','["滿耳環珮聲，雲根綫寒玉。", "雨過勿雷吼，老龍鼾正熟。"]'),
('1822fa78-842b-4f1e-a41b-617710869c24','龍洞','鄭國輔','宋','宋诗','song-poetry','','[]','泥蟠蟄卧久潜蹤，一旦青雲得路通。',32,'全唐诗/poet.song.253000.json','["泥蟠蟄卧久潜蹤，一旦青雲得路通。", "利物濟人功已了，却遺凡骨返仙宮。"]'),
('93ccf324-82f3-4a60-8636-2f01701e6329','鳳洞','鄭國輔','宋','宋诗','song-poetry','','[]','古木森森翳女蘿，四山環抱鬰嵯峨。',96,'全唐诗/poet.song.253000.json','["古木森森翳女蘿，四山環抱鬰嵯峨。", "此間定有荆山璞，未審何時遇卞和。", "斬開綠棘黄荆路，巖上采霞摇影動。", "洞裏仙人醉不知，巖前留下無聲鳳。", "我今行向洞前來，是洞須開鳳莫猜。", "便好跨遊三島去，等閑抖擻輕塵埃。"]'),
('21114b32-b993-4e2c-b395-20832e165343','清音亭','鄭國輔','宋','宋诗','song-poetry','','[]','山泉潄玉琴，塵世誰知音。',24,'全唐诗/poet.song.253000.json','["山泉潄玉琴，塵世誰知音。", "植杖憩于此，頓消名利心。"]'),
('2a24b2a5-129f-4cf4-92d7-93e559549d9e','翠微亭','鄭國輔','宋','宋诗','song-poetry','','[]','滿眼青山倦應酬，小亭回護頗知休。',32,'全唐诗/poet.song.253000.json','["滿眼青山倦應酬，小亭回護頗知休。", "撚髯索句空歸去，疑在飛來峰上頭。"]'),
('2a8f7738-b625-41c5-9b3f-6041c42e285d','仙迹巖題詩二十三首 三清殿','無名氏','宋','宋诗','song-poetry','','[]','虛無混沌未分前，大道元居太極先。',32,'全唐诗/poet.song.253000.json','["虛無混沌未分前，大道元居太極先。", "自一而三同祖炁，澄清高上積陽天。"]'),
('6258752e-c48d-49b9-8a76-0a435a272831','仙迹巖題詩二十三首 佑聖殿','無名氏','宋','宋诗','song-poetry','','[]','挺鋒鎮北闡威權，翦伐魔精正法宣。',32,'全唐诗/poet.song.253000.json','["挺鋒鎮北闡威權，翦伐魔精正法宣。", "化育黎民臻大道，安寧家國享長年。"]'),
('5e999348-9670-4f33-b23d-4d3b0c2b56e6','仙迹巖題詩二十三首 齋堂','無名氏','宋','宋诗','song-poetry','','[]','辨道焚修練性根，應時粥飯益真元。',32,'全唐诗/poet.song.253000.json','["辨道焚修練性根，應時粥飯益真元。", "齋餘有報君恩重，壽祝無疆帝道尊。"]'),
('c291e7bf-3ed0-467b-bbe8-5f360aaff16e','仙迹巖題詩二十三首 演教堂','無名氏','宋','宋诗','song-poetry','','[]','參稽道德本無言，不二門開闡古先。',32,'全唐诗/poet.song.253000.json','["參稽道德本無言，不二門開闡古先。", "多謝師尊傳演教，要令後學悟真詮。"]'),
('ec807eb9-c844-48f3-9261-ad421e838020','仙迹巖題詩二十三首 方丈後聚仙亭','無名氏','宋','宋诗','song-poetry','','[]','高敞山齋立乳巔，飄颻雲馭聚群仙。',32,'全唐诗/poet.song.253000.json','["高敞山齋立乳巔，飄颻雲馭聚群仙。", "百靈聽講開壇夜，大法將臨報語宣。"]'),
('f630b2d4-79d1-4452-b52a-7e117f0ec681','仙迹巖題詩二十三首 道院','無名氏','宋','宋诗','song-poetry','','[]','幽棲枹樸古先精，宴坐參同元化并。',32,'全唐诗/poet.song.253000.json','["幽棲枹樸古先精，宴坐參同元化并。", "一炷清香騰瑞靄，雲端時透步虛聲。"]'),
('f1ee6e48-a2c6-4986-8902-d64eece2356d','仙迹巖題詩二十三首 精思道院','無名氏','宋','宋诗','song-poetry','','[]','精思名扁列金題，沖素齋居與道齊。',32,'全唐诗/poet.song.253000.json','["精思名扁列金題，沖素齋居與道齊。", "德感天仙來聽論，芝軿時降共參稽。"]'),
('69d6e1dc-8c0d-46c1-8eb1-d49ca3fd5523','仙迹巖題詩二十三首 昊天殿','無名氏','宋','宋诗','song-poetry','','[]','遊幸名山德壽存，鼎新大殿顯仁恩。',32,'全唐诗/poet.song.253000.json','["遊幸名山德壽存，鼎新大殿顯仁恩。", "玉圭物物皆珍異，安奉嚴恭玉帝尊。"]'),
('3533c15b-b86d-4e3e-aadf-f3d361213f45','仙迹巖題詩二十三首 璇璣殿','無名氏','宋','宋诗','song-poetry','','[]','衆聖環拱位中天，統濟乾坤妙轉旋。',32,'全唐诗/poet.song.253000.json','["衆聖環拱位中天，統濟乾坤妙轉旋。", "高覆崑崙朝帝闕，注生迴死福增延。"]'),
('476a1253-c8e5-4fe2-9d70-b770968868e6','仙迹巖題詩二十三首 翠蛟亭','無名氏','宋','宋诗','song-poetry','','[]','湍激清泉舞翠蛟，幽亭跨澗對岩坳。',32,'全唐诗/poet.song.253000.json','["湍激清泉舞翠蛟，幽亭跨澗對岩坳。", "我來憩此觀嘉趣，一洗塵襟凡世拋。"]'),
('b8e1c15e-ff45-4c3d-8aa5-afa1fea4bdd7','仙迹巖題詩二十三首 鍾樓','無名氏','宋','宋诗','song-poetry','','[]','重樓高聳丹霄外，深夜聲摩碧落中。',32,'全唐诗/poet.song.253000.json','["重樓高聳丹霄外，深夜聲摩碧落中。", "神通無量鴻音遠，永鎮名山有顯功。"]'),
('adc56a05-4d9a-4e63-81c0-7cda18abf432','仙迹巖題詩二十三首 張真君祠','無名氏','宋','宋诗','song-poetry','','[]','聖像遷祠出禁扃，天恩遣使從神靈。',32,'全唐诗/poet.song.253000.json','["聖像遷祠出禁扃，天恩遣使從神靈。", "奉安欽敬祈民福，應感昭彰佑帝庭。"]'),
('14c3e8b5-db69-4092-adbd-e3dba20a28c1','仙迹巖題詩二十三首 葉天師書樓','無名氏','宋','宋诗','song-poetry','','[]','巍然垂象隠精思，著述丹書與世違。',32,'全唐诗/poet.song.253000.json','["巍然垂象隠精思，著述丹書與世違。", "真得紫文無上道，業成遺跡是題詩。"]'),
('3ac0ee0a-db57-4df8-95f4-de7856341eee','仙迹巖題詩二十三首 經閣','無名氏','宋','宋诗','song-poetry','','[]','寶閣莊嚴金玄耀，風鈴震響玉丁東。',32,'全唐诗/poet.song.253000.json','["寶閣莊嚴金玄耀，風鈴震響玉丁東。", "甍飛傑出青霄上，道典珍藏在此中。"]'),
('48668383-aa2e-4d5f-a145-abcc1e1bd2ba','仙迹巖題詩二十三首 雲根石','無名氏','宋','宋诗','song-poetry','','[]','一片輪囷跡嚴存，無心出岫瑞騰坤。',32,'全唐诗/poet.song.253000.json','["一片輪囷跡嚴存，無心出岫瑞騰坤。", "不隨風雨輕舒卷，觸石凝然正性根。"]'),
('16548712-2597-42bf-aa81-26b456b79a02','仙迹巖題詩二十三首 天柱泉','無名氏','宋','宋诗','song-poetry','','[]','大滌之西一窮生，源高樵者只聞聲。',32,'全唐诗/poet.song.253000.json','["大滌之西一窮生，源高樵者只聞聲。", "汲泉烹茗多甘味，內隠丹砂赤更清。"]'),
('3560e87a-f350-4999-8217-f97a67d54b33','仙迹巖題詩二十三首 冷泉','無名氏','宋','宋诗','song-poetry','','[]','琳宮門外小橋東，石罅泉流細脈通。',32,'全唐诗/poet.song.253000.json','["琳宮門外小橋東，石罅泉流細脈通。", "清似玉壺承沆瀣，遊人掬飲凜生風。"]'),
('9172e915-1e72-4142-a46f-1a3748be3ea7','仙迹巖題詩二十三首 茶嶺','無名氏','宋','宋诗','song-poetry','','[]','秀鍾天柱産靈芝，造就仙芽發嫩旗。',32,'全唐诗/poet.song.253000.json','["秀鍾天柱産靈芝，造就仙芽發嫩旗。", "採向先春煙露裏，喊山鳳尾豈爲奇。"]'),
('6e127092-688f-4368-b558-891d21d15495','仙迹巖題詩二十三首 龍井','無名氏','宋','宋诗','song-poetry','','[]','鯪鰻環遶井楯間，兩目神光狀類丹。',32,'全唐诗/poet.song.253000.json','["鯪鰻環遶井楯間，兩目神光狀類丹。", "杖撲投淵陰霧鎖，殿堂洶湧盡波瀾。"]'),
('bc8f39f8-8391-436b-a145-8b48a681020a','仙迹巖題詩二十三首 無骨篛','無名氏','宋','宋诗','song-poetry','','[]','許氏功成獲上昇，曾遺一劑語丁寧。',64,'全唐诗/poet.song.253000.json','["許氏功成獲上昇，曾遺一劑語丁寧。", "山生紺篛奇無骨，洞隠金丹顯有靈。", "松竹欹岩非易取，煙霞塞道卒難經。", "有緣仙者當須遇，用倖搜求豈露形。"]'),
('4f7b6a7e-3679-4911-86a8-ac8f9442cb64','仙迹巖題詩二十三首 採芝朮即事','無名氏','宋','宋诗','song-poetry','','[]','仙芝靈朮總芳妍，野草閑花各變遷。',32,'全唐诗/poet.song.253000.json','["仙芝靈朮總芳妍，野草閑花各變遷。", "古櫟復榮松化石，藥苗蕃植可延年。"]'),
('282ba09d-e26a-4891-9e64-cb058f94bb8a','仙迹巖題詩二十三首 祥光亭','無名氏','宋','宋诗','song-poetry','','[]','覆石爲亭武肅成，有仙來此變棋枰。',32,'全唐诗/poet.song.253000.json','["覆石爲亭武肅成，有仙來此變棋枰。", "炷香五色祥光現，縹緲靈官朝玉京。"]'),
('55a1c6a7-d9e6-4eb3-aa5e-62e039a39684','仙迹巖題詩二十三首 飛玉亭','無名氏','宋','宋诗','song-poetry','','[]','閑亭清憩覺情優，四顧嵐光景色幽。',32,'全唐诗/poet.song.253000.json','["閑亭清憩覺情優，四顧嵐光景色幽。", "湍玉飛簾侵座冷，璇源本自接天流。"]'),
('821f0871-8379-4c99-b637-2b32e3d2c57a','句','無名氏','宋','宋诗','song-poetry','','[]','鳥鳴深夜豈知形，徹曉音喧響更清。',16,'全唐诗/poet.song.253000.json','["鳥鳴深夜豈知形，徹曉音喧響更清。"]'),
('90deee61-ec4a-40ff-952e-d15660ec65b0','題浩然觀','舒道紀','宋','宋诗','song-poetry','','[]','憕心坐清境，虛白生林端。',48,'全唐诗/poet.song.253000.json','["憕心坐清境，虛白生林端。", "夜靜嘯聲出，月明松影寒。", "絳霞封藥竈，碧竇濺齋壇。", "海樹幾回老，先生棋未殘。"]'),
('d50e6950-cf6d-4af9-a96e-c2dd59699c24','常庵題','范心遠','宋','宋诗','song-poetry','','[]','路入清溪第二灣，東風猶自逗餘寒。',64,'全唐诗/poet.song.253000.json','["路入清溪第二灣，東風猶自逗餘寒。", "白雲粘地掃不去，黄葉戀枝吹未乾。", "沙上濕痕誰涉水，天邊長嘯獨憑闌。", "道人酒意無醲薄，飲盡携琴月下彈。"]'),
('ef62f2a4-f26d-4a5b-b37b-56986685153c','題雲溪庵','范心遠','宋','宋诗','song-poetry','','[]','雲溪高隠卧煙霞，默飲陽晶與月華。',64,'全唐诗/poet.song.253000.json','["雲溪高隠卧煙霞，默飲陽晶與月華。", "霧斂丹臺生瑞草，雲收靈腑結瓊葩。", "青龍吐火烹金茗，白虎跑泉溉玉芽。", "龍虎媾交功九轉，刀圭一粒捧丹砂。"]'),
('18ed0291-c6ac-41f8-a52e-b4f1821c0dda','昭孝道院','趙菊莊','宋','宋诗','song-poetry','','[]','雲深戶不開，竹屋兩三間。',48,'全唐诗/poet.song.253000.json','["雲深戶不開，竹屋兩三間。", "野水浸官渡，低牆出遠山。", "絕葷如鶴瘦，習懶慣童頑。", "我亦皈真者，來公半日閑。"]'),
('e70c0c5f-dec2-44f0-ab8f-c773f11dad03','題方丈  其一','黄庭美','宋','宋诗','song-poetry','','[]','賓雲奏徹控青鸞，綵幔香銷生翠寒。',32,'全唐诗/poet.song.253000.json','["賓雲奏徹控青鸞，綵幔香銷生翠寒。", "三十六峰秋色裏，月明人倚玉闌干。"]'),
('f7143c48-0a05-4b20-9b9a-f1e5b9cf9a10','題方丈  其二','黄庭美','宋','宋诗','song-poetry','','[]','欲看太乙青蔾火，笑領仙人綠玉杯。',32,'全唐诗/poet.song.253000.json','["欲看太乙青蔾火，笑領仙人綠玉杯。", "物外同心誰管鮑，山中清話得張裴。"]'),
('6cd4cedf-e40d-4804-a725-b84d41fd26f5','題方丈  其三','黄庭美','宋','宋诗','song-poetry','','[]','九重雲外步虛聲，十二時中太古情。',32,'全唐诗/poet.song.253000.json','["九重雲外步虛聲，十二時中太古情。", "爲問當年赤松子，人生何處是功成。"]'),
('b171c491-0ad0-4ded-8130-57556aab5d44','天遊觀','林錫翁','宋','宋诗','song-poetry','','[]','覽遍溪山最上頭，琳宮貝闕更清幽。',32,'全唐诗/poet.song.253000.json','["覽遍溪山最上頭，琳宮貝闕更清幽。", "雖然未得長生訣，也道曾從天上遊。"]'),
('139a1aa2-10b4-467e-929b-68436ed017c8','天柱峰','林錫翁','宋','宋诗','song-poetry','','[]','共工發怒亦徒然，煉石忙忙女補天。',32,'全唐诗/poet.song.253000.json','["共工發怒亦徒然，煉石忙忙女補天。", "既用斷鰲并立極，此峰何不立當先。"]'),
('55696594-6496-4f5d-8643-254b82a28e5f','接笋巖','林錫翁','宋','宋诗','song-poetry','','[]','兒童日報竹平安，新笋如何折一痕。',32,'全唐诗/poet.song.253000.json','["兒童日報竹平安，新笋如何折一痕。", "接住喜憑仙掌力，春風胡不長琅玕。"]'),
('249d82d5-4f3f-4306-bb0e-08cb34fb88e8','貓兒峰','林錫翁','宋','宋诗','song-poetry','','[]','貓兒峰小眼精光，來護仙家石廩糧。',32,'全唐诗/poet.song.253000.json','["貓兒峰小眼精光，來護仙家石廩糧。", "回顧威風何凜凜，山中安得有拖腸。"]'),
('117f1010-a76d-4be2-97ef-2828a32aee36','金鷄巖','林錫翁','宋','宋诗','song-poetry','','[]','幾載修真洞裏人，只憑啁哳報天明。',32,'全唐诗/poet.song.253000.json','["幾載修真洞裏人，只憑啁哳報天明。", "丹成不逐劉安去，只在岩頭唱五更。"]'),
('ad4909c8-cb2b-4cbd-a5ac-3e973e1988d7','隠求齋','林錫翁','宋','宋诗','song-poetry','','[]','蝸名蠅利處樊籠，世事□其轉眼空。',32,'全唐诗/poet.song.253000.json','["蝸名蠅利處樊籠，世事□其轉眼空。", "惟有高人林下隠，只求明月與清風。"]'),
('58b3e133-6e3c-41e7-81a8-c17b2f726d5d','天遊觀','陳元英','宋','宋诗','song-poetry','','[]','琅玕瑶草滿空山，月上丹臺鶴未還。',32,'全唐诗/poet.song.253000.json','["琅玕瑶草滿空山，月上丹臺鶴未還。", "夜入瓊樓襟袖冷，始知身在白雲間。"]'),
('7802f70b-bba1-44fb-ab2f-af39bf00c26c','翠蛟亭','新父','宋','宋诗','song-poetry','','[]','斷崖捲銀濤，拍岸雪相濺。',24,'全唐诗/poet.song.253000.json','["斷崖捲銀濤，拍岸雪相濺。", "去住本無心，曾向岷峨見。"]'),
('a14172a9-afea-46e9-b909-9daae7f7320b','翠蛟亭','金堅','宋','宋诗','song-poetry','','[]','怒猊抉石驥奔泉，誰挽河流下九天。',32,'全唐诗/poet.song.253000.json','["怒猊抉石驥奔泉，誰挽河流下九天。", "傾瀉瓊珠三萬斛，從師乞作買山錢。"]'),
('7c7d30b8-ddb0-4b38-8e2c-b6cda5834dc2','大滌洞','金堅','宋','宋诗','song-poetry','','[]','手翻河漢出天關，雪漱霜飛照眼寒。',32,'全唐诗/poet.song.253000.json','["手翻河漢出天關，雪漱霜飛照眼寒。", "且向亭前供玩好，却來筆底作波瀾。"]'),
('ca6caadf-58d1-4a07-8e12-aca78aa05a38','翠蛟亭','泰亨','宋','宋诗','song-poetry','','[]','坡謝無人共此山，翠蛟亭上拍欄干。',64,'全唐诗/poet.song.253000.json','["坡謝無人共此山，翠蛟亭上拍欄干。", "溪聲到耳三更雨，嵐氣霑衣六月寒。", "酒釀可呼仙子飲，池深怕有老龍蟠。", "天河挽住不容易，只縱游人一餉觀。"]'),
('5aec4a37-96a1-4e5a-9a07-aec13fcaacd1','賡翠蛟亭韻','王與能','宋','宋诗','song-poetry','','[]','靈砂九轉鍊金頑，留得丹泉在此間。',64,'全唐诗/poet.song.253000.json','["靈砂九轉鍊金頑，留得丹泉在此間。", "明月清風誰管領，洞天福地占幽閑。", "巖巔雪湧金波立，石罅潮生銀屋翻。", "句續坡仙懷古意，梅花也覺带歡顔。"]'),
('70110b27-9123-471f-b497-4166728e5287','游洞霄宮','王與能','宋','宋诗','song-poetry','','[]','洞霄飛杖屨，人境共真清。',48,'全唐诗/poet.song.253000.json','["洞霄飛杖屨，人境共真清。", "天柱擎峰出，丹泉迸霤生。", "棲巖遺隠迹，漱石洗虛名。", "珍重樂斯者，微吟謾紀行。"]'),
('f539445d-6c8f-447e-8da2-4bfacf8e6453','借翠蛟亭韻','笑擲震雷','宋','宋诗','song-poetry','','[]','兀兀梅窗坐已頑，自憐失脚落人間。',64,'全唐诗/poet.song.253000.json','["兀兀梅窗坐已頑，自憐失脚落人間。", "洞霄宮裏星辰近，天柱峰前日月閑。", "野鶴聽琴飛雪舞，湫龍喜客爲瀾翻。", "此中不晝生雲雨，珍重坡仙一扁顔。"]'),
('a87fabd1-865e-4e42-945a-364728933716','游洞霄宮  其一','黄常吉','宋','宋诗','song-poetry','','[]','山鎖清溪溪鎖峰，溪光山色兩怡融。',64,'全唐诗/poet.song.253000.json','["山鎖清溪溪鎖峰，溪光山色兩怡融。", "松枝點滴衣夾雨，雲葉飄揚巖際風。", "玉室金堂端好坐，石壇乳竇自相通。", "我生已幸塵緣薄，擬結茅廬天柱東。"]'),
('88c42ff1-77aa-4920-a066-e6f271206de5','游洞霄宮  其二','黄常吉','宋','宋诗','song-poetry','','[]','喬松蒼竹带煙霏，木拱彤簷藹翠微。',64,'全唐诗/poet.song.253000.json','["喬松蒼竹带煙霏，木拱彤簷藹翠微。", "虛谷玲瓏遺鳳響，行雲蒙密護龍歸。", "繁花結繡迷樵徑，靈飄藥香滿客衣。", "更欲搘筇遍諸頂，可憐無策駐殘暉。"]'),
('f7e40849-5b46-45a2-a42b-5d5dc3bdb1d5','游洞霄','黄常吉','宋','宋诗','song-poetry','','[]','我厭城市喧，故作林泉遊。',48,'全唐诗/poet.song.253000.json','["我厭城市喧，故作林泉遊。", "十事思九錯，一笑忘百憂。", "道念豈不定，俗累良未休。", "安得弄泉石，味道老一丘。"]'),
('16f00845-6e46-4bed-ba2a-26058329f82d','游洞霄宮','祕仲威','宋','宋诗','song-poetry','','[]','洞霄之名天下聞，洞霄之職宰輔分。',128,'全唐诗/poet.song.253000.json','["洞霄之名天下聞，洞霄之職宰輔分。", "聞名姓往未識面，寄祿於此徒紛紛。", "身到仙關不如我，九虎迎門開□鎖。", "六洞高人接笑談，三泉隠客通香火。", "風來萬壑嘶松杉，水繞百折鳴嵌巖。", "門前俗客自斂迹，不待立柱名隔凡。", "群仙挽衣留我住，因一相逢忽相語。", "雙徑秋風已掃塵，奚爲後我同歸去。"]'),
('84b8006c-7f27-40c3-a58e-15fa175572fd','大滌洞天留題  其一','祕仲威','宋','宋诗','song-poetry','','[]','紫府清都不可梯，何年宮闕下遷移。',64,'全唐诗/poet.song.253000.json','["紫府清都不可梯，何年宮闕下遷移。", "飛來殿閣風雷架，逼近巖崖日月馳。", "境靜固宜真聖宅，地靈唯許列仙知。", "想應留鑰更相授，以待虛皇駕幸時。"]'),
('8cdbf613-f47d-42c4-a0c7-36b7cc71396a','大滌洞天留題  其二','祕仲威','宋','宋诗','song-poetry','','[]','我行不識洞霄門，但怪東來見紫氛。',64,'全唐诗/poet.song.253000.json','["我行不識洞霄門，但怪東來見紫氛。", "玉帝衮衣明日月，仙官劍履會風雲。", "箬根也有靈丹助，芝草疇非協氣薰。", "亦恐彌明寓茲境，儻同尊酒細論文。"]'),
('1f8a0539-073d-4b48-8a93-e11fd1e05be9','游洞霄宮  其一','張巽','宋','宋诗','song-poetry','','[]','掣開九鎖謁琳宮，物色真仙劍履蹤。',64,'全唐诗/poet.song.253000.json','["掣開九鎖謁琳宮，物色真仙劍履蹤。", "一朵雲根生老澗，千尋天柱壓群峰。", "功名祕略求黄石，呼吸微言斅赤松。", "我是康廬倦游客，朅來猶愛翠雲重。"]'),
('11c99890-5dce-4ed1-bfdc-93e2110042f3','游洞霄宮  其二','張巽','宋','宋诗','song-poetry','','[]','新晴草木翠光流，麥隴清和四月秋。',64,'全唐诗/poet.song.253000.json','["新晴草木翠光流，麥隴清和四月秋。", "巽二風來山髪冷，阿香雷過馨聲幽。", "杜鵑鬨枕催歸去，丁鶴攀轅欲借留。", "半夜忽聞巖壑響，小詩調戲鬼神愁。"]'),
('6f3f1cb7-239f-4492-b9e8-68524086318a','游洞霄宮  其三','張巽','宋','宋诗','song-poetry','','[]','曜相偏羸足力强，不辭複嶺與重崗。',64,'全唐诗/poet.song.253000.json','["曜相偏羸足力强，不辭複嶺與重崗。", "未窮仙隠千年跡，先炷宸遊一瓣香。", "詩得好題難駐筆，酒逢佳趣便飛觴。", "夢回彷彿前身事，却認金庭是故鄉。"]'),
('6e98719b-a35c-462b-b9c3-b192b3ac9959','游洞霄宮','盧正中','宋','宋诗','song-poetry','','[]','雲海三山路忽通，形神俱妙玉霄東。',32,'全唐诗/poet.song.253000.json','["雲海三山路忽通，形神俱妙玉霄東。", "八篇擬授無司馬，銀鼎浮珠問葛翁。"]'),
('d78f5069-e2b3-44a4-90e0-6f1dbad9ded7','游洞霄宮','余愚','宋','宋诗','song-poetry','','[]','琳宮勝處絕塵囂，千古佳名號洞霄。',64,'全唐诗/poet.song.253000.json','["琳宮勝處絕塵囂，千古佳名號洞霄。", "地鎖九峰形屈曲，擎天一柱勢岧嶢。", "鳳鳴怪石仙巖邃，蛟舞流泉澗壑遥。", "幸有飛昇遺跡在，便須騎鶴快扶摇。"]'),
('ce318ce3-b610-4f8d-ad07-085832469c13','游洞霄','陸卿','宋','宋诗','song-poetry','','[]','名山長表冠東南，一柱屹然天與參。',64,'全唐诗/poet.song.253000.json','["名山長表冠東南，一柱屹然天與參。", "玉府從來通六六，金扃寧竟鎖三三。", "千巖深處標馴虎，萬乘當時幸秣驂。", "撫掌酌泉觀舞翠，清忠□詠□高談。"]'),
('b6c29f31-e2be-475f-a6fc-27fc788ecd0d','遊洞霄和坡仙韻','史宗愷','宋','宋诗','song-poetry','','[]','水非凡濁石非頑，水石縈迴九鎖間。',64,'全唐诗/poet.song.253000.json','["水非凡濁石非頑，水石縈迴九鎖間。", "遊客步隨清浪起，道人身似白雲閑。", "仙巖泉滴瓊音碎，古木風輕寶蓋翻。", "共酌翠蛟亭上酒，翠光相與映紅顔。"]'),
('04cdf317-1c20-436b-9cbc-0622989698d2','和周丞丈遊洞霄韻','史宗愷','宋','宋诗','song-poetry','','[]','苕溪之源流洞天，中有福地壽可延。',176,'全唐诗/poet.song.253000.json','["苕溪之源流洞天，中有福地壽可延。", "山盤九鎖到空谷，石間隠蹟知其仙。", "懸崖險阻不易到，來者悚觀須有緣。", "道邊獸石卧獅虎，庭下鏡沼流潺湲。", "東游大滌阻天柱，西至石室飛寒泉。", "雲房石磴絡苔蘚，疑是霞玉留花鈿。", "嵌空上下不可數，曉猿夜鶴驚人眠。", "西林詩伯□仙裔，落筆妙句今青錢。", "歷窮巘嶮事幽討，不畏蔓草矜蛇蜒。", "皈來詩篇壯青谷，好句屹崛參天全。", "何當□約素秋晚，與公共醉洪崖巔。"]'),
('7f408259-f884-455b-b6ab-1bdd15ed56f0','游洞霄','易群峰','宋','宋诗','song-poetry','','[]','片雲將雨又輕還，物外光陰本自閑。',32,'全唐诗/poet.song.253000.json','["片雲將雨又輕還，物外光陰本自閑。", "醉裏不妨游汗漫，詩成更爲寫斕斑。"]'),
('a13f971b-a1b6-401b-b751-375d4298ba4a','初入洞霄','易群峰','宋','宋诗','song-poetry','','[]','半生華髪笑茫然，作意清朝到洞天。',64,'全唐诗/poet.song.253000.json','["半生華髪笑茫然，作意清朝到洞天。", "疊嶂互□芒屩穩，飛雲故傍葛巾偏。", "忍思城市輪蹄夢，款結山林筍蕨緣。", "我有賜餘蒼玉璧，與君同試酌寒泉。"]'),
('d296af7d-478d-44d0-bd8a-c2be8a545017','遊洞霄','姚自强','宋','宋诗','song-poetry','','[]','青藜有分步仙家，昨日晴暉今雨霾。',32,'全唐诗/poet.song.253000.json','["青藜有分步仙家，昨日晴暉今雨霾。", "不是游觀先一日，何緣識得淡生涯。"]'),
('882e1474-d5c9-4ec7-b963-7487aee02756','游洞霄','徐獻子','宋','宋诗','song-poetry','','[]','何處尋仙隠，樓居出世間。',48,'全唐诗/poet.song.253000.json','["何處尋仙隠，樓居出世間。", "洞天藏福地，丹水接青山。", "樹掛崖腰古，苔封石齒班。", "午窗經卷寂，長對□□□。"]'),
('0c12ab24-a9ef-4628-9ec2-ca75604598bd','游洞霄','聶兼善','宋','宋诗','song-poetry','','[]','吾聞洞霄山水妙天下，繚白縈青勝圖寫。',226,'全唐诗/poet.song.253000.json','["吾聞洞霄山水妙天下，繚白縈青勝圖寫。", "九重扃鑰極深嚴，一岫寬閑更瀟灑。", "倚空天柱何孤高，諸峰羅立猶兒曹。", "長松怪石入題品，金堂玉室供遊遨。", "此地隠居皆勝士，道骨仙風絕塵滓。", "就中俞子最少年，烱若芙蓉映秋水。", "青鞋布襪千里來，一見使我昏眸開。", "談空說有坐終日，舌濤衮衮生風雷。", "鄙夫未愚晚聞道，寄傲嵌巖事幽討。", "只緣方寸無荆棘，漸喜丹田熟梨棗。", "人生百歲空自忙，讀書博塞俱亡羊。", "勸君火急烹鉛汞，莫待倒景飛屋梁。", "春風又放鶑求友，烟外暗黄初著柳。", "南行儻遇置書郵，莫忘超然北山叟。"]'),
('75acab46-de5a-4060-98b7-cfd40c116785','遊洞霄','嚴嘉','宋','宋诗','song-poetry','','[]','帝子吹簫上瑶闕，靈妃跨鳳音塵絕。',112,'全唐诗/poet.song.253000.json','["帝子吹簫上瑶闕，靈妃跨鳳音塵絕。", "行雲山水跡依然，留伴九峰秋夜月。", "閬苑宮前見玉真，許傳消息到金庭。", "瓊姿一去丹霞□，紫桂蟠桃幾度春。", "十二欄干天一握，教人望斷緱山鶴。", "蜀客歸槎杳未來，銀漢縱香泉□□。", "巖前邂逅童顔子，許我刀圭大患痊。"]'),
('291df9ec-9c80-451f-b959-188d9aa2c51c','遊洞霄','餘杭令','宋','宋诗','song-poetry','','[]','野服蕭蕭款翠微，虛亭高敞射晴暉。',64,'全唐诗/poet.song.253000.json','["野服蕭蕭款翠微，虛亭高敞射晴暉。", "仙歸洞府雲烟靜，春入名山笋蕨肥。", "緩飲壺觴聊自適，暫指朱墨便忘歸。", "何時罷脫利名去，始悟人間萬事非。"]'),
('2caddad0-96ec-4b6d-b348-68209bd38190','洞霄紀遊','聞鑒','宋','宋诗','song-poetry','','[]','從來此山中，不記幾遊歷。',120,'全唐诗/poet.song.253000.json','["從來此山中，不記幾遊歷。", "每緣困杯酌，未暇賦篇什。", "屢恐爲山羞，欲吟嗟思澀。", "今晨始杖屨，醒眼看泉石。", "草木呈幽姿，烟雲舒秀色。", "捫蘿扣棲真，束燎穿大滌。", "神工跨石梁，天巧鏤巖壁。", "仙人不可逢，靈箬無從得。", "回觀翠蛟舞，俯視雲根屹。", "何如出山去，飛騰霈甘澤。"]'),
('17b38107-bde2-433f-aab8-4dab98f885b7','游洞霄','何處厚','宋','宋诗','song-poetry','','[]','洞天宮中清無塵，紛紛霏霏翔五雲。',208,'全唐诗/poet.song.253000.json','["洞天宮中清無塵，紛紛霏霏翔五雲。", "光浮閬風藹無垠，中有神仙相輩倫。", "服曳雲章玉佩珣，時聞金鐘催朝真。", "仙班序列覲紫宸，瓊花羌靈飛翁翁。", "水晶簾捲許行循，群仙以我丘壑身。", "相與笑語交益親，玄談妙句泣鬼神。", "一局圍棋度幾春，大開十二樓宴賓。", "玉真安排雲錦茵，天女競着絳霞裙。", "盎缶罍洗羅珠珍，金爐龍腦香騰薰。", "七寶蠟炬光如銀，鳳泉飲散醉醺醺。", "天子呼來不得臣，宴罷乘槎渡漢津。", "玉皇遽遣使者巡，使者交薦有大勳。", "玉皇詔歸眷注勤，不容山中伴帝君。"]'),
('ad7c4a9c-ed7c-43a6-8a97-8e1fa9b6a755','游洞霄','彭揮','宋','宋诗','song-poetry','','[]','洞霄從古宅真仙，鎮日群峰起瑞烟。',64,'全唐诗/poet.song.253000.json','["洞霄從古宅真仙，鎮日群峰起瑞烟。", "林下千年丹已就，山中九鎖月長圓。", "半巖隠迹遺靈像，一井清凉撫掌泉。", "我到此間無別事，燒香直欲達諸天。"]'),
('6379d46e-781c-404a-a732-4268019d23a2','游洞霄','米仲昌','宋','宋诗','song-poetry','','[]','公餘陪侍九鎖行，花已凋殘鶑已老。',64,'全唐诗/poet.song.253000.json','["公餘陪侍九鎖行，花已凋殘鶑已老。", "舞蛟亭下泉如奔，伏虎巖前景尤好。", "四圍翠巘悉可躋，一點紅塵渾不到。", "坐中元白非一人，自愧才疏難壓倒。"]'),
('a0ed7d15-8b3a-4370-b4be-656eff1cd6c8','遊洞霄','俞洵直','宋','宋诗','song-poetry','','[]','九折山圍五洞天，中間玉殿倚祥烟。',64,'全唐诗/poet.song.253000.json','["九折山圍五洞天，中間玉殿倚祥烟。", "隔雲雞犬聞清曉，鎖徑松篁認永年。", "野鹿獻花來石室，寒猿擲果飲溪泉。", "玉皇弄笑飛金電，太上紅顔雪滿顛。"]'),
('93d0993d-7062-4a3b-a17f-921b29ec040d','夜宿武夷宮','彥修','宋','宋诗','song-poetry','','[]','巢松老鶴鳴丹井，籠月梅花摇素影。',64,'全唐诗/poet.song.253000.json','["巢松老鶴鳴丹井，籠月梅花摇素影。", "竹敲白露幔亭寒，吟弄紫簫山月冷。", "山月簫聲清且幽，幔亭不見昔人游。", "我來欲此騰雲霧，笑指三山十二樓。"]'),
('011643bc-a06c-4082-9521-42eda5313dfd','宿武夷宮  其一','彥修','宋','宋诗','song-poetry','','[]','學仙獨訪武夷君，老樹垂藤弄夕曛。',32,'全唐诗/poet.song.253000.json','["學仙獨訪武夷君，老樹垂藤弄夕曛。", "我欲幔亭拚一醉，不知何處奏賓雲。"]'),
('809ac2bf-87ab-441f-82f8-967ffe049d50','宿武夷宮  其二','彥修','宋','宋诗','song-poetry','','[]','月滿空山雪滿溪，幽人何處吹龍笛。',32,'全唐诗/poet.song.253000.json','["月滿空山雪滿溪，幽人何處吹龍笛。", "醒來和月倚虛窗，鶴翻松露滴雲石。"]'),
('edb9da2f-f766-4985-b193-9ebe545e7921','宿武夷宮  其三','彥修','宋','宋诗','song-poetry','','[]','偶過群仙入武夷，蒼崖瑶草白雲飛。',32,'全唐诗/poet.song.253000.json','["偶過群仙入武夷，蒼崖瑶草白雲飛。", "不知何處猿啼月，巖上松花落滿衣。"]'),
('1de1c27b-f606-4c9d-ad4b-75f5f5132294','益清堂偶作','自强','宋','宋诗','song-poetry','','[]','大洞仙宮古有名，要觀主宰立平生。',64,'全唐诗/poet.song.253000.json','["大洞仙宮古有名，要觀主宰立平生。", "掛琴堂上心尤逸，種菊池邊景益清。", "巳喜襟期同我得，旋將契誼與君盟。", "丹泉肯入丹田去，願受丹□學大成。"]'),
('1b2fada2-7365-47a6-b603-1c1fbcc4bdad','山行宿道院','蕭蘭皋','宋','宋诗','song-poetry','','[]','終朝穿翠微，投暮叩松扉。',48,'全唐诗/poet.song.253000.json','["終朝穿翠微，投暮叩松扉。", "童子出相語，道人猶未歸。", "尋香溫紙被，拂石弄金徽。", "明發下山去，白雲隨馬飛。"]'),
('4f00dabd-145c-4f7a-a24c-57492a57e3f5','超然館彈琴夜話','陳庚生','宋','宋诗','song-poetry','','[]','玉琴彈罷一燈青，仙鼠飛飛到客庭。',32,'全唐诗/poet.song.253000.json','["玉琴彈罷一燈青，仙鼠飛飛到客庭。", "道士却能談肇論，夜深傾聽有山靈。"]'),
('d3e55ce1-8702-42d9-8db8-c11d6e3cf992','濯纓亭','陳庚生','宋','宋诗','song-poetry','','[]','誰引滄洲客，行歌到此亭。',48,'全唐诗/poet.song.253000.json','["誰引滄洲客，行歌到此亭。", "縈迴一水碧，巉絕兩峰青。", "小雨吹行艦，疏梅度遠汀。", "我無纓可濯，華髪任星星。"]'),
('4fa804a1-c6de-4498-a213-6d3e526da15a','謁陶隠居祠呈郎中張聲華','陳庚生','宋','宋诗','song-poetry','','[]','煉就靈丹歲月賒，藥爐丹竈旋成漥。',64,'全唐诗/poet.song.253000.json','["煉就靈丹歲月賒，藥爐丹竈旋成漥。", "庭空響落山松子，路遠香迷野草花。", "舊事誰能問□水，神仙今已在東華。", "田翁猶酹先生酒，亂紙飛錢噪暮鴉。"]'),
('4ba91364-d447-4c18-a153-6ecd4cc4cbe0','賀家湖','陳庚生','宋','宋诗','song-poetry','','[]','風流誰似賀知章，乞得平湖任草荒。',32,'全唐诗/poet.song.253000.json','["風流誰似賀知章，乞得平湖任草荒。", "今日藕花三百畝，折來依舊屬君莊。"]'),
('a5f4afed-3642-4b62-b196-876dccfb5856','遊天柱宮因留宿觀醮','何君式','宋','宋诗','song-poetry','','[]','路轉峰回意豁然，逢迎馬首更飛泉。',64,'全唐诗/poet.song.253000.json','["路轉峰回意豁然，逢迎馬首更飛泉。", "地嚴九鎖紅塵外，天近三關黄道邊。", "奏簡夜騰孤鶴表，步虛聲徹老龍淵。", "會須香火通仙籍，一洗人間未了緣。"]'),
('5dc891cb-b57b-4211-9274-f35ead4084a5','都下作','樓雲卧','宋','宋诗','song-poetry','','[]','紅塵車馬道，曾向閙中看。',48,'全唐诗/poet.song.253000.json','["紅塵車馬道，曾向閙中看。", "貴賤人多等，利名心一般。", "侯門崇嗜慾，客路薄孤寒。", "誰肯翻然悟，尋仙求大丹。"]'),
('37ee3066-58e1-427c-803c-2c9521ca7195','古揚州','倪應淵','宋','宋诗','song-poetry','','[]','雉堞平來塹擁沙，綠蕪闕處見人家。',64,'全唐诗/poet.song.253000.json','["雉堞平來塹擁沙，綠蕪闕處見人家。", "山河舊影藏秋月，關塞新聲起暮笳。", "玉蕊已爲亭下草，蒺藜不是眼中花。", "當年鳳舸經行地，枯柳無枝寄宿鴉。"]'),
('1c062d5a-d218-49d0-a330-b7e3c6bc594a','雷塘','倪應淵','宋','宋诗','song-poetry','','[]','天留遺迹鑑興亡，出郭傷心見此塘。',64,'全唐诗/poet.song.253000.json','["天留遺迹鑑興亡，出郭傷心見此塘。", "廢苑無螢秋寂寂，壞陵有樹月蒼蒼。", "綠悽霜重摧荷蓋，紫怯波寒褪芰裳。", "喚醒錦帆當日夢，一聲水調隔雲長。"]'),
('bce1200d-5b76-4b6a-878a-15986b60509c','多景樓','倪應淵','宋','宋诗','song-poetry','','[]','狠石蒼頑歲月遥，幾人觸境想英標。',64,'全唐诗/poet.song.253000.json','["狠石蒼頑歲月遥，幾人觸境想英標。", "欲知三國興亡事，但看一江來去潮。", "南土塵飛通嶺海，中流砥立獨金焦。", "雲山繞檻期深隠，不受劉安作賦招。"]'),
('821f710a-7d25-4e2c-a922-cfea0349c2b9','金山寺','倪應淵','宋','宋诗','song-poetry','','[]','金錫飛來日，靈鼇負地形。',48,'全唐诗/poet.song.253000.json','["金錫飛來日，靈鼇負地形。", "濤翻四面白，寺裹一山青。", "海月窺簷箔，天風語塔鈴。", "倦懷思煮茗，誰與汲中𤃩。"]'),
('ffd6bb0b-7e7a-4253-960f-b1d55368d750','太平州','趙竹屋','宋','宋诗','song-poetry','','[]','拍欄一笑大江橫，號太平州亦浪名。',32,'全唐诗/poet.song.253000.json','["拍欄一笑大江橫，號太平州亦浪名。", "春水秋濤流不盡，半年農事半年兵。"]'),
('e9af7fa6-7d90-49d0-92de-c33f570caaa4','城南','王月窗','宋','宋诗','song-poetry','','[]','早出城南路，江山總着題。',48,'全唐诗/poet.song.253000.json','["早出城南路，江山總着題。", "林高樓似縮，岸遠樹疑低。", "鸜鵒噪喬木，桔橰鳴小畦。", "郵亭聊一憩，沽酒夕陽西。"]'),
('db22198a-a922-4a15-a740-8e250ed65b40','普向山門','王月窗','宋','宋诗','song-poetry','','[]','來訪山中景，亭闌鼠甘陰。',48,'全唐诗/poet.song.253000.json','["來訪山中景，亭闌鼠甘陰。", "客投孤寺宿，蟬趁夕陽晴。", "滿樹青苔濕，一村黄葉深。", "納凉歸去晚，湖月掛遥林。"]'),
('6832d5a8-39f3-42c6-b709-33c67af02ac9','邊景','曾邍','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','匹馬來逢寒草秋，淮雲一片隔神州。',64,'全唐诗/poet.song.253000.json','["匹馬來逢寒草秋，淮雲一片隔神州。", "黄昏燈火西津渡，白晝風烟北固樓。", "猶有斷碑知晉宋，誰將遺石問孫劉。", "天荒地老英雄盡，落日長江萬古秋。"]'),
('d7f44325-c7a4-48fb-a978-d69f8d260341','題九鎖山','陳逢辰','宋','宋诗','song-poetry','','[]','九山互鎖碧烟深，路轉花香惱客吟。',64,'全唐诗/poet.song.253000.json','["九山互鎖碧烟深，路轉花香惱客吟。", "歸鶴带雲回谷口，潜蛟飛雪噴亭心。", "洞中無計尋芝鼠，箬底猶聞搗藥禽。", "莫歎仙凡幾塵隔，菊花巖畔是知音。"]'),
('4fdbcc9f-9e72-4c05-a91a-0f542d1eb10a','天台道中','釋惠嵩','宋','宋诗','song-poetry','','[]','滿川梨雪照斜曛，野水交流路不分。',32,'全唐诗/poet.song.253000.json','["滿川梨雪照斜曛，野水交流路不分。", "隔岸一聲牛背笛，和風吹落渡頭雲。"]'),
('034d6191-a7a0-45b3-bb67-13c08d72eb5a','歙溪道中','周耕雲','宋','宋诗','song-poetry','','[]','行行欲少歇，爭奈客途長。',48,'全唐诗/poet.song.253000.json','["行行欲少歇，爭奈客途長。", "村酒略無味，野花空自香。", "幾家茅屋小，數畝麥田荒。", "何處堪投宿，林梢已夕陽。"]'),
('2139375b-7bcb-44be-b8d1-89b156dfd30d','賦介軒半村新居','周耕雲','宋','宋诗','song-poetry','','[]','近謀吟屋傍潯溪，雁蕩山深雲未歸。',64,'全唐诗/poet.song.253000.json','["近謀吟屋傍潯溪，雁蕩山深雲未歸。", "怕惱春光花種少，愛延月色竹栽稀。", "寶藏書冊教兒讀，土視功名與世違。", "不是詩人相過處，晝長應是掩柴扉。"]'),
('b5336e6e-901e-41f1-8e60-ffbb5a1e0931','清江道中','胡琴窗','宋','宋诗','song-poetry','','[]','黑潦妨行役，呼船渡碧灣。',48,'全唐诗/poet.song.253000.json','["黑潦妨行役，呼船渡碧灣。", "春烟數家遠，綠樹一鶑閑。", "古有難行路，今無僻處山。", "空餘芳草句，流落在人間。"]'),
('6cce1d9a-c1ed-4117-a0b9-bce2e0ec8832','題柯山道中','何籌齋','宋','宋诗','song-poetry','','[]','扁舟空載斷紋琴，橫膝誰知太古音。',32,'全唐诗/poet.song.253000.json','["扁舟空載斷紋琴，橫膝誰知太古音。", "趁取暮潮歸舊隠，豆花籬落正秋深。"]'),
('2c6f429a-cad6-4200-a9e3-cda922c2eacb','溪軒即事','何籌齋','宋','宋诗','song-poetry','','[]','小立溪窗下，山光晚不同。',48,'全唐诗/poet.song.253000.json','["小立溪窗下，山光晚不同。", "清秋霜未降，烏桕葉先紅。", "橋影涵深水，鍾聲挾遠風。", "閑情誰領會，吟處倚梧桐。"]'),
('ad45a7b5-c148-4260-a69f-e38a86f82d65','書鄉僧庵','何籌齋','宋','宋诗','song-poetry','','[]','靜答光陰轉法華，生涯更藉菊爲家。',64,'全唐诗/poet.song.253000.json','["靜答光陰轉法華，生涯更藉菊爲家。", "山園隔樹翻秋雨，石逕縈池浴晚霞。", "學鳳尾翹無限草，似雞冠樣不勝花。", "蕭槮安得諸王謝，竹下清譚煮露芽。"]'),
('cbf9fc59-e26b-4ae7-89de-5c1c98ea2fcb','林間','劉草廬','宋','宋诗','song-poetry','','[]','身如孤鶴在林間，百事無營只愛閑。',64,'全唐诗/poet.song.253000.json','["身如孤鶴在林間，百事無營只愛閑。", "最得意時朝曝背，未忘情處晚看山。", "靜拈周易從頭讀，醉把唐詩信手刪。", "爲愛石橋明月色，柴門常是夜深關。"]'),
('727a291f-8e9c-4719-9d86-5abfd3c64cfb','廬山','章雲心','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','晚眺青牛谷，晨遊白鹿山。',48,'全唐诗/poet.song.253000.json','["晚眺青牛谷，晨遊白鹿山。", "乾坤何日老，今古幾人閑。", "卉木煙華紫，江湖雨氣斑。", "聘君猶在否，悵望隔雲關。"]'),
('754c081b-c344-4be6-89a5-7b9be1a8344f','竹','章雲心','宋','宋诗','song-poetry','','[]','萬朵奇雲繞屋飛，雲心修竹綠猗猗。',64,'全唐诗/poet.song.253000.json','["萬朵奇雲繞屋飛，雲心修竹綠猗猗。", "孤高不爲風霜折，正直只應天地知。", "四海久無龍化處，千年幾具雁來時。", "晉林充隠皆塵土，瞻彼西山我所思。"]'),
('dda718ca-dfaa-42d0-9fbb-cd955a358a83','武昌江漢亭','章雲心','宋','宋诗','song-poetry','','[]','江漢亭前江漢浮，岷嶓萬里會吳頭。',64,'全唐诗/poet.song.253000.json','["江漢亭前江漢浮，岷嶓萬里會吳頭。", "江穿南北天心落，漢接東西地脈流。", "水上龍爭方一夢，山中鵲起已千秋。", "張劉精爽知何在，安得同來賦遠遊。"]'),
('af1382bd-4f05-4271-97d5-310b0097f225','古意十四首  其一','章雲心','宋','宋诗','song-poetry','','[]','龍馬圖猶在，麒麟使亦傳。',24,'全唐诗/poet.song.253000.json','["龍馬圖猶在，麒麟使亦傳。", "羲皇心不死，孔子夢難圓。"]'),
('9b4e560b-ac55-4920-b1c3-f31b06176cd3','古意十四首  其二','章雲心','宋','宋诗','song-poetry','','[]','折柳繫離船，船行柳條短。',24,'全唐诗/poet.song.253000.json','["折柳繫離船，船行柳條短。", "頼有枝上花，飄泊隨君遠。"]'),
('b1bae408-f41b-4f64-a647-c470d24c9948','古意十四首  其三','章雲心','宋','宋诗','song-poetry','','[]','采蓮莫采花，采花損空房。',24,'全唐诗/poet.song.253000.json','["采蓮莫采花，采花損空房。", "留房結青子，種作明年香。"]'),
('5eeabfbd-f79d-404d-8eb0-0a50231879ea','古意十四首  其四','章雲心','宋','宋诗','song-poetry','','[]','匆匆采桑女，花雨濕襜袖。',24,'全唐诗/poet.song.253000.json','["匆匆采桑女，花雨濕襜袖。", "春風十二絃，生世未觸手。"]'),
('cb9bf169-2ffd-4c25-91d5-5c7eb90f10a0','古意十四首  其五','章雲心','宋','宋诗','song-poetry','','[]','浣衣輕浣布，布縷不如絲。',24,'全唐诗/poet.song.253000.json','["浣衣輕浣布，布縷不如絲。", "□堅猶易穿，布弱從可知。"]'),
('2a93ab6a-ee5c-4cc7-8fb5-d5e063b933c8','古意十四首  其六','章雲心','宋','宋诗','song-poetry','','[]','佳人買明鏡，意重輕千金。',36,'全唐诗/poet.song.253000.json','["佳人買明鏡，意重輕千金。", "結以雙羅带，欲照蕩子心。", "蕩子渺不歸，鏡影春雲深。"]'),
('745bf5ca-34a2-4570-8487-f95f243cd77d','古意十四首  其七','章雲心','宋','宋诗','song-poetry','','[]','賤妾燕子身，銜泥巢君屋。',48,'全唐诗/poet.song.253000.json','["賤妾燕子身，銜泥巢君屋。", "游子黄鵠志，辭家獨南翔。", "采花爲誰容，襲蘭爲誰香。", "安得小心風，寄子雙明璫。"]'),
('2170607c-9f7b-4608-af0c-1c17e39343dd','古意十四首  其八','章雲心','宋','宋诗','song-poetry','','[]','難與時流道，憂心常悄悄。',48,'全唐诗/poet.song.253000.json','["難與時流道，憂心常悄悄。", "古道貴平易，今人□機巧。", "好古而居今，每飯不能飽。", "來往無嫌猜，□知愛沙鳥。"]'),
('76f2d4a4-48bc-4ca1-97fe-65a29a57773f','古意十四首  其九','章雲心','宋','宋诗','song-poetry','','[]','百川畢東注，兩丸盡西頹。',60,'全唐诗/poet.song.253000.json','["百川畢東注，兩丸盡西頹。", "二物常汲汲，未嘗少徘徊。", "短生亦如斯，逝者良可哀。", "自昔青雲士，皆爲黄土堆。", "何如大覺仙，無去亦無來。"]'),
('ac434041-1744-44a0-be69-a058c2c5117c','古意十四首  其一○','章雲心','宋','宋诗','song-poetry','','[]','吉凶本由人，往事皆可覆。',60,'全唐诗/poet.song.253000.json','["吉凶本由人，往事皆可覆。", "禍人還自禍，福人還自福。", "于公果傳世，李斯竟夷族。", "豺狼不知寤，紛紛方擇肉。", "達者識幾微，爲之先痛哭。"]'),
('ec5b0c6f-5073-4d29-9cb7-3ca2185e6dea','古意十四首  其一一','章雲心','宋','宋诗','song-poetry','','[]','福禍遞隠伏，榮辱相因依。',48,'全唐诗/poet.song.253000.json','["福禍遞隠伏，榮辱相因依。", "賢達素知此，不肯如脂韋。", "青門工種瓜，首陽甘采薇。", "清風彌萬世，斯人諒堪晞。"]'),
('32ad94fc-9cd1-46af-aa8d-766084e28cb0','古意十四首  其一二','章雲心','宋','宋诗','song-poetry','','[]','谷風扇春和，卉木皆敷芬。',48,'全唐诗/poet.song.253000.json','["谷風扇春和，卉木皆敷芬。", "貞松但如故，高標在煙雲。", "君子守常性，時榮非所欣。", "亦有孤鳳皇，不與衆鳥群。"]'),
('d281eed4-5b8d-447f-96c4-8f63a92e4f71','古意十四首  其一三','章雲心','宋','宋诗','song-poetry','','[]','逝川常東流，白日易西沒。',72,'全唐诗/poet.song.253000.json','["逝川常東流，白日易西沒。", "悠悠天地間，二物何飄忽。", "促迫於生人，綠鬢成華髪。", "昧者不自知，終朝常汩汩。", "利欲沈厥身，其本已先蹷。", "孰若繕真性，以自固靈骨。"]'),
('a2ee100e-3bce-4d04-8261-e66f8ac77b6c','古意十四首  其一四','章雲心','宋','宋诗','song-poetry','','[]','老梅何偃蹇，雪時方始花。',72,'全唐诗/poet.song.253000.json','["老梅何偃蹇，雪時方始花。", "自守歲寒性，不肯隨春花。", "隠人適然見，移植溪水涯。", "瘦影無陽豔，清香絕淫邪。", "閒靜如隠人，隠人心所嘉。", "樵牧無見侵，以詒隠人嗟。"]'),
('555cbe22-5852-4677-8aff-d259c0cd7404','送劉同年入蜀','章雲心','宋','宋诗','song-poetry','','[]','蜀山如砥水如絲，送子西遊蜀道時。',64,'全唐诗/poet.song.253000.json','["蜀山如砥水如絲，送子西遊蜀道時。", "萬里乾坤猶戰血，百年豪傑幾愁眉。", "青蟲漸老秋聲小，白雁不來霜信遲。", "若過錦宮城下路，遥憐墮淚孔明祠。"]'),
('a3461072-4553-40c0-8c4f-d579181dae47','題武夷','林方','宋','宋诗','song-poetry','','[]','□□霞佩久蹁躚，峭壁崚嶒駕紫烟。',64,'全唐诗/poet.song.253000.json','["□□霞佩久蹁躚，峭壁崚嶒駕紫烟。", "天下名山無此境，世間何地更尋仙。", "雲迷古洞還丹室，鶴護仙家種玉田。", "我欲携書來此住，隠屏峰下弄雲泉。"]'),
('1f85e124-3e26-4df9-9b68-21f23863a8db','題武夷','楊遶善','宋','宋诗','song-poetry','','[]','說盡東南第一峰，武夷端與畫圖同。',64,'全唐诗/poet.song.253000.json','["說盡東南第一峰，武夷端與畫圖同。", "幔亭烟带凌霄紫，玉女霜花照水紅。", "漁父欹殘溪澗冷，仙人蛻久洞巖空。", "飛塵馬足何時已，安得誅茅深翠中。"]'),
('1a8d8817-b450-4a20-baab-dca0a67461bc','題武夷','孫士廉','宋','宋诗','song-poetry','','[]','翠巖九曲老仙家，玉女峰頭煉紫霞。',64,'全唐诗/poet.song.253000.json','["翠巖九曲老仙家，玉女峰頭煉紫霞。", "幻海無人來跨鶴，天河有路可乘槎。", "春雲細釀幔亭酒，夜雨初煎石鼎茶。", "久矣樵漁懷此志，吹簫閑看碧桃花。"]'),
('c92e3552-458f-4130-a7ef-3c91bb4137d0','武夷','石建見','宋','宋诗','song-poetry','','[]','拂散征塵曳素袍，小鞍乘興過林臯。',64,'全唐诗/poet.song.253000.json','["拂散征塵曳素袍，小鞍乘興過林臯。", "溪山九曲雲烟合，宮闕萬年星斗高。", "天柱插空留鶴駕，仙船橫石待鯨濤。", "玉笙吹徹金鷄叫，落盡巖前幾樹桃。"]'),
('115d0b35-c072-4109-8ea4-95da5aead21b','集峰名','石建見','宋','宋诗','song-poetry','','[]','大王高住碧雲間，玉女風鬟相對看。',64,'全唐诗/poet.song.253000.json','["大王高住碧雲間，玉女風鬟相對看。", "畫鶴有年游瀚海，釣魚何日起波瀾。", "工添一線仙機就，酒盡三杯茶竈乾。", "醉聽鼓樓聲已遠，幔亭環珮響珊珊。"]'),
('dfdf8e3c-98b9-4926-8b3d-16021a55e1b6','武夷','楊希古','宋','宋诗','song-poetry','','[]','萬壑千巖疊翠微，幔亭紅日浸漣漪。',32,'全唐诗/poet.song.253000.json','["萬壑千巖疊翠微，幔亭紅日浸漣漪。", "紫陽去後無消息，留得溪山九曲詩。"]'),
('ce2e28ad-6c82-42cd-9618-5b0b37b04b26','寄題武夷','陳子浩','宋','宋诗','song-poetry','','[]','武夷山水稱奇絕，歷歷仙源路可通。',64,'全唐诗/poet.song.253000.json','["武夷山水稱奇絕，歷歷仙源路可通。", "人古道尊精舍在，曾玄世隔幔亭空。", "萬年宮接青冥上，九曲溪流碧嶂中。", "幾欲相期游汗漫，披圖陡覺馭天風。"]'),
('3a6446c9-a8db-47f1-94e9-15ab30bbba47','題武夷','馬合麻','宋','宋诗','song-poetry','','[]','石鼓溪邊渡，門前一葉舟。',48,'全唐诗/poet.song.253000.json','["石鼓溪邊渡，門前一葉舟。", "雨滋千壑翠，風動萬巖秋。", "仙去雲常在，山空水自流。", "九天煩紫詔，借我此中遊。"]'),
('2fc7a73e-0e44-46bd-8499-ef37f633b8fb','寄題武夷','聶鐵峰','宋','宋诗','song-poetry','','[]','秋香扶我過仙家，□大眠雲石逕斜。',64,'全唐诗/poet.song.253000.json','["秋香扶我過仙家，□大眠雲石逕斜。", "九曲溪山閑日月，萬年宮殿老烟霞。", "吟筇尚带瑶階蘚，渡舫曾撐翠竹沙。", "迴首雲深何處覓，洞簫吹落碧巖花。"]'),
('36417052-b4c4-4530-963a-dcc68cd0fce4','題武夷','趙宗吉','宋','宋诗','song-poetry','','[]','天風吹盡蔽空雲，疊嶂層巒勢吐吞。',64,'全唐诗/poet.song.253000.json','["天風吹盡蔽空雲，疊嶂層巒勢吐吞。", "鐵笛聲沉人換世，幔亭宴罷竹生孫。", "崑閬境界烟霞窟，洙泗源流道義門。", "分治優游公事了，溪山佳處共清尊。"]'),
('03c2efeb-d882-4d10-8c25-c3f54ba38138','題武夷','趙承禧','宋','宋诗','song-poetry','','[]','群玉山前隠道園，松聲鶴唳隔溪聞。',32,'全唐诗/poet.song.253000.json','["群玉山前隠道園，松聲鶴唳隔溪聞。", "山靈似識遊人意，要看青林映白雲。"]'),
('05388273-decd-4190-b485-a1765dccf2d7','題武夷','李公平','宋','宋诗','song-poetry','','[]','溪頭借得釣魚船，又向山中覓洞天。',32,'全唐诗/poet.song.253000.json','["溪頭借得釣魚船，又向山中覓洞天。", "聞道巖前有遺蛻，神仙飛去二千年。"]'),
('273e5da5-5b47-4f40-b91a-a2ab069f4b1b','山中','丁西湖','宋','宋诗','song-poetry','','[]','金門待漏馬嘶寒，月落宮牆未曉天。',32,'全唐诗/poet.song.253000.json','["金門待漏馬嘶寒，月落宮牆未曉天。", "爭子莫教容易掃，恐傷一片惜花心。"]'),
('51a67644-f139-4d09-b152-5156beb7fe89','送吳菊潭遊越','丁西湖','宋','宋诗','song-poetry','','[]','春江柳色新，別酒易成醺。',48,'全唐诗/poet.song.253000.json','["春江柳色新，別酒易成醺。", "自厭久爲客，難堪又送君。", "溪晴沙度鶴，地暖水生兮。", "若到蘭亭上，應須弔右軍。"]'),
('fbb450cc-42d3-4c41-af0d-ebef27146023','龍游石壁','釋本粹','宋','宋诗','song-poetry','','[]','巉巖古徑幽，疏林閣秋雨。',24,'全唐诗/poet.song.253000.json','["巉巖古徑幽，疏林閣秋雨。", "小立蘚花寒，江清魚可數。"]'),
('9d6a0e62-e4e1-480b-96a2-95ae34c6cd29','永青溪石壁','無名氏','宋','宋诗','song-poetry','','[]','青溪宜晚日，曲處千丈晦。',96,'全唐诗/poet.song.253000.json','["青溪宜晚日，曲處千丈晦。", "天開蒼石屏，影落西村外。", "虛無元氣立，明滅河漢對。", "人行崢嶸下，鳥急浩蕩內。", "向來千萬峰，瑣細等蓬塊。", "老夫倚杖久，三嘆造物大。", "惜哉太史公，意短遺此快。", "更欲訪野人，窮探視其背。"]'),
('a43af648-cba4-4121-9a54-194c5231dfba','西陽嶺','葉維瞻','宋','宋诗','song-poetry','','[]','杜鵑啼處花成血，燕子忙時麥未胎。',32,'全唐诗/poet.song.253000.json','["杜鵑啼處花成血，燕子忙時麥未胎。", "舉世但知春易老，不知春老幾人來。"]'),
('7726ca7a-b780-48ee-9705-6f408d910855','遊武夷山洞天','孟晉','宋','宋诗','song-poetry','','[]','昔聞仙子宅，今幸過琳宮。',48,'全唐诗/poet.song.253000.json','["昔聞仙子宅，今幸過琳宮。", "溪曲三三水，山環六六峰。", "翠雲升送雨，白鶴舞凌風。", "好景遊歸晚，簫聲縹緲中。"]'),
('3da663b7-4bee-470a-82de-75d54916c91b','大滌洞天留題','何洞清','宋','宋诗','song-poetry','','[]','落魄人間成謾老，足繭胼胝要聞道。',192,'全唐诗/poet.song.253000.json','["落魄人間成謾老，足繭胼胝要聞道。", "掉頭不向聲利場，飄飄逈出風塵表。", "嗟嗟事事不愜懷，却喜因緣飽幽討。", "登太華兮濯滄浪，雲夢湫隘魯邾小。", "既不責人求諸己，自信玄門窮妙理。", "虛室生白悟名言，坐見吉祥來止止。", "箇中端的合乾坤，幾道致柔若諸水。", "要須萬里可參同，坐斷孤峰空棄鄙。", "潜山霍山大滌山，天柱插雲人莫企。", "癡狂取笑誰氏子，不以生生而死死。", "自知蹤跡類閭丘，君家可是留前軌。", "枯藤擬待掛休休，莫使風雷暗催徙。"]'),
('7239d222-c590-4586-ae5e-29055de1fcb3','大滌洞','何炳然','宋','宋诗','song-poetry','','[]','杳默閟虛曠，森爽離人寰。',24,'全唐诗/poet.song.253000.json','["杳默閟虛曠，森爽離人寰。", "玉室非所詣，回首烟中山。"]'),
('239afc92-f8bb-43b2-bc76-2db73567029a','天柱峰','何炳然','宋','宋诗','song-poetry','','[]','終古鬰岧嶢，東南此撐柱。',24,'全唐诗/poet.song.253000.json','["終古鬰岧嶢，東南此撐柱。", "當時若更高，恐礙日月路。"]'),
('35a2f7a2-83b6-433d-b27b-f0d5e9ed81a6','雲根峰','何炳然','宋','宋诗','song-poetry','','[]','十洲仙子騎龍鶴，路闊雲深貪舞躍。',64,'全唐诗/poet.song.253000.json','["十洲仙子騎龍鶴，路闊雲深貪舞躍。", "不知縹緲已無心，一朵飛來墜山脚。", "幾度天風吹不開，數回山雨誤飄來。", "直恐老龍招得去，千頃萬頃遊蓬萊。"]'),
('684f5849-2051-4d8b-b442-365ce01ef670','千年古石','何炳然','宋','宋诗','song-poetry','','[]','怪底黄石公，乃是赤松子。',24,'全唐诗/poet.song.253000.json','["怪底黄石公，乃是赤松子。", "蒲柳不自强，一見顙應泚。"]'),
('8daeec27-6de8-42aa-8b53-cea1d85e1193','龍洞','何炳然','宋','宋诗','song-poetry','','[]','胡髯抱嵌巖，白雲擁萬里。',24,'全唐诗/poet.song.253000.json','["胡髯抱嵌巖，白雲擁萬里。", "若弄華陽珠，我欲割左耳。"]'),
('b4bbc9f1-2b94-4bd4-9469-e5c1b2ac09ac','右鳳洞','何炳然','宋','宋诗','song-poetry','','[]','上作千仞翔，下作千巖棲。',24,'全唐诗/poet.song.253000.json','["上作千仞翔，下作千巖棲。", "簫韶在何處，蒼梧雲氣迷。"]'),
('8192333e-bc8a-4660-a8be-d0b11b6c01e1','大滌洞','呂某','宋','宋诗','song-poetry','','[]','古檜沉沉萬籟微，祥光縈繞鎖瑶扉。',32,'全唐诗/poet.song.253000.json','["古檜沉沉萬籟微，祥光縈繞鎖瑶扉。", "石間怪底泉涓滴，却是老龍行雨歸。"]'),
('a94f139b-330a-4530-8dbe-f2fd17f31b26','大滌洞天留題','李暘夫','宋','宋诗','song-poetry','','[]','誰挽天河瀉翠崖，一條飛瀑界烟霞。',32,'全唐诗/poet.song.253000.json','["誰挽天河瀉翠崖，一條飛瀑界烟霞。", "只愁風力半天勁，吹向人間作雪花。"]'),
('9b6a805f-5348-4d3b-ac13-fc1ad74a7938','大滌洞天留題','蘇遹','宋','宋诗','song-poetry','','[]','生平未識洞霄宮，幸與東君訪赤松。',64,'全唐诗/poet.song.253000.json','["生平未識洞霄宮，幸與東君訪赤松。", "丹井千年猶好在，青山九鎖不曾封。", "入門快臯雲根石，矯首遐觀天柱峰。", "凡骨變成仙骨了，此軀何患弗爲龍。"]'),
('f33cde11-38be-43f5-baea-5b1cf36920a6','題大滌洞天留題','胡𧗸','宋','宋诗','song-poetry','','[]','拔脚紅塵到蕊宮，眼前物物是詩筒。',64,'全唐诗/poet.song.253000.json','["拔脚紅塵到蕊宮，眼前物物是詩筒。", "雲關左右轉九鎖，天柱西南邊一峰。", "正喜齋厨供筍蕨，更尋藥圃覓芝芎。", "飛仙何在應憐我，指出靈丹紺箬叢。"]'),
('bc730fb0-d844-46c3-bb2e-e6ab9cebe1f9','大滌洞天留題','陳德翁','宋','宋诗','song-poetry','','[]','天柱峰頭疊紫烟，遥看萬玉聳相連。',64,'全唐诗/poet.song.253000.json','["天柱峰頭疊紫烟，遥看萬玉聳相連。", "雲深九鎖疑無路，翠豁一區我有天。", "靈氣襲人噓石潤，嗔雷飛雨響山泉。", "倏然不類人間世，今日自驚平地仙。"]'),
('926faf30-154c-4160-b6ae-189ce147ea8f','大滌洞天留題','薛炎','宋','宋诗','song-poetry','','[]','我有愛山癖，苦無買山錢。',48,'全唐诗/poet.song.253000.json','["我有愛山癖，苦無買山錢。", "平生天柱夢，今日地行仙。", "九鎖何曾礙，三椽若有緣。", "鵝溪三百幅，喚起老龍眠。"]'),
('db3197e6-ac1e-4652-85bf-73086873ca58','大滌洞天留題','趙觀復','宋','宋诗','song-poetry','','[]','不作翠蛟詩，獨賦上池水。',204,'全唐诗/poet.song.253000.json','["不作翠蛟詩，獨賦上池水。", "鑿開自淵源，鑒觀湛然止。", "豈惟白心事，且以明□底。", "松風生晚清，暑夜看晨起。", "二瓢餉內熱，透徹□若髓。", "匯流接山腰，放溜達澗尾。", "當其保持盈，一丈若縱侈。", "□輪爭道來，三板擁清泚。", "飛簾從天下，衆吼亂石裏。", "濺珠忽尋丈，灑面寸尺咫。", "恭惟坡仙翁，學道老不已。", "每言杭有緣，來往即鄉里。", "自題九鎖篇，景物相刃靡。", "親聞衆妙玄，金丹起人死。", "新名揭亭戶，空翠冷欄几。", "易求水之形，難造水之理。", "與君論源流，或者未劇此。"]'),
('b88fb444-7c3c-4f37-a0bb-75bb0e3588af','大滌洞天留題  其一','呂奫','宋','宋诗','song-poetry','','[]','泠然風御遠光塵，軒豁嵯峨插碧雲。',32,'全唐诗/poet.song.253000.json','["泠然風御遠光塵，軒豁嵯峨插碧雲。", "空洞元來無一物，惟留飛鼠自成群。"]'),
('b954dc49-77f7-4098-a853-3b6294726a20','大滌洞天留題  其二','呂奫','宋','宋诗','song-poetry','','[]','九鎖瓊宮萃列仙，飄然別是一壺天。',64,'全唐诗/poet.song.253000.json','["九鎖瓊宮萃列仙，飄然別是一壺天。", "時時雲氣生巖洞，日日松聲助澗泉。", "山茗已堪回短夢，金丹要可得長年。", "是中着語真難事，今古舂容幾大篇。"]'),
('e2537970-4b74-44a2-80cb-5293278c9a91','翠蛟  其一','呂奫','宋','宋诗','song-poetry','','[]','遠岫參橫滃白雲，一聲雷震出天門。',32,'全唐诗/poet.song.253000.json','["遠岫參橫滃白雲，一聲雷震出天門。", "恍然身在龍頭上，笑引莊生五石樽。"]'),
('d38b9378-40b9-4fa5-a289-fa37b2d6fd25','翠蛟  其二','呂奫','宋','宋诗','song-poetry','','[]','我讀坡詩醉眼開，翠蛟騎取借風雷。',32,'全唐诗/poet.song.253000.json','["我讀坡詩醉眼開，翠蛟騎取借風雷。", "直教大地霑霖雨，變作清凉不快哉。"]'),
('73b0d2cd-f7eb-41cd-aae7-7b17fdcf4933','大滌洞天留題  其一','陳唐生','宋','宋诗','song-poetry','','[]','天下有力可移山，底事秦鞭不作難。',32,'全唐诗/poet.song.253000.json','["天下有力可移山，底事秦鞭不作難。", "我却笑渠精衛石，一生愁絕海漫漫。"]'),
('df08ce9c-edbc-482a-9bde-7e5eadac1adc','大滌洞天留題  其二','陳唐生','宋','宋诗','song-poetry','','[]','肩臂成漥古石存，雨乾不受野苔痕。',32,'全唐诗/poet.song.253000.json','["肩臂成漥古石存，雨乾不受野苔痕。", "道人未用誇神力，自是山王不動尊。"]'),
('65f2f6b4-5f22-403b-a23a-8a43dad64b5c','大滌洞天留題','陳垵留','宋','宋诗','song-poetry','','[]','支徑縈紆路似窮，疑非瓊館洞霄宮。',64,'全唐诗/poet.song.253000.json','["支徑縈紆路似窮，疑非瓊館洞霄宮。", "雖煩綠野諸公領，誰到青山九鎖中。", "栝隠又深千嶂月，笋將猶欠一枝筇。", "道人欲識巖棲處，因鶴東來問漫翁。"]'),
('f510a5d5-616f-4573-8cf5-dde4c2703c2a','大滌洞天留題','朴子文','宋','宋诗','song-poetry','','[]','不得入壺中，不知有洞天。',240,'全唐诗/poet.song.253000.json','["不得入壺中，不知有洞天。", "未許涉弱水，蓬瀛名空傳。", "洞霄古真境，九鎖開其先。", "靈殿拱嘉樹，奇巖漱飛泉。", "朝氣夜沆瀣，夕嵐蟠霏烟。", "自從漢晉間，隠迹叢真仙。", "所以鎮琳宮，距今千百年。", "我來尋勝游，聊以息塵緣。", "誰意得高人，凡百爲之前。", "捫蘿扣大滌，曳裾登來賢。", "宮殿本邃靚，亦許奉周旋。", "倦游恬小憩，借我幽榻眠。", "覺我黄粱夢，枕上破纏綿。", "醉我真一酒，春臺熙熙然。", "勿謂房櫳深，入室乃淵淵。", "勿謂欄檻小，棲幽即㛹娟。", "苟有一拳石，天巧意已全。", "苟有一樹木，風月亦足延。", "况是石與木，森羅呈萬妍。", "有仙山即靈，君當悟真筌。"]'),
('2f47fb30-4e9c-49cc-bfb2-86ee478e0cd5','大滌洞天留題','龍友','宋','宋诗','song-poetry','','[]','每見杭人說洞霄，恨無雙翼興飄飄。',64,'全唐诗/poet.song.253000.json','["每見杭人說洞霄，恨無雙翼興飄飄。", "恍觀石勢如蟠獸，靜聽泉聲若春韶。", "既想洞天多窈妙，更知仙境絕塵囂。", "官遊到此勞人甚，準擬時來酌一瓢。"]'),
('704aeda4-d3f4-4313-a174-9984b3142486','大滌洞天留題','高攀','宋','宋诗','song-poetry','','[]','洞府幽深幸許探，危峰削玉與天參。',64,'全唐诗/poet.song.253000.json','["洞府幽深幸許探，危峰削玉與天參。", "凡心洗滌今無妄，仙迹微茫要指南。", "俯澗長吟舒逸興，倚巖小酌助清談。", "抱琴携子盟泉石，終老山阿我亦甘。"]'),
('cc44340d-e260-4d89-8bc5-7a582d1ca275','大滌洞天留題  其一','蘇瀛','宋','宋诗','song-poetry','','[]','天作名山滿世間，洞霄畢竟出塵寰。',64,'全唐诗/poet.song.253000.json','["天作名山滿世間，洞霄畢竟出塵寰。", "達翁不問長生藥，高興惟通九鎖關。", "願學坡仙遊赤壁，肯如謝老陟東山。", "羽人能重來賢裔，杖屨相陪一日閑。"]'),
('f31c1540-00a3-471f-80c3-fd8718cd04d9','大滌洞天留題  其二','蘇瀛','宋','宋诗','song-poetry','','[]','冉冉雲根手可採，天然泉石故相參。',64,'全唐诗/poet.song.253000.json','["冉冉雲根手可採，天然泉石故相參。", "仙家永日元無夜，虛室冷風每自南。", "賸辦芒鞋尋隠躅，更從羽士縱玄談。", "真空不在多言論，學道何如啖蔗甘。"]'),
('dd52e540-3c55-4ae4-bf4a-c9c3520283c7','大滌洞天留題','霍正夫','宋','宋诗','song-poetry','','[]','長虹舞澗石磷磷，勝踐還憐雨送春。',64,'全唐诗/poet.song.253000.json','["長虹舞澗石磷磷，勝踐還憐雨送春。", "雲木千章森翠幄，洞天九鎖絕紅塵。", "丹藏仙谷生奇箬，香到龍祠澤旱民。", "山有舊盟來更好，齋心恭對玉晨真。"]'),
('f3dca1e4-d153-4fc9-a1ff-246355bcb94c','大滌洞天留題','彭老','宋','宋诗','song-poetry','','[]','九峰嵯峨擁金碧，來游知費幾兩屐。',64,'全唐诗/poet.song.253000.json','["九峰嵯峨擁金碧，來游知費幾兩屐。", "石虹妥玉飛雪寒，蘿屏削紫春雲濕。", "仙蹤誰言隔弱水，時見石盤敲玉子。", "千年箬底遺丹紅，桃花洞口吹天風。"]'),
('b580eafb-c290-4638-8f02-23a10e75f832','大滌洞天留題','李閌先','宋','宋诗','song-poetry','','[]','福地彎環古洞霄，古壇雲冷寶□飄。',64,'全唐诗/poet.song.253000.json','["福地彎環古洞霄，古壇雲冷寶□飄。", "無蛟可斷泉猶怒，有虎難馴霧未消。", "一柱孤擎天妥帖，重巒九掩路迢遥。", "自憐骨相多奇蹇，只合山中種藥苗。"]'),
('db98472f-e289-476a-a220-675596474407','大滌洞天留題','果老','宋','宋诗','song-poetry','','[]','烟霞溟濛峰九轉，淀潑屏風倚天半。',64,'全唐诗/poet.song.253000.json','["烟霞溟濛峰九轉，淀潑屏風倚天半。", "石龍背冷泉聲哀，萬疊靈鼉飛素練。", "江山登臨夙所願，何當騎麟醉遊徧。", "仙人一去不可見，洞天春晚花流遠。"]'),
('fb213439-4943-4090-b8be-a97b4bdcfca6','大滌洞天留題','邵喆','宋','宋诗','song-poetry','','[]','抖擻京塵只素衣，脫銜困馬喜逶迤。',64,'全唐诗/poet.song.253000.json','["抖擻京塵只素衣，脫銜困馬喜逶迤。", "雲根來擬啟金室，天柱高攀得玉芝。", "龍躍清泉知客定，丹藏紺箬與誰期。", "晴霞闊引棲真洞，不管落花流水知。"]'),
('0f63d341-45b6-4d8f-929d-281d7046d392','大滌洞天留題','湖杓','宋','宋诗','song-poetry','','[]','蔓藤森木閲千齡，斷壁嵌崖翠削成。',64,'全唐诗/poet.song.253000.json','["蔓藤森木閲千齡，斷壁嵌崖翠削成。", "安得抱琴來此宿，夜深隨意寫溪聲。", "平生晝裏看丘壑，便欲扶筇快賞心。", "真箇溪山在亭外，老坡千古共知音。"]'),
('34d52c9c-7018-4a27-98d5-19365e95fa50','大滌洞天留題','徐初學','宋','宋诗','song-poetry','','[]','化工欲使聚群靈，上下鑿開洞府深。',64,'全唐诗/poet.song.253000.json','["化工欲使聚群靈，上下鑿開洞府深。", "雲放碧峰藍掩映，溜迴小澗雲浮沉。", "至神莫測圓湫水，澤潤能成大旱霖。", "天下洞霄真第一，到茲寧不效蟲吟。"]'),
('09978379-6136-4341-a5a6-37185af6bbe7','大滌洞天留題','樊處恭','宋','宋诗','song-poetry','','[]','持杯睥睨不逾時，一派寒聲落翠微。',64,'全唐诗/poet.song.253000.json','["持杯睥睨不逾時，一派寒聲落翠微。", "蛟室倒翻珠亂躍，瓊田耕破玉紛飛。", "壯懷摇動頻扶檻，濺沫飄零欲濕衣。", "繞磵更須林蔭密，呼尊重約扣巖扉。"]'),
('7da6d1dd-3c69-4ad3-9b2d-ef8d81c79c99','大滌洞天留題','潘伯虎','宋','宋诗','song-poetry','','[]','平生聞有洞霄奇，三載京華夢裏知。',64,'全唐诗/poet.song.253000.json','["平生聞有洞霄奇，三載京華夢裏知。", "非藉賢侯爲引領，那因小子獲追隨。", "危坡滑滑憑輿上，古洞陰陰秉燭窺。", "萬壑千巖遊未徧，又催歸騎向東籬。"]'),
('3ede117c-b98a-45de-b171-3b2141eaf195','大滌洞天留題','張遜','宋','宋诗','song-poetry','','[]','浮雲飛動渾非真，飽看山水浴精神。',64,'全唐诗/poet.song.253000.json','["浮雲飛動渾非真，飽看山水浴精神。", "行空未駕青田鶴，持杯欲餉採薇人。", "醉中往往紅生面，是是非非都不見。", "只言學詩與學仙，此道如今絕如線。"]'),
('9a2d402b-5214-494f-8b77-2da72da15801','大滌洞天留題','何林','宋','宋诗','song-poetry','','[]','仙窟訪龍君，開奩炷室薰。',48,'全唐诗/poet.song.253000.json','["仙窟訪龍君，開奩炷室薰。", "洞中天地別，物外聖凡分。", "古井流金水，空山鎖白雲。", "步虛聲杳杳，疑向碧霄聞。"]'),
('6542fe7c-16ff-48ce-94a4-623569e09c06','大滌洞天留題','朱堂','宋','宋诗','song-poetry','','[]','地勝群峰秀，山高宿霧昏。',48,'全唐诗/poet.song.253000.json','["地勝群峰秀，山高宿霧昏。", "靈宮從昔著，仙迹至今存。", "嵌洞窺天巧，飛泉挾石奔。", "塵緣何日了，小築占雲根。"]'),
('a502e2fb-99ef-4c8d-a189-7393cf5d86e6','大滌洞','葉漙','宋','宋诗','song-poetry','','[]','青山曲折鎖瑶扉，俗客頻勞攬芝衣。',32,'全唐诗/poet.song.253000.json','["青山曲折鎖瑶扉，俗客頻勞攬芝衣。", "更看臨流輕指顧，翠蛟化作玉龍飛。"]'),
('c59cc50b-2208-4041-bf64-a85a5428ce1f','大滌洞','黄子安','宋','宋诗','song-poetry','','[]','洞天三十六，此地屬苕南。',48,'全唐诗/poet.song.253000.json','["洞天三十六，此地屬苕南。", "古物藏松石，清流勝菊潭。", "擎空山骨瘦，懸乳石毛毿。", "飛舄王喬事，行看日接三。"]'),
('f205e7ef-0f79-4280-9a2b-f0a7ca3eba71','大滌洞天留題','閻良臣','宋','宋诗','song-poetry','','[]','慈泉地闢與天開，屈曲飛鳴聲隠雷。',32,'全唐诗/poet.song.253000.json','["慈泉地闢與天開，屈曲飛鳴聲隠雷。", "若使翠華臨此地，飛來未必羨佳哉。"]'),
('67ffbb00-ac66-4719-aef1-7e841c8acc6a','菁江','林人隠','宋','宋诗','song-poetry','','[]','浮跡東西浙，大江長短亭。',48,'全唐诗/poet.song.253000.json','["浮跡東西浙，大江長短亭。", "潮來遠水白，雨過亂峰青。", "春夜夢無定，天寒酒易醒。", "回橈下江渚，杜若滿沙汀。"]'),
('78ce1d32-fe7b-4a1e-a6bf-51e4c093a660','湖州溪舍','林人隠','宋','宋诗','song-poetry','','[]','茅舍枕寒溪，出門煙翠齊。',48,'全唐诗/poet.song.253000.json','["茅舍枕寒溪，出門煙翠齊。", "曉林過栗鼠，秋草伏莎雞。", "村酒大書字，山蔬小作畦。", "落然人寂歷，野迥白雲低。"]'),
('ae14bac6-6c39-418f-bef6-d2b5ba30a779','湖上','徐一山','宋','宋诗','song-poetry','','[]','堤上柳依依，柳風吹絮飛。',48,'全唐诗/poet.song.253000.json','["堤上柳依依，柳風吹絮飛。", "帝京三月盡，客子幾時歸。", "山近鳥棲早，花殘人買稀。", "儘多湖水在，誰與浣塵衣。"]'),
('c23980bc-dcf9-45d5-b9cb-33860e78cf49','偶成','徐一山','宋','宋诗','song-poetry','','[]','一見青山便是家，苦無人可共烟霞。',32,'全唐诗/poet.song.253000.json','["一見青山便是家，苦無人可共烟霞。", "枯腸不受春風膩，莫汲花邊水煮茶。"]'),
('81a6cd22-79ab-4db2-84d5-3883e053bec9','小溪','李介山','宋','宋诗','song-poetry','','[]','東風滿眼柳花飛，信步扶藜過小溪。',64,'全唐诗/poet.song.253000.json','["東風滿眼柳花飛，信步扶藜過小溪。", "淮甸淒凉春事少，楚天空闊暮雲低。", "江山有意憐孤客，桃李無心戀故蹊。", "縱使有家歸未得，數聲蜀魄爲誰啼。"]'),
('7fc6079b-42ed-4828-8207-689de1ed06ef','梅雨潭','李介山','宋','宋诗','song-poetry','','[]','靈源分左界，千仞落飛泉。',48,'全唐诗/poet.song.253000.json','["靈源分左界，千仞落飛泉。", "散作一空雨，長如四月天。", "挂巖寒練直，濺席水珠圓。", "湫石龍應在，巖扉浮翠烟。"]'),
('3b5f7727-3166-46dc-ba1e-83ac0adb6ce9','石門貪泉','王竹臞','宋','宋诗','song-poetry','','[]','天闊不知山脚遠，潮平微見晚烟橫。',32,'全唐诗/poet.song.253000.json','["天闊不知山脚遠，潮平微見晚烟橫。", "石門無數征帆去，惟有漁舟箇箇輕。"]'),
('83d0e375-7b71-49ae-8332-a9fdefbea243','清音','王威','宋','宋诗','song-poetry','','[]','白雲深處有清音，上接祥光古木森。',32,'全唐诗/poet.song.253000.json','["白雲深處有清音，上接祥光古木森。", "不但濯纓兼濯足，直須一洗利名心。"]'),
('33596a6e-fa3f-4cbf-af35-a7db3bd017ca','天柱峰','□韞','宋','宋诗','song-poetry','','[]','拄天屹嶪斷鼇根，卧草蒙茸伏虎痕。',32,'全唐诗/poet.song.253000.json','["拄天屹嶪斷鼇根，卧草蒙茸伏虎痕。", "想見山中明月夜，有人長嘯抱崑崙。"]'),
('66689bdb-5bd4-439f-b219-77d640f95fa9','翠蛟峰','□韞','宋','宋诗','song-poetry','','[]','蒼松翠石束寒流，飛下長身白玉虬。',32,'全唐诗/poet.song.253000.json','["蒼松翠石束寒流，飛下長身白玉虬。", "吐出英雲□□□，□□□□□□□。"]'),
('0aaa17ef-f090-4748-bfe9-5621d8108af3','清音泉','□韞','宋','宋诗','song-poetry','','[]','山出涓寒一道泉，暗聲落澗玉錚然。',32,'全唐诗/poet.song.253000.json','["山出涓寒一道泉，暗聲落澗玉錚然。", "轆轤引上泥丸頂，便是人間赤脚仙。"]'),
('71f25b97-652e-4dca-a263-b631a688f805','石室','□韞','宋','宋诗','song-poetry','','[]','竹几蒲團石室中，細書抱朴校參同。',32,'全唐诗/poet.song.253000.json','["竹几蒲團石室中，細書抱朴校參同。", "寄聲碧眼朱高士，何必携琴下閬風。"]'),
('2fdda176-a024-452d-98e2-d6f2608325b8','天柱峰','吳某','宋','宋诗','song-poetry','','[]','孤峰斗絕矗雲浮，俯視群山若蟻丘。',32,'全唐诗/poet.song.253000.json','["孤峰斗絕矗雲浮，俯視群山若蟻丘。", "倚住東南天一角，笑它芑國謾多憂。"]'),
('5e4307b3-1d4a-4b47-a62b-58ece1cf2beb','雲根石','吳某','宋','宋诗','song-poetry','','[]','白雲觸石起油然，倏忽從龍遍九天。',32,'全唐诗/poet.song.253000.json','["白雲觸石起油然，倏忽從龍遍九天。", "多謝豐隆留一葉，至今遺跡在巖前。"]'),
('e833e5bf-a825-435d-b0af-c61d7a0b62ce','翠蛟亭','吳某','宋','宋诗','song-poetry','','[]','蒼崖决水下雷霆，掉尾蜿蜒不暫停。',32,'全唐诗/poet.song.253000.json','["蒼崖决水下雷霆，掉尾蜿蜒不暫停。", "榜作翠蛟猶未稱，不如喚作舞蛟亭。"]'),
('d34475df-9d9a-496c-9f20-e52c45cf436f','天遊峰','魏麟一','宋','宋诗','song-poetry','','[]','冰海濯足來天遊，萬里雲氣隨青牛。',294,'全唐诗/poet.song.253000.json','["冰海濯足來天遊，萬里雲氣隨青牛。", "盤車沾沾星斗濕，手捲風雨藏金甌。", "玲瓏珊瑚樹，記得西王母挂玉鈎。", "幾時化作小玉船，一葉蕩蕩隨天流。", "滿載清霜落九州，與人生白頭。", "我歌黄鵠歌，南斗盤其南兮，河嶽擁其後。", "海岱明東方，黄河之源。", "江水之宗，昆侖雪山在其右，巍然天柱當中居。", "斯文光氣長，萬丈塞太虛。", "不信九天上，仙人不讀書。", "如今白玉樓，聞道紫陽老子在其上，手摶日月安星辰，爲玉皇作典謨。", "又聞鬰羅蕭臺上，紫陽奏可决取河漢之水，千古萬古洗濯下土愚民愚。", "男子學麟鳳，女子學王雎，萬萬萬世尊唐虞。", "我乃太姥之曾孫，故聞天上語。", "來此樂飲，人間愁一粟無，只有天地吾非吾。", "鼓髪長嘯秋月白，照見大千世界都置在我太姥清水之玉壺。"]'),
('fa5fa232-48cd-48ec-a2d5-1e3ddf9bce7f','透碧霄','朱叔大','宋','宋诗','song-poetry','','[]','初疑石壁無行路，已轉方知透碧霄。',64,'全唐诗/poet.song.253000.json','["初疑石壁無行路，已轉方知透碧霄。", "茶鼎快烹泉竇月，酒杯低吸海門潮。", "乾坤浩蕩鄉心遠，歲月蒼忙客鬢凋。", "欲約洪崖同一笑，滿山竹□自蕭蕭。"]'),
('5b2e1b77-19e2-4175-b4ad-085d5f651fc7','大滌洞天留題  其一','朱希言','宋','宋诗','song-poetry','','[]','君看萬事等虛舟，一任星星兩鬢秋。',32,'全唐诗/poet.song.253000.json','["君看萬事等虛舟，一任星星兩鬢秋。", "惟有林泉久成癖，每逢佳處爲遲留。"]'),
('8ffea1a2-ae1c-44dc-aecf-161fcf5f5058','大滌洞天留題  其二','朱希言','宋','宋诗','song-poetry','','[]','松檜參天幾萬株，清陰夾道暑全無。',32,'全唐诗/poet.song.253000.json','["松檜參天幾萬株，清陰夾道暑全無。", "暗泉深洞尤難寫，擬借君詩作畫圖。"]'),
('bca445b6-d115-48b1-9a2e-ebdae4a5a25e','曉岸','易平湖','宋','宋诗','song-poetry','','[]','扁舟曉泊畫橋西，風滿蓬窗水拍堤。',32,'全唐诗/poet.song.253000.json','["扁舟曉泊畫橋西，風滿蓬窗水拍堤。", "落舟半山人未起，萬蛙聲裏子規啼。"]'),
('816cad93-d275-43a2-afb3-821d61713ccc','春日山中','田耕月','宋','宋诗','song-poetry','','[]','山靜鶑啼春事深，意行到處若爲情。',32,'全唐诗/poet.song.253000.json','["山靜鶑啼春事深，意行到處若爲情。", "休言柳絮全輕薄，半是東風不老成。"]'),
('eb987e3f-58ac-40c9-a4d1-adc54fef9c76','暖翠','安𪊲','宋','宋诗','song-poetry','','[]','暖翠浮嵐萬壑春，桃花流水碧沄沄。',64,'全唐诗/poet.song.253000.json','["暖翠浮嵐萬壑春，桃花流水碧沄沄。", "同亭祠下生青草，天柱峰頭空白雲。", "雨後石林群鷺宿，月中山樹兩猿分。", "幾時結屋清溪上，鶴氅筇枝學隠君。"]'),
('e8595475-04d3-4c33-9576-0a77adfa9680','三姑石','安𪊲','宋','宋诗','song-poetry','','[]','霧鬢烟鬟彷彿梳，老翁指點說三姑。',32,'全唐诗/poet.song.253000.json','["霧鬢烟鬟彷彿梳，老翁指點說三姑。", "娉婷不嫁非無意，誰是人間大丈夫。"]'),
('9a381c84-4412-41dd-b2d8-28e2f8cfbd7a','春日嶺南','孫正平','宋','宋诗','song-poetry','','[]','窗前修竹靄如雲，巧語春禽只聽聞。',32,'全唐诗/poet.song.253000.json','["窗前修竹靄如雲，巧語春禽只聽聞。", "睡起蒲團趺坐穩，惟將茗椀對爐熏。"]'),
('8eb9bace-1337-4c7a-8e4a-632791d49707','菊巖','葉師文','宋','宋诗','song-poetry','','[]','東風紅紫過千千，獨着黄衣不敢先。',32,'全唐诗/poet.song.253000.json','["東風紅紫過千千，獨着黄衣不敢先。", "萬仞峰頭今一萼，別無花木可秋天。"]'),
('be2fd440-c545-4448-89bc-52beae2a93ba','題蛻龍洞 白茆洞 其一','無名氏','宋','宋诗','song-poetry','','[]','西南十里嶺之巔，靈冢巋然洞隠仙。',64,'全唐诗/poet.song.253000.json','["西南十里嶺之巔，靈冢巋然洞隠仙。", "門闢神扃低視井，柱生一竅仰瞻天。", "甕中春酒今朝釀，洞內仙賓昔日賢。", "路阻山高難可到，茆君職守幾千年。"]'),
('d31ddb34-c3bc-4ec7-97d8-e5e064f1f7b2','題蛻龍洞 白茆洞 其二','無名氏','宋','宋诗','song-poetry','','[]','白茆職此不知年，井竇迴環會飲仙。',32,'全唐诗/poet.song.253000.json','["白茆職此不知年，井竇迴環會飲仙。", "遺跡空存春酒甕，通天靈竅尚依然。"]'),
('c396880c-f207-4001-b071-818f47db6af1','題蛻龍洞 伏虎巖','無名氏','宋','宋诗','song-poetry','','[]','空巖深峻可棲真，猛虎溫馴異類親。',32,'全唐诗/poet.song.253000.json','["空巖深峻可棲真，猛虎溫馴異類親。", "正節天師時憩此，逍遥忘返詠章新。"]'),
('f271d250-742d-4301-9f26-366bda2658ad','題蛻龍洞 鳴鳳洞','無名氏','宋','宋诗','song-poetry','','[]','鳴鳳來儀瑞翠巔，洞中阻隘石門全。',32,'全唐诗/poet.song.253000.json','["鳴鳳來儀瑞翠巔，洞中阻隘石門全。", "傍通小徑無窮極，溜響玎璫有穴泉。"]'),
('fe4b16bc-0a85-46fb-a338-faf1fccb1700','知宮高士菊巖','張復','宋','宋诗','song-poetry','','[]','來游九鎖山，忽遇菊巖仙。',48,'全唐诗/poet.song.253000.json','["來游九鎖山，忽遇菊巖仙。", "老翠偃千畝，黄金鋪萬錢。", "花經令尹愛，詞入北司編。", "最重水中石，平舟曾爲鎸。"]'),
('50d5f02d-fe91-4df5-bfe6-0b426ad70c97','龜山','季履道','宋','宋诗','song-poetry','','[]','濁酒三秋館，青燈半夜花。',48,'全唐诗/poet.song.253000.json','["濁酒三秋館，青燈半夜花。", "故人渾在目，幽夢暫還家。", "淮近風偏惡，山高月易斜。", "新霜何處雁，片影落平沙。"]'),
('eacfbbd2-a922-4be8-90c5-3a4e08c742c0','早梅','鄭上村','宋','宋诗','song-poetry','','[]','紛紛蜂蝶莫教知，竹外疏花一兩枝。',32,'全唐诗/poet.song.253000.json','["紛紛蜂蝶莫教知，竹外疏花一兩枝。", "待得枝頭春爛熳，便如詩到晚唐時。"]'),
('29ef7a50-6309-4d4e-b78f-a624fe378558','梅氏梅樓','鄭上村','宋','宋诗','song-poetry','','[]','山雲樓頭徹夜明，天風吹下讀書聲。',32,'全唐诗/poet.song.253000.json','["山雲樓頭徹夜明，天風吹下讀書聲。", "勸君莫把離騷讀，見說梅花恨未平。"]'),
('1fa70aba-9194-4a07-955c-c0b11289c6ca','晚梅','高安齋','宋','宋诗','song-poetry','','[]','買得街頭最晚梅，瀟瀟風雨對吟杯。',32,'全唐诗/poet.song.253000.json','["買得街頭最晚梅，瀟瀟風雨對吟杯。", "莫嫌吟蕊能稀少，不學春光爛熳開。"]'),
('86153c19-fdbb-463c-a7f1-3286b17ef180','九月梨花','韓準','宋','宋诗','song-poetry','','[]','粉膩迷春月滿枝，誤隨秋日弄芳菲。',32,'全唐诗/poet.song.253000.json','["粉膩迷春月滿枝，誤隨秋日弄芳菲。", "料應潜作春宵夢，剛被西風不放歸。"]'),
('c0e33bec-933f-4f4e-8364-f7866b7efb49','瓶花','李雲巖','宋','宋诗','song-poetry','','[]','點檢春風事，瓶花最可憐。',24,'全唐诗/poet.song.253000.json','["點檢春風事，瓶花最可憐。", "本根不知處，猶自向人妍。"]'),
('375d2eae-8582-43f8-adab-bda4ecae1f79','太師菊','凌雲屋','宋','宋诗','song-poetry','','[]','清白冠他三少貴，孤高獨占九秋寒。',32,'全唐诗/poet.song.253000.json','["清白冠他三少貴，孤高獨占九秋寒。", "功成勇退東籬下，不逐春紅相牡丹。"]'),
('c6d7e26d-fd5b-417e-9465-47a367a9319b','栽蘭','韓愛山','宋','宋诗','song-poetry','','["\u897f\u6e56"]','不能隨俗辦生涯，剗草栽蘭當理家。',32,'全唐诗/poet.song.253000.json','["不能隨俗辦生涯，剗草栽蘭當理家。", "不見西湖林處士，一生受用只梅花。"]'),
('652c0230-2dc7-4fae-ab3b-fba9a9d1578a','謝惠竹萌','錢積善','宋','宋诗','song-poetry','','[]','新挑笋茁喜登盤，減却南階竹幾竿。',32,'全唐诗/poet.song.253000.json','["新挑笋茁喜登盤，減却南階竹幾竿。", "已爲枯禪參玉版，暫停排日報平安。"]'),
('21cf0e3b-8303-4568-bc62-c6101788a397','蛩','耕吳','宋','宋诗','song-poetry','','[]','九夏蜩螗不可聽，秋風纔動便無聲。',32,'全唐诗/poet.song.253000.json','["九夏蜩螗不可聽，秋風纔動便無聲。", "一襟月露丘園裏，却勝趨炎作隊鳴。"]'),
('36678ae0-1aa1-4f58-b052-febf4b9168f5','村莊即事','耕吳','宋','宋诗','song-poetry','','[]','菊過重陽尚吐香，晚秋風景屬村莊。',64,'全唐诗/poet.song.253000.json','["菊過重陽尚吐香，晚秋風景屬村莊。", "日羹野菜同妻飯，時倩鄰蒭對客觴。", "霜後樹枝多老醜，雨餘山色半微茫。", "近來少入城中去，爲愛閑居滋味長。"]'),
('e8c716a8-9d20-4366-9fc4-385454cf6ceb','隠居','耕吳','宋','宋诗','song-poetry','','[]','得失兩忘機，何心問是非。',48,'全唐诗/poet.song.253000.json','["得失兩忘機，何心問是非。", "難求斬馬劍，且守釣魚磯。", "鶴瘦添新料，兒寒補舊衣。", "詩成興飄逸，天外片雲飛。"]'),
('7bf31162-040e-4cda-83a8-43f6b9751346','雨鳩','向雪湖','宋','宋诗','song-poetry','','[]','曈曨曉日上簾旌，又聽林鳩逐婦聲。',32,'全唐诗/poet.song.253000.json','["曈曨曉日上簾旌，又聽林鳩逐婦聲。", "可笑天公無定向，只隨汝輩作陰晴。"]'),
('ec2d2f73-f234-46cc-a7df-1d4e2210abc4','秋燕','黄月湖','宋','宋诗','song-poetry','','[]','主人情熟已忘機，簾幙中間自在飛。',32,'全唐诗/poet.song.253000.json','["主人情熟已忘機，簾幙中間自在飛。", "昨夜西風凉信早，豈無歸夢到烏衣。"]'),
('1c669c75-4d5d-43b1-bdcd-47e56c39d4bf','莫養虎','彭子翔','宋','宋诗','song-poetry','','[]','莫養虎，飽則喜子饑則怒。',68,'全唐诗/poet.song.253000.json','["莫養虎，飽則喜子饑則怒。", "莫養鷹，饑則附人飽颺去。", "鷹去但忘恩，虎怒將爲冤。", "不如團飯養雞狗，狗能吠盜雞戒曉。", "世事反覆不可□，狗或反噬雞亂啼。"]'),
('fa8933b4-b72c-4e8c-87ec-694dd53a4c26','廢宮','陶應靁','宋','宋诗','song-poetry','','[]','雨壞宮牆蔓草多，自披荒棘認銅駝。',32,'全唐诗/poet.song.253000.json','["雨壞宮牆蔓草多，自披荒棘認銅駝。", "舊家遊女知亡國，不唱春風緩緩歌。"]'),
('4aed2e80-29ea-4764-b234-f82483be49dc','古詩二首  其一','陶應靁','宋','宋诗','song-poetry','','[]','晨選期門士，大獵南山陽。',264,'全唐诗/poet.song.253000.json','["晨選期門士，大獵南山陽。", "白日照旌旗，咫尺臨清光。", "之子才且武，結髪在戎行。", "控弮拉羆虎，餘勇殊未央。", "回車宴五柞，舉烽令行觴。", "禾黍被中野，松柏生高岡。", "借問何所思，所思在冀方。", "彼美冀方士，安得同翱翔。", "峨峨切雲冠，奕奕夫容劍。", "揚揚徒旅繁，濟濟駕紫燕。", "行行向雙闕，去上未央殿。", "君明臣亦良，四海皆清晏。", "齋房多靈芝，郊藪鳳凰見。", "群臣亦何爲，稱功勸封禪。", "中夜整冠带，覽彼明月光。", "屏營不能寐，憂心獨怦怦。", "危坐待月發，牽牛直南榮。", "盈庭樹蘭蕙，芬香日凋零。", "客行隨所適，感物懷故鄉。", "朝發雁門道，夕入蘭臺宮。", "佳賓會若雲，列鼎吹笙簧。", "終歲極燕樂，保己有餘慶。"]'),
('0eb717ba-ef4c-47c4-b2ff-44c3193e97ce','古詩二首  其二','陶應靁','宋','宋诗','song-poetry','','[]','仙人降瑶席，風露清壇場。',96,'全唐诗/poet.song.253000.json','["仙人降瑶席，風露清壇場。", "朗詠玉書文，遥上綠雲章。", "閶闔啟中夜，五色垂景光。", "霓旌導絳節，授以長生方。", "湛然守中扃，不迎亦不將。", "瓊漿酌天和，玉芝茹春香。", "手種蟠桃花，坐待三千霜。", "相從廣成子，鸞鵠參翱翔。"]'),
('d073dd59-e739-4983-accf-516f7cb4bb38','題清隠堂','無名氏','宋','宋诗','song-poetry','','[]','凉蟬亂叫朝暮雨，獨鶴不迷前後山。',32,'全唐诗/poet.song.253000.json','["凉蟬亂叫朝暮雨，獨鶴不迷前後山。", "茶葉煮湯勝茗椀，栗花然火稱松關。"]'),
('4c586be3-9b33-4056-b79f-dc6ce000245f','世居亭','謝安之','宋','宋诗','song-poetry','','[]','后皇來何從，頓此八紘網。',132,'全唐诗/poet.song.253000.json','["后皇來何從，頓此八紘網。", "神臯塵冥冥，冠蓋爭勇往。", "研桑到白首，塞屋猶怏怏。", "云何石南牧，上印歸州黨。", "虛裝絕桂海，借石壓輕槳。", "清風肅炎漲，心事映莽沆。", "一朝入吳門，幾載耀庭幌。", "取廉報常豐，溢作百世享。", "英英玉華姿，宛有鬰林象。", "開軒函位置，得地甫尋丈。", "何以詔雲仍，世居如此榜。"]'),
('ff27dc53-5da2-42d5-8790-519c9572f619','題清芬閣','蔡王竦','宋','宋诗','song-poetry','','[]','先生窮不怨，語淡氣渾然。',48,'全唐诗/poet.song.253000.json','["先生窮不怨，語淡氣渾然。", "大雅三百首，高□□萬年。", "至今存舊稿，舉世玩新編。", "我獨非真□，□慚遠裔賢。"]'),
('4ab79c0c-136b-4541-bb82-67d24be136d4','題清芬閣','長倩','宋','宋诗','song-poetry','','[]','先生有古風，杳出塵外格。',180,'全唐诗/poet.song.253000.json','["先生有古風，杳出塵外格。", "猶如陵空鴻，矯矯奮六翮。", "鏘金中律呂，詠性甘糠覈。", "苦調非孟酸，□適鄙韓窄。", "逸韻肩曹劉，雄詞卑甫白。", "空遺茂陵稿，未前宣室席。", "瓌寶豈終埋，簡編綴陳迹。", "予生誦風雅，嗜好真成癖。", "盥手讀終篇，喜同藏拱璧。", "裔孫文昌郎，授受良珍惜。", "小巫畏大匠，累句屢承索。", "續貂愧非尾，成裘由聚腋。", "皇華間白雪，雜唱紛繳繹。", "意欲揚祖美，不問玉與石。", "長言拙稱贊，徒慕郢中客。"]'),
('09359141-9920-4775-b56c-09efa2b7d1fd','題清芬閣','令狐勤','宋','宋诗','song-poetry','','[]','遠叩玄英舊隠扉，清風今日尚依依。',64,'全唐诗/poet.song.253000.json','["遠叩玄英舊隠扉，清風今日尚依依。", "雲山自許老龍卧，霄漢不妨雙鳳飛。", "欲訪騷人考槃地，但尋漢叟釣魚磯。", "年來踏盡紅塵路，頼有溪流濯客衣。"]'),
('3e8836b9-4beb-42f3-bcb1-874319469f34','題清芬閣二首  其一','李洸','宋','宋诗','song-poetry','','[]','詩亡向千載，禮義誰維持。',144,'全唐诗/poet.song.253000.json','["詩亡向千載，禮義誰維持。", "唐人得名者，沈宋稱綺詞。", "卓哉先生才，邈視數子卑。", "抗懷信高潔，出事皆清奇。", "不矜險絕句，意遠窺無涯。", "春歸鑑湖綠，水落嚴子磯。", "往來寄漁釣，遯世心獨知。", "松月繞雲山，盡入騷人思。", "白雪雅調高，俗耳聽不宜。", "群兒謾嘲毀，百歲名愈馳。", "裔孫有清風，宛若先生詩。", "搔頭試一吟，古意猶能追。"]'),
('3f37fc4b-b779-449f-9337-1189c6977f4d','題清芬閣二首  其二','李洸','宋','宋诗','song-poetry','','[]','備員何奉再依仁，仰慕亨衢速若神。',64,'全唐诗/poet.song.253000.json','["備員何奉再依仁，仰慕亨衢速若神。", "萬里雲龍遭聖世，三年苫塊報慈親。", "盧茨山水風騷國，獬豸衣冠法令臣。", "誰謂趨朝虛几席，長兄歌酒更延賓。"]'),
('361c26e4-428b-4008-b6d8-969f682fdffa','題清芬閣二首  其一','陶遷','宋','宋诗','song-poetry','','[]','盧茨源上風烟好，結架遥憐雲水湄。',64,'全唐诗/poet.song.253000.json','["盧茨源上風烟好，結架遥憐雲水湄。", "曾是先生親卜築，不妨相國細吟詩。", "山開兩峽雲來暝，灘急一江帆到遲。", "作意雲孫真好事，清芬高繼昔人□。"]'),
('9c57cc2d-a994-4d20-aa09-e5d175f065fb','題清芬閣二首  其二','陶遷','宋','宋诗','song-poetry','','[]','平生無夢到班行，留得清名與世長。',64,'全唐诗/poet.song.253000.json','["平生無夢到班行，留得清名與世長。", "此老風流勝此謝，諸郎佳句似池塘。", "掛雲出屋須臨賦，卓筆名題信似狂。", "小泊便思安石渚，他年容我聽鳴羯。"]'),
('d0a2a05a-4c59-47e1-806d-3b1eac5aa740','野人家','趙蘭皋','宋','宋诗','song-poetry','','[]','總爲門無馬足塵，敗簑懸壁亦天真。',64,'全唐诗/poet.song.253000.json','["總爲門無馬足塵，敗簑懸壁亦天真。", "看渠只是芸田者，處世强如識字人。", "隔水架茅知避俗，得魚沽酒却分鄰。", "市朝多少人稱隠，只隠黄金不隠身。"]'),
('ddb8bda0-5d4a-4893-8aa7-4e09a0201590','田家','羅南山','宋','宋诗','song-poetry','','[]','逐壯雞飛過短牆，茅柴燒盡滿林霜。',64,'全唐诗/poet.song.253000.json','["逐壯雞飛過短牆，茅柴燒盡滿林霜。", "釀成社酒家家醉，炊得新粳處處香。", "牽犢負犁朝種麥，開渠引水晚澆桑。", "老農不管催租急，未夜烘衣先上床。"]'),
('7bf93926-d666-44f8-a5cd-c46cfb48dade','巖嶺憩亭','吳敏','宋','宋诗','song-poetry','','[]','蟬聲滿秋樹，雲影護晴雷。',24,'全唐诗/poet.song.253000.json','["蟬聲滿秋樹，雲影護晴雷。", "獨坐西風久，半空飛雨來。"]'),
('1de2ad56-d2c4-42e7-9d28-181420f5614d','列岫亭','江定齋','宋','宋诗','song-poetry','','[]','倚檻窮雙目，疏林出遠村。',48,'全唐诗/poet.song.253000.json','["倚檻窮雙目，疏林出遠村。", "秋深山有骨，霜降水無痕。", "天地供吟思，煙霞入醉魂。", "回頭雲破處，新月報黄昏。"]'),
('99535070-c542-4491-b4e4-7684442f9ca6','題金山雄跨亭','江定齋','宋','宋诗','song-poetry','','[]','漠漠楊花滿渡頭，東方助我作山遊。',64,'全唐诗/poet.song.253000.json','["漠漠楊花滿渡頭，東方助我作山遊。", "凌空地勢欲吞海，繞寺渡聲長带秋。", "遠近煙光分岸色，高低塔影浸江流。", "欄干倚遍無窮思，頻喚吟杯洗□愁。"]'),
('ec6ecfe7-a0ee-4ac6-9f8f-35ab27155e6a','南塘山居','上官琪園','宋','宋诗','song-poetry','','[]','微雨樵蒸煙起遲，一官拋去久忘機。',64,'全唐诗/poet.song.253000.json','["微雨樵蒸煙起遲，一官拋去久忘機。", "門多雜樹聞蟬早，家近青山見客稀。", "藥臼每移斜日晒，荻船常趁便風歸。", "生來未覺疏琴史，冰簟苔樽在石磯。"]'),
('4ad83969-6e28-4561-aec2-30d8692c0a7e','山隠齋樓居偶成','趙汝記','宋','宋诗','song-poetry','','[]','近屋新篁已作叢，山光稍遠眼濛濛。',32,'全唐诗/poet.song.253000.json','["近屋新篁已作叢，山光稍遠眼濛濛。", "何如乞取仙源水，塵垢俱消洗滌中。"]'),
('aaead99d-9ede-43b2-b9ee-052ff3792f06','題友人山居','高竹鶴','宋','宋诗','song-poetry','','[]','自汲清泉灌藥畦，西風籬落豆初肥。',64,'全唐诗/poet.song.253000.json','["自汲清泉灌藥畦，西風籬落豆初肥。", "溪童趁日烘漁網，山婦迎寒織雨衣。", "棋散石臺仙客去，松摇花崦野猿歸。", "尚嫌居處鄰村近，又欲移家入翠微。"]'),
('90989d08-6ae5-4a42-a14e-7caff5de8a30','村居即事','劉雪崖','宋','宋诗','song-poetry','','[]','數聲雞犬自相聞，借得茅廬住水濆。',64,'全唐诗/poet.song.253000.json','["數聲雞犬自相聞，借得茅廬住水濆。", "梅欲黄時常是雨，稻纔青處便如雲。", "憂時每歎朝廷遠，學稼方知畎畝勤。", "若使徵書到巖谷，北山又恐動移文。"]'),
('7da4c3d2-8f71-4206-b044-1cb2b12f28de','客邸','劉雪崖','宋','宋诗','song-poetry','','[]','蟠蟀吟空壁，秋深夜漸長。',48,'全唐诗/poet.song.253000.json','["蟠蟀吟空壁，秋深夜漸長。", "月華清似水，露氣重於霜。", "醉後夢難記，興來詩欲狂。", "西風何處笛，喚起客思鄉。"]'),
('ab97b047-9861-4c7d-bbcb-4bd99df84166','李山人所居','申屠月巖','宋','宋诗','song-poetry','','[]','竹滿園林水滿池，旋栽黄菊補疎籬。',32,'全唐诗/poet.song.253000.json','["竹滿園林水滿池，旋栽黄菊補疎籬。", "白雲遮斷紅塵路，人是人非總不知。"]'),
('3bba7160-b5e5-4c43-8673-af64778c971c','閒居遣興','申屠月巖','宋','宋诗','song-poetry','','[]','鷗鷺江湖性，清閑勝作官。',48,'全唐诗/poet.song.253000.json','["鷗鷺江湖性，清閑勝作官。", "家貧隨分過，母健覺心寬。", "酒熟旋篘飲，詩成逐板刊。", "七星在長鋏，斷不爲魚彈。"]'),
('6733844a-57be-4a30-8cb2-cce47c9bf194','復州東樓','吳默齋','宋','宋诗','song-poetry','','[]','閑憑欄干立，詩牽望眼迷。',48,'全唐诗/poet.song.253000.json','["閑憑欄干立，詩牽望眼迷。", "水穿城內外，樓接市東西。", "江闊雲常濕，天寬山盡低。", "燕鶑春寂寂，只有雨鳩啼。"]'),
('82f27cdd-a185-400a-8283-5e8141b6375f','雙溪閣','鄭錦溪','宋','宋诗','song-poetry','','[]','玳簪新筍破泥沙，寒食輕陰酒望斜。',32,'全唐诗/poet.song.253000.json','["玳簪新筍破泥沙，寒食輕陰酒望斜。", "日暮子規啼不住，滿山風雨落桐花。"]'),
('618b6aa1-4503-4eb3-9647-d99f068d363f','晚對亭','虞子萬','宋','宋诗','song-poetry','','[]','落日下青嶂，歸雲猶未安。',24,'全唐诗/poet.song.253000.json','["落日下青嶂，歸雲猶未安。", "倚杖無言久，夕陰生翠寒。"]'),
('5fd63bd5-f296-4004-8cc8-0a351808c119','九日山亭','陳壑山','宋','宋诗','song-poetry','','[]','青竹題猶在，黄花課又供。',48,'全唐诗/poet.song.253000.json','["青竹題猶在，黄花課又供。", "浮生閑日少，清賞幾人從。", "老木有豪氣，秋山無媚容。", "凭高政懷古，江上夕陽舂。"]'),
('0958d3b0-e9c1-4927-b927-8c6f5d0a4c06','晚對亭','林漢宗','宋','宋诗','song-poetry','','[]','晚對無人但翠屏，春猿秋鶴自飛吟。',32,'全唐诗/poet.song.253000.json','["晚對無人但翠屏，春猿秋鶴自飛吟。", "滿船載酒來歌舞，誰識當年仁智心。"]'),
('536fbcc7-9c3b-4399-85eb-f9cc8a0752aa','初夏閑居','鮑鼇川','宋','宋诗','song-poetry','','[]','杜門春又夏，貧不厭身閑。',48,'全唐诗/poet.song.253000.json','["杜門春又夏，貧不厭身閑。", "白日靜於水，綠陰濃似山。", "野蔬留客飲，小艇送僧還。", "却憶西庵雨，泉聲石壁間。"]'),
('ffe44845-e093-4374-b7ac-0032b8bcb50f','題旅舍','武夷','宋','宋诗','song-poetry','','[]','去日春蠶吐雪絲，歸時霜菊剝金衣。',32,'全唐诗/poet.song.253000.json','["去日春蠶吐雪絲，歸時霜菊剝金衣。", "沙鷗不入鴛鴻侶，依舊滄浪繞釣磯。"]'),
('cfde5f89-6e31-4572-92a8-3c887ea3d251','故人亭','皇甫□','宋','宋诗','song-poetry','','[]','倚棹短亭西，吹塵認舊題。',48,'全唐诗/poet.song.253000.json','["倚棹短亭西，吹塵認舊題。", "水添春岸闊，雲壓暮山低。", "沙觜鷺初宿，樹頭烏自啼。", "故人今不見，惟有草萋萋。"]'),
('799d39e4-ad21-4dc6-9f6a-543382caa56e','句','皇甫□','宋','宋诗','song-poetry','','[]','棹穿波底月。',6,'全唐诗/poet.song.253000.json','["棹穿波底月。"]'),
('5fd5f3c5-a69a-4934-afb4-eaf3e9e3fd43','吾廬','何凉窗','宋','宋诗','song-poetry','','[]','禹山山下是吾廬，坐處常安數卷書。',64,'全唐诗/poet.song.253000.json','["禹山山下是吾廬，坐處常安數卷書。", "族近弟兄相聚密，家貧朋友欲來疏。", "臨窗種竹堪延鶴，向水開門可釣魚。", "莫羨貴人連甲第，一生能得幾時居。"]'),
('7d212f9e-9d02-4541-93ab-7ba1d73e6818','吾廬','劉叔驥','宋','宋诗','song-poetry','','[]','竹樹深藏遠市譁，吾廬真似野人家。',64,'全唐诗/poet.song.253000.json','["竹樹深藏遠市譁，吾廬真似野人家。", "幽禽就浴階前水，游蝶來尋几上花。", "心地幸無閑事擾，眼塵還有好書遮。", "浮生如此亦堪老，世路驅人底有涯。"]'),
('df344a3f-ff8a-414a-aead-3f39210eaf57','潄玉館','留怡然','宋','宋诗','song-poetry','','[]','拳石漱芳玉，夢回堪洗耳。',24,'全唐诗/poet.song.253000.json','["拳石漱芳玉，夢回堪洗耳。", "客至館於斯，妙處從此始。"]'),
('c3b9332c-c847-485b-88a3-3ea914660d0b','題蔡令葉嶺書房','趙汝□','宋','宋诗','song-poetry','','[]','日誦哲師記，歲通聖人書。',192,'全唐诗/poet.song.253000.json','["日誦哲師記，歲通聖人書。", "前岡復後麓，儼在中間居。", "佩月而冠雲，被服以璠璵。", "滄海朝奮駕，崑崙暮停車。", "矯然竦上征，浩蕩遊太虛。", "竟當一悟足，紛歷萬變餘。", "危機易翻覆，末世多崎嶇。", "主公總軍戎，參佐謀議攄。", "環帳募敖曹，奪營走休屠。", "寧知情事異，豈謂才智疏。", "歸飲永嘉水，勝食建鄴魚。", "緬想過西山，薰風襲芙蕖。", "朗明觀衆妙，沖漠味至腴。", "身治爲物基，學廣充理儲。", "潜深下董帷，抱獨吟葛廬。", "經綸有時命，吾子意何如。"]'),
('ce5b9100-c5c6-4b5d-9c80-110f53837bb2','題文公書院','管御史','宋','宋诗','song-poetry','','[]','乘舟駐馬覽九曲，怪柏喬松映修竹。',96,'全唐诗/poet.song.253000.json','["乘舟駐馬覽九曲，怪柏喬松映修竹。", "水明山秀讀書地，萬古悠悠遺芳躅。", "年深景怪公不來，淡霧衰草迷書臺。", "烏啼鵲噪暮林杪，明月夜夜穿空齋。", "門軒歲月誰開閉，策杖登臨令心碎。", "無聊舉棹便迴路，悶倚船窗讀周易。"]'),
('83a0605e-0b84-4c2c-8e66-65d745f33f55','題苑林北樓','鄭隼','宋','宋诗','song-poetry','','[]','雨來風靜綠蕪鮮，憑看朱欄思浩然。',64,'全唐诗/poet.song.253000.json','["雨來風靜綠蕪鮮，憑看朱欄思浩然。", "人語獨耕燒後嶺，鳥飛斜沒望中烟。", "松梢半露藏雲寺，灘勢橫流出浦船。", "若遣謝宣城不死，必應吟盡夕陽川。"]'),
('8cd86cbe-1827-4a51-9572-0fa07994716a','西窗','徐太玉','宋','宋诗','song-poetry','','[]','十日書窗九日扃，春晴無處不閑行。',32,'全唐诗/poet.song.253000.json','["十日書窗九日扃，春晴無處不閑行。", "瓶花落盡無人管，留得殘枝葉自生。"]'),
('f1b6fd90-39a3-48ba-b309-f4c13bf155c9','齋宿南山堂','呂良叔','宋','宋诗','song-poetry','','[]','寒窗一穗篆煙斜，紙帳孤眠對月華。',32,'全唐诗/poet.song.253000.json','["寒窗一穗篆煙斜，紙帳孤眠對月華。", "信是道人風味別，枕邊祇欠着梅花。"]'),
('80c531f3-e6c5-4266-bc7a-deaadf7c1f73','次君用借屋','鄭恕齋','宋','宋诗','song-poetry','','["\u897f\u6e56"]','拋却西湖舊綠簑，閉門無計奈愁何。',64,'全唐诗/poet.song.253000.json','["拋却西湖舊綠簑，閉門無計奈愁何。", "非關豪氣消磨盡，自是中年感慨多。", "漫漫平波魚自躍，陰陰垂柳鳥能歌。", "小樓咫尺無因到，輸與周郎日日過。"]'),
('fccbb43f-c10c-40ae-917d-129c36ae6c13','閑居','盛松坡','宋','宋诗','song-poetry','','[]','地僻無人到，何緣有市聲。',48,'全唐诗/poet.song.253000.json','["地僻無人到，何緣有市聲。", "醉中詩句健，閑裏夢魂清。", "澗水濃煎茗，畦蔬淡煮羹。", "讀書猶懶在，何暇見公卿。"]'),
('06d9e925-b897-4745-826b-f5998ca8a971','烏石山僧舍','盛松坡','宋','宋诗','song-poetry','','[]','小徑通山寺，飛簷抹曉霞。',48,'全唐诗/poet.song.253000.json','["小徑通山寺，飛簷抹曉霞。", "松風驚蝶夢，梵磬雜蜂衙。", "僧臘菩提樹，禪心菡萏花。", "詩成因抵掌，飛起欲棲鴉。"]'),
('c9d32799-359c-4e51-be26-40d71bf8ea33','卜築','林羲','宋','宋诗','song-poetry','','[]','卜築向東郊，低簷淺覆巢。',48,'全唐诗/poet.song.253000.json','["卜築向東郊，低簷淺覆巢。", "自知心計拙，不與市情交。", "夜燭調詩律，晨香玩易爻。", "有時松影散，坐看鶴歸巢。"]'),
('4460859d-f6f6-4255-bf9c-b625d6e40ac1','月夜登樓','王漁壑','宋','宋诗','song-poetry','','[]','維舟古柳傍嚴城，借我今宵倚晚晴。',64,'全唐诗/poet.song.253000.json','["維舟古柳傍嚴城，借我今宵倚晚晴。", "一笛清風秋萬里，半樓殘月夜三更。", "客懷耿耿清樽窄，世故悠悠白髪生。", "醉倒拍床誰喚醒，轆轤聲裏辨長庚。"]'),
('4cfa9893-1701-4732-b562-4afafb06b996','林潘張三友會于新樓','和請','宋','宋诗','song-poetry','','[]','又携詩卷到南州，塵滿征衫雪滿頭。',64,'全唐诗/poet.song.253000.json','["又携詩卷到南州，塵滿征衫雪滿頭。", "桃李春風故國夢，江山落日異鄉愁。", "樽前一笑真奇事，坐上諸君盡勝流。", "政倚清談洗胸臆，莫教王粲賦登樓。"]'),
('3282f65c-7d98-4e2a-b471-1d295e04b7d1','簡高澹軒','姜竹野','宋','宋诗','song-poetry','','[]','西風籬下菊班班，想得吟肩正聳山。',32,'全唐诗/poet.song.253000.json','["西風籬下菊班班，想得吟肩正聳山。", "急遣麴生陪杖履，要傳好句出人間。"]'),
('f6f42f02-2107-4741-ade1-e8317973deb7','西湖竹閣寺','姜竹野','宋','宋诗','song-poetry','','["\u897f\u6e56"]','來此琅玕影裏吟，更於何處覓山林。',32,'全唐诗/poet.song.253000.json','["來此琅玕影裏吟，更於何處覓山林。", "千年清事無人管，獨有香山領此心。"]'),
('ce31bfbb-3e9b-41d9-a21e-cc2abc3ac664','船子和尚西亭','姜竹野','宋','宋诗','song-poetry','','[]','船翻亭迹尚依然，動有風波靜有天。',32,'全唐诗/poet.song.253000.json','["船翻亭迹尚依然，動有風波靜有天。", "人世不知行實地，每於船上又安船。"]'),
('2419d877-e6a2-41c1-8f5a-c83602e99db3','清明遊玉堂莊','釋朋來','宋','宋诗','song-poetry','','[]','幾宿青山逐陸郎，清明時節好煙光。',64,'全唐诗/poet.song.253000.json','["幾宿青山逐陸郎，清明時節好煙光。", "歸穿綠荇船頭滑，醉踏殘花屐齒香。", "風急嶺雲飄逈野，雨餘田水落方塘。", "不堪吟罷東回首，滿耳蛙聲正夕陽。"]'),
('568ef7fc-4238-49f1-a545-698ff9e2eb8c','下竺寺','周野齋','宋','宋诗','song-poetry','','[]','靜看唐人刻，相連坐石陰。',48,'全唐诗/poet.song.253000.json','["靜看唐人刻，相連坐石陰。", "鳥呼留客意，果熟住山心。", "野水流詩葉，天香襲道林。", "雲根有桂樹，應待月中尋。"]'),
('25f0c2fb-1f27-472c-9c5e-0abd8d290ea5','題度門寺','周□','宋','宋诗','song-poetry','','[]','才入度門寺，先觀覺範詩。',48,'全唐诗/poet.song.253000.json','["才入度門寺，先觀覺範詩。", "昔人吟不盡，今日到方知。", "地僻寒來早，山高月上遲。", "池邊老脩竹，曾映董生帷。"]'),
('864aabc0-5888-4577-9d40-86cf5eb91c63','九曲尼院','黄樵逸','宋','宋诗','song-poetry','','[]','曾是衣裳第一人，曲終認得本來身。',32,'全唐诗/poet.song.253000.json','["曾是衣裳第一人，曲終認得本來身。", "多年不作東風夢，閑却薔薇一架春。"]'),
('d2fa49c6-ee5f-4697-884d-9276ba0b37a9','祥符寺水閣','余國寶','宋','宋诗','song-poetry','','[]','楚江空闊水痕收，葭葦蕭蕭兩岸幽。',64,'全唐诗/poet.song.253000.json','["楚江空闊水痕收，葭葦蕭蕭兩岸幽。", "柔櫓推殘千頃浪，好風吹過一帆愁。", "人歸別浦雲烟晚，舟泊寒沙島嶼秋。", "領略風光須我輩，謾尋詩句倚江樓。"]'),
('71182c3c-45a7-474e-b525-35d1b059447f','鶴林寺竹院','朱省齋','宋','宋诗','song-poetry','','[]','鶴林古竹院，馬素舊松關。',48,'全唐诗/poet.song.253000.json','["鶴林古竹院，馬素舊松關。", "草合門前路，雲埋寺後山。", "花神千載去，僧話片時閑。", "滿壁瑰奇句，慚窺豹一斑。"]'),
('79fff412-00ae-489f-a3bd-1043abc66fb4','禹寺','蘇凌然','宋','宋诗','song-poetry','','[]','看經轉佛稻場邊，一逕松杉密似煙。',32,'全唐诗/poet.song.253000.json','["看經轉佛稻場邊，一逕松杉密似煙。", "見說老僧渾不出，送人只到寺門前。"]'),
('e3224a18-3672-40d5-a093-d1f16213efa0','靈巖禪寺','蔣允中','宋','宋诗','song-poetry','','["\u534e\u5c71"]','曉入靈巖寺，靈蹤一一穿。',120,'全唐诗/poet.song.253000.json','["曉入靈巖寺，靈蹤一一穿。", "天聰鑿混沌，龍鼻滴潺湲。", "不雨山長濕，微風谷競喧。", "參旗開障日，鼇柱仰擎天。", "雁異靈山鷲，蒲非華嶽蓮。", "重臺疑魏載，卓筆豈張顛。", "夜月連千嶂，晴雲畫一川。", "凈名常宴坐，行亮昔安禪。", "共樂仙遊勝，都將世事捐。", "雙鸞知可跨，擬把石碑鎸。"]'),
('78d3fbdd-8cd7-4b54-a66d-8cc2f3c37e68','壽昌禪寺','康惇','宋','宋诗','song-poetry','','[]','不怕石頭滑，來爲雁蕩行。',48,'全唐诗/poet.song.253000.json','["不怕石頭滑，來爲雁蕩行。", "平生夢不到，今日眼逾明。", "未歷千巖秀，先逢一段清。", "遍觀從此始，着脚歷崢嶸。"]'),
('0fe0885c-ec78-4fba-b8d2-d9cf0382f33e','題妙庭觀  其一','邊維嶽','宋','宋诗','song-poetry','','[]','飛橋翼翼傍雲岑，田宅荒凉一逕深。',32,'全唐诗/poet.song.253000.json','["飛橋翼翼傍雲岑，田宅荒凉一逕深。", "想像吹笙凉徹夜，却疑風竹助遺音。"]'),
('60426bc3-f7e2-4922-b8c2-6e2ddfb07b81','題妙庭觀  其二','邊維嶽','宋','宋诗','song-poetry','','[]','不見當年鼎與堅，望中河漢路漫漫。',32,'全唐诗/poet.song.253000.json','["不見當年鼎與堅，望中河漢路漫漫。", "人人自有飛昇骨，平却心丹是內丹。"]'),
('b8b08d5c-e8ad-4c03-af80-713cea035ed5','題妙庭觀  其一','程秘','宋','宋诗','song-poetry','','[]','衝雨西來又雨歸，出門重爲此山悲。',32,'全唐诗/poet.song.253000.json','["衝雨西來又雨歸，出門重爲此山悲。", "重重俗屋遮藏盡，無復新軒扁乞芝。"]'),
('557bf139-0b15-41d8-af1c-fd132156c8b7','題妙庭觀  其二','程秘','宋','宋诗','song-poetry','','[]','要識仙霞五色丹，須還苔瑣舊靈壇。',32,'全唐诗/poet.song.253000.json','["要識仙霞五色丹，須還苔瑣舊靈壇。", "玉樓更疑群仙宿，移向長虹卧處安。"]'),
('4cc44030-03e7-4d3a-a2b1-2bf4ff0f0ad8','老人行','無名氏','宋','宋诗','song-poetry','','[]','有一老翁老無齒，處處無人問年紀。',320,'全唐诗/poet.song.253000.json','["有一老翁老無齒，處處無人問年紀。", "白髪如絲向下垂，一雙眸子碧如水。", "不裹頭，又不履，相識雖多少知己。", "問翁畢竟何所止，笑言只在紅塵裏。", "秋風獵獵行雲飛，老人此意無人會，目注雲歸心自知。", "黄口小兒莫相笑，老人舊日曾年少。", "浪迹常如不繫舟，地角天涯自知跳。", "亦曾樂半夜，傳籌醉朱閣。", "美人如花弄絃索，只恨樽前明月落。", "亦曾憂羈放，他鄉迫暮秋。", "故國日邊無信息，斷鴻空逐水長流。", "或安貧，或安富，或爵通侯封萬戶。", "一任秋霜換鬢毛，本來面目長如故。", "水有蘋兮山有芝，人意雖存事已非。", "有時却憶經游處，都似茫茫春夢歸。", "邇來尤解安貧賤，不爲公卿强陪面。", "皎如明月在秋水，動著依前還不見。", "還不見，可奈何，空使遠人增眷戀。", "但只從他隨物轉，青樓黄閣長相見。", "長相見，莫殷勤，却是翁家舊主人。"]'),
('fbb8b729-8ffe-4775-a2db-138ba46cb4bd','遊虎丘見瞎堂扁額有感','趙月泉','宋','宋诗','song-poetry','','[]','入山認得本來蹤，識破機關境界同。',32,'全唐诗/poet.song.253000.json','["入山認得本來蹤，識破機關境界同。", "水自東流山自秀，因緣只在笑談中。"]'),
('095ed6d9-b09c-4a23-918f-42a9c31ad7be','句','偉岸翁','宋','宋诗','song-poetry','','[]','水聲翻海底，塔影寫樓心。',12,'全唐诗/poet.song.253000.json','["水聲翻海底，塔影寫樓心。"]'),
('2004ccb9-ec07-4a01-a1eb-65b25158ccb6','虎丘呈元機上人','葛逸','宋','宋诗','song-poetry','','[]','樓觀倚雲端，烟收陸海寬。',48,'全唐诗/poet.song.253000.json','["樓觀倚雲端，烟收陸海寬。", "蒼崖留劍跡，古木見龍蟠。", "石徑青苔滑，霜林木葉乾。", "憑欄千里豁，爽氣逼人寒。"]'),
('f14149ed-ef47-4194-aa3e-b302e0b657cd','北固山','張靈受','宋','宋诗','song-poetry','','[]','鐵甕城頭數塞鴻，淮山依約翠烟中。',64,'全唐诗/poet.song.253000.json','["鐵甕城頭數塞鴻，淮山依約翠烟中。", "傷心狠石千年在，極目迷樓百尺空。", "浮玉春酣江带綠，扶桑日漲海門紅。", "南朝流下無窮浪，長與漁人櫂短蓬。"]'),
('a8a6057d-85d4-498c-8e23-2b5a34111dc6','遊金山','潘景良','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','嵌巖穹窿，屹立乎江中。',300,'全唐诗/poet.song.253000.json','["嵌巖穹窿，屹立乎江中。", "崩湍下瞰不見底，巨石崛出高摩空。", "混沌破來到今幾萬歲，雄奇秀麗胡爲乎此山兮獨鍾。", "長江西來一萬里，當空削出金芙蓉。", "上有金仙居，下有馮夷宮。", "寶坊櫛比列霄漢，塔影倒置驚魚龍。", "有時洪鐘咽烟響，潮音屬和驅群聾。", "鳥飛竟力不得到，我嘗拏舟一抵其雲峰。", "攝衣步樓閣，矯首觀無窮。", "齊州九點落眼底，岷峨西望滄溟濛。", "忽聞長風破巨浪，芥蒂一洗平生胸。", "山僧喜殊常，握手何從容。", "杯擎陸羽水，茶汎玉川風。", "鶴庵散仙，恒齋老翁，把臂大笑聲融融。", "天風吹袂欲輕舉，白雲縹緲將何從。", "不知海外之三山，群仙之樂與此將異而或同。", "迄今別去五六載，我舟又復來掀篷。", "山靈偃蹇我倨傲，塵懷汩沒不得追前蹤。", "風帆一笑金山過，山頭日落飛冥鴻。"]'),
('5eafc4c9-a4ee-4832-bf12-dee2073a6692','題白雲院','余越','宋','宋诗','song-poetry','','[]','松花蔌蔌糝蒼苔，牆角梧桐取次開。',32,'全唐诗/poet.song.253000.json','["松花蔌蔌糝蒼苔，牆角梧桐取次開。", "倚徧闌干人未去，一雙白鷺破山來。"]'),
('16c34d34-15fe-4d99-940d-5c00b52ecbe0','遊寶林寺','上官祐','宋','宋诗','song-poetry','','[]','野寺無人到，春風掃落花。',24,'全唐诗/poet.song.253000.json','["野寺無人到，春風掃落花。", "重尋舊遊處，泉石遶烟霞。"]'),
('97541e69-19e6-4210-a273-4015f218a27f','句  其一','黄畸翁','宋','宋诗','song-poetry','','[]','流落人間一萬篇。',8,'全唐诗/poet.song.253000.json','["流落人間一萬篇。"]'),
('f75901ab-a2fc-43e6-9fc4-e481f6093c38','句  其二','黄畸翁','宋','宋诗','song-poetry','','[]','身閑不入紅塵市，夢好頻驚畫角聲。',16,'全唐诗/poet.song.253000.json','["身閑不入紅塵市，夢好頻驚畫角聲。"]'),
('8e53b5ca-cbc6-4e7d-9576-e53a39ffff89','句  其三','黄畸翁','宋','宋诗','song-poetry','','[]','日高三丈宿酒醒，鳥喚一聲春夢驚。',16,'全唐诗/poet.song.253000.json','["日高三丈宿酒醒，鳥喚一聲春夢驚。"]'),
('d9ba2615-06da-4ef9-a39c-4d12bc24fe99','靈鑒院','洪延','宋','宋诗','song-poetry','','[]','曉日開晴壑，山行信馬蹄。',48,'全唐诗/poet.song.253000.json','["曉日開晴壑，山行信馬蹄。", "石泉鳴夜玉，林筍迸春遲。", "松月禪心靜，塵埃俗眼迷。", "懸崖高萬丈，倚作上天梯。"]'),
('a3fb1cc1-458a-4599-8357-196896753891','題太平館','傅知錄','宋','宋诗','song-poetry','','[]','萬物榮枯自有時，梅花非早菊非遲。',32,'全唐诗/poet.song.253000.json','["萬物榮枯自有時，梅花非早菊非遲。", "時人莫似春蝴蝶，才到花開便滿枝。"]'),
('4ca92ed5-9778-44dd-9eff-97ed3e829866','高平北巖','□說','宋','宋诗','song-poetry','','[]','路入仙峰不記重，一軒瀟洒檜陰中。',64,'全唐诗/poet.song.253000.json','["路入仙峰不記重，一軒瀟洒檜陰中。", "溪山括盡丹青巧，天地馳回造化工。", "風剡鱗波清枕簟，日扶花影上簾櫳。", "來遊絕異人間景，身世依稀到蘂宮。"]'),
('0a614ac2-1a19-4852-9226-86d69ec49f50','閶門灘','黄宗德','宋','宋诗','song-poetry','','[]','姑蘇西去是閶門，何事祁山亦共名。',32,'全唐诗/poet.song.253000.json','["姑蘇西去是閶門，何事祁山亦共名。", "落月啼烏人睡覺，曉鐘空動故鄉情。"]'),
('1663869f-839e-4e53-9486-670a3970e962','清溪','胡溥','宋','宋诗','song-poetry','','[]','楊柳汀洲綠四圍，沙中禽鳥雜相依。',32,'全唐诗/poet.song.253000.json','["楊柳汀洲綠四圍，沙中禽鳥雜相依。", "烟留群鷺和鷗卧，霞带孤鴻與鶩飛。"]'),
('87d7363c-13cb-49a0-97bb-5cabb333094b','通玄觀','汪行素','宋','宋诗','song-poetry','','[]','蓬壺咫尺隔塵氛，流水桃源上下村。',32,'全唐诗/poet.song.253000.json','["蓬壺咫尺隔塵氛，流水桃源上下村。", "遊遍東西南北洞，風光別是一乾坤。"]'),
('910ef6e8-7ef8-40a0-9264-210ca91d2db2','謝劉本玉先生惠簟','王學','宋','宋诗','song-poetry','','[]','南朝笛竹蘄爲良，織成文簟瑠璃黄。',64,'全唐诗/poet.song.253000.json','["南朝笛竹蘄爲良，織成文簟瑠璃黄。", "舊物正爾冷如鐵，此君無奈寒如霜。", "山齋溽暑正六月，野人清夢迷三湘。", "卷舒隨分且藏節，作詩爲報劉中央。"]'),
('79c9f0e7-df92-4eec-84d9-4f82d68209db','君山','施冘','宋','宋诗','song-poetry','','[]','蒼虬橫距沙心泊，蜿蜒跨山矗一角。',64,'全唐诗/poet.song.253000.json','["蒼虬橫距沙心泊，蜿蜒跨山矗一角。", "松林忽撼洪濤風，雪浪排空奔電雹。", "長淮渺渺烟未收，英雄自老江自流。", "野人半醉不一語，豁見秋月升山頭。"]'),
('bfa0690b-7896-4063-b804-b3c0962e7529','君山','孫應威','宋','宋诗','song-poetry','','[]','君山盤結青雲梯，堂高更覺天象低。',128,'全唐诗/poet.song.253000.json','["君山盤結青雲梯，堂高更覺天象低。", "橫江萬頃瑩玻璃，蓬瀛勝概從端倪。", "幾欲收拾歸品題，分甘獨令倦攀躋。", "使君領客佇沙堤，指點淮浙分東西。", "神州三百塵埃迷，慨懷往昔重慘悽。", "我聞王師臨青齊，虜穴已掃庭已犁。", "志士毋必驚聞鷄，威儀喜見皆遺黎。", "當頌中興鎸浯溪，說秦彊楚不復稽。"]'),
('91fbad99-b5cd-47b7-89a7-9d74cb594fd1','君山','鄭奎','宋','宋诗','song-poetry','','[]','歲晚征顔嘆飄泊，日暮江城吹畫角。',64,'全唐诗/poet.song.253000.json','["歲晚征顔嘆飄泊，日暮江城吹畫角。", "倚欄無地吊興亡，松風落子驚飛雹。", "雲凝蒼梧愁不收，英雄淚灑涇渭流。", "眼前不着沙洲礙，望到中原天盡頭。"]'),
('656e0c5b-6214-41ed-a31d-422072ca7b7e','題大茅峰','王元復','宋','宋诗','song-poetry','','[]','五雲金紫湧仙宮，十八灣尖第一峰。',32,'全唐诗/poet.song.253000.json','["五雲金紫湧仙宮，十八灣尖第一峰。", "木石陰陰風颯颯，方池掬看小神龍。"]'),
('14586c0d-f014-4504-b56d-edbc6e10b532','題王子晉','童童','宋','宋诗','song-poetry','','[]','屣棄萬乘追浮丘，仙成駕鶴緱山頭。',64,'全唐诗/poet.song.253000.json','["屣棄萬乘追浮丘，仙成駕鶴緱山頭。", "碧桃千樹鎖金嗣，玉笙嘹喨天風秋。", "回眸下笑蜉蝣輩，蝸角爭戰污濁世。", "何當高氣凌雲霄，願隨環珮聯雲騎。"]'),
('1f8e8b84-ccb3-432c-86f9-c25ce157c8da','次韻武侯廟','汪應晦','宋','宋诗','song-poetry','','[]','武侯遺廟自丹青，霸業銷磨但故城。',64,'全唐诗/poet.song.253000.json','["武侯遺廟自丹青，霸業銷磨但故城。", "北魏中分盟血在，南陽三顧夙心明。", "君臣際會宜興漢，吳蜀相資失借荆。", "獨致瓣香思祀典，西山回首暮雲生。"]'),
('fbf7bd7c-0fea-4ad6-9f8a-ac14b2935ebb','宣城倅館','吳山','宋','宋诗','song-poetry','','[]','一年荒宿敬亭嵐，世路如今亦頗諳。',64,'全唐诗/poet.song.253000.json','["一年荒宿敬亭嵐，世路如今亦頗諳。", "鴉带夕陽來舍北，雁傳秋信到江南。", "王曾素志非溫飽，毛義微名爲旨甘。", "料得倚門凝望切，東風何日擁歸驂。"]'),
('d1c63855-5b0b-436c-b5a7-b7f12e1072b0','野泊對月有感','周尹潜','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','可憐江月亂中明，應識逋逃病客情。',64,'全唐诗/poet.song.253000.json','["可憐江月亂中明，應識逋逃病客情。", "斗柄闌干洞庭野，角聲淒斷岳陽城。", "酒添客淚愁仍濺，浪卷歸心暗自驚。", "欲問行朝舊消息，眼中盜賊尚縱橫。"]'),
('0dd8b4fe-4671-40d4-86b0-0dc7ee1450f5','題海慧寺畫水壁','釋德葵','宋','宋诗','song-poetry','','[]','君不見昔人十日畫一水，摩挲漥窿隨手起。',149,'全唐诗/poet.song.253000.json','["君不見昔人十日畫一水，摩挲漥窿隨手起。", "若非胸次吞江湖，安得波瀾來筆底。", "我來蕭寺觀奇蹤，壁間隠隠騰蛟龍。", "初疑乘風馭弱水，恍然坐我蓬萊宮。", "又疑去年八月秋水溢，陰風襲人廊廡濕。", "誰知畫者巧通神，董羽至今羞死筆。", "此水不是畫，一水一水勢相及。", "對此融神坐終日，後人雖畫畫不出。", "何如倒却毘陵華嚴壁，海慧北廊推第一。"]'),
('5eb41520-6a1c-4f05-8e29-d7f81b0ac4df','留春亭','釋德葵','宋','宋诗','song-poetry','','[]','聞說芳亭著意濃，留連美景一壺中。',64,'全唐诗/poet.song.253000.json','["聞說芳亭著意濃，留連美景一壺中。", "歌聲不放鶑聲老，酒面長陪花面紅。", "筍迸玉簪穿落日，柳拖金綫繫東風。", "時人盡道春歸去，疑是桃源路忽通。"]'),
('39d72651-84f3-4027-b216-e720d4647aba','精進閣','釋德葵','宋','宋诗','song-poetry','','[]','五月六月火雲蒸，家家納凉前後庭。',32,'全唐诗/poet.song.253000.json','["五月六月火雲蒸，家家納凉前後庭。", "樓頭四鼓五鼓急，閣上猶聞人誦經。"]'),
('b56b18e2-21df-45b0-acf6-cdda9316c93d','水心亭','饒道深','宋','宋诗','song-poetry','','[]','兩岸塵埃終不到，四簷風月冷無聲。',32,'全唐诗/poet.song.253000.json','["兩岸塵埃終不到，四簷風月冷無聲。", "路從碧樹陰中斷，人向紅蓮影裏行。"]'),
('03189f7a-40e9-4a60-8a86-3458fe5290a0','句','饒道深','宋','宋诗','song-poetry','','[]','落霞斷岸斜陽裏，萬里江天畫不成。',16,'全唐诗/poet.song.253000.json','["落霞斷岸斜陽裏，萬里江天畫不成。"]'),
('a74da130-e05f-49e5-9abb-b35966724863','宣聖墓','無名氏','宋','宋诗','song-poetry','','[]','靈光殿古生秋草，曲阜城荒噪晚鴉。',32,'全唐诗/poet.song.253000.json','["靈光殿古生秋草，曲阜城荒噪晚鴉。", "惟有孔林殘照裏，至今猶屬仲尼家。"]'),
('33a5cde4-f33e-489d-927f-d22b426f876a','句','無名氏','宋','宋诗','song-poetry','','[]','祖來産業分兄弟，身後詩書遺子孫。',16,'全唐诗/poet.song.253000.json','["祖來産業分兄弟，身後詩書遺子孫。"]'),
('e218de25-a9bd-47a5-af34-ee1e9899832b','鈐岡早行','鄧南秀','宋','宋诗','song-poetry','','[]','漁照滅不滅，水光空復空。',48,'全唐诗/poet.song.253000.json','["漁照滅不滅，水光空復空。", "疏鍾五更月，殘夢萬松風。", "沆瀣虛無外，凄清頃刻中。", "火輪欲飛動，灧灧紫霄東。"]'),
('31932454-e9fe-47f6-bfd5-3ae95169f5a3','椰子','趙升之','宋','宋诗','song-poetry','','[]','落蒂纍纍入海航，枯皮猶吐綠芽長。',68,'全唐诗/poet.song.253000.json','["落蒂纍纍入海航，枯皮猶吐綠芽長。", "金絲髪裹烏龍腦，白兔脂凝碧玉漿。", "未許分瓢飲{需酉靈}醁，且堪切肉配檳榔。", "當時曾掛將軍首，此說荒唐未可量。"]'),
('d87d5e30-1bec-4e8c-af47-c6f2005f460f','尊賢堂','陳正善','宋','宋诗','song-poetry','','[]','聞道騎鯨碧眼仙，黄柑手植尚依然。',64,'全唐诗/poet.song.253000.json','["聞道騎鯨碧眼仙，黄柑手植尚依然。", "人間俯仰更成古，天下聲名不計年。", "繭紙誰能收妙墨，雞林何用續遺編。", "使君爲創新堂事，若解尊賢即是賢。"]'),
('2721ffcc-d227-448e-931a-7143c526e55a','籌邊亭','黄嗣','宋','宋诗','song-poetry','','[]','誅茅壘石結新亭，退食籌邊答聖明。',32,'全唐诗/poet.song.253000.json','["誅茅壘石結新亭，退食籌邊答聖明。", "海外時康民訟簡，同官莫惜共論兵。"]'),
('6ab348f7-eac2-45f6-8ce5-98d10b550230','題醉翁亭','丁臣','宋','宋诗','song-poetry','','[]','山僧野老遠逢迎，指點清泉笑語同。',64,'全唐诗/poet.song.253000.json','["山僧野老遠逢迎，指點清泉笑語同。", "近日帝前樞軸老，舊來亭上醉吟翁。", "林巒自古名雖勝，事物因人地轉雄。", "從此州民增壯觀，峴山非獨有羊公。"]'),
('05b0dd76-4b2f-4e67-b9be-7b8120461a76','譏賈平章','無名氏','宋','宋诗','song-poetry','','[]','戎馬掀天動地來，襄陽城下哭聲哀。',32,'全唐诗/poet.song.253000.json','["戎馬掀天動地來，襄陽城下哭聲哀。", "平章束手全無策，却把科場惱秀才。"]'),
('379e3a6f-ff86-4ef6-8b04-bd3a634e700f','十七字詩','無名氏','宋','宋诗','song-poetry','','[]','駕幸景靈宮，諸生盡鞠躬。',21,'全唐诗/poet.song.253000.json','["駕幸景靈宮，諸生盡鞠躬。", "頭烏身上白，米蟲。"]'),
('0968cd1b-1500-437e-abca-67293cc034c3','到夔州','冉居常','宋','宋诗','song-poetry','','[]','縹緲飛樓壓舊城，年年來聽峽猿吟。',64,'全唐诗/poet.song.253000.json','["縹緲飛樓壓舊城，年年來聽峽猿吟。", "衣裳慣見秋風冷，夢寐常愁塞日陰。", "霜露園林千古事，波濤鷗鷺一生心。", "祗應庾信頻飄泊，正坐江關緣分深。"]'),
('8e559c58-39cb-4846-a23b-3a499e6f719b','夔州試院呈諸公  其一','冉居常','宋','宋诗','song-poetry','','[]','他年蟲篆老書生，謬向文闈預領衡。',64,'全唐诗/poet.song.253000.json','["他年蟲篆老書生，謬向文闈預領衡。", "敢道靈鼇嗟贔屭，祗愁洼馬賦崢嶸。", "舊傳錦樣心雖愧，新揀沙金眼自明。", "收拾美莊逃謗去，升沈脚跡任諸英。"]'),
('8b09f3a2-2342-4434-8f3a-4627ff30edd5','夔州試院呈諸公  其二','冉居常','宋','宋诗','song-poetry','','[]','粉袍切勿笑冬烘，且踏燒殘鼠尾蹤。',64,'全唐诗/poet.song.253000.json','["粉袍切勿笑冬烘，且踏燒殘鼠尾蹤。", "總是炎蒸同造榜，不妨衣鉢繼登庸。", "雲移白帝鵬霄近，月入清秋桂子濃。", "願得詞鋒倚天劍，借君雷雨化蛟龍。"]'),
('2d665feb-a959-453a-9c15-ad2cb0308c98','白帝廟','冉居常','宋','宋诗','song-poetry','','[]','西南割據幾何年，長託威靈灧澦前。',64,'全唐诗/poet.song.253000.json','["西南割據幾何年，長託威靈灧澦前。", "霸氣不隨天數盡，神祠猶壓地形偏。", "舟航歲晚方孤客，關塞山寒更莫煙。", "欲論興亡愁意緒，持杯寂寞酹山川。"]'),
('bda0b9e1-408e-4e3d-894b-49f42a372fad','上元竹枝歌和曾大卿  其一','冉居常','宋','宋诗','song-poetry','','[]','青春惱人思跰躚，女郎市酒趣數錢。',32,'全唐诗/poet.song.253000.json','["青春惱人思跰躚，女郎市酒趣數錢。", "不道翁家久留客，紅襠幔結賽鞦韆。"]'),
('14a28d62-d38c-4f63-9486-fc5663f96914','上元竹枝歌和曾大卿  其二','冉居常','宋','宋诗','song-poetry','','[]','學簫學鼓少年群，準擬春來奉使君。',32,'全唐诗/poet.song.253000.json','["學簫學鼓少年群，準擬春來奉使君。", "自向琱籠作行隊，安排好曲寫殷勤。"]'),
('5cb879cd-3ad3-410d-b944-344742aadf78','上元竹枝歌和曾大卿  其三','冉居常','宋','宋诗','song-poetry','','[]','珍珠絡結繡衣裳，家住江南山後鄉。',32,'全唐诗/poet.song.253000.json','["珍珠絡結繡衣裳，家住江南山後鄉。", "聞道使君重行樂，爭携腰鼓趁年光。"]'),
('1eaf397c-df84-48cc-a48e-b403c41af66f','次韻和漕司小紅翠亭  其一','劉士季','宋','宋诗','song-poetry','','[]','少陵遺蹟瀼西東，端的高齋在此中。',64,'全唐诗/poet.song.253000.json','["少陵遺蹟瀼西東，端的高齋在此中。", "今日花枝弄煙雨，前時蔬甲卧霜風。", "根株移取他山翠，跗萼輸來別圃紅。", "收拾陽春無盡藏，夔人端說兩詩翁。"]'),
('fd3803f1-e776-4490-acd0-63d500510ad5','次韻和漕司小紅翠亭  其二','劉士季','宋','宋诗','song-poetry','','[]','苑在中巴東復東，滿城春色一園中。',64,'全唐诗/poet.song.253000.json','["苑在中巴東復東，滿城春色一園中。", "休言小小鶑花界，也勝纖纖燕麥風。", "舞袖卷紗空映翠，晴窗磨鏡漫晞紅。", "葉成帷幄花成陣，壯觀詩壇矍鑠翁。"]'),
('91389412-cd45-4f8c-acc9-45de85dc4217','蘆臺峭帆亭','張德容','宋','宋诗','song-poetry','','[]','高秋客未還，何處望鄉關。',48,'全唐诗/poet.song.253000.json','["高秋客未還，何處望鄉關。", "喬宇蒼烟外，孤亭落照間。", "雨晴山覺近，潮滿水如閑。", "目斷峒陽路，歸雲不可攀。"]'),
('3e976f3d-ff1d-4e1f-9302-a1af9f071eed','漳州寫懷','呂信臣','宋','宋诗','song-poetry','','[]','秦川西去遠，不意過漳川。',48,'全唐诗/poet.song.253000.json','["秦川西去遠，不意過漳川。", "歸夢三千里，羈愁二十年。", "謀生空白髪，行路若青天。", "餘事休相問，相留只醉眠。"]'),
('eea373cf-7713-4a6c-a79c-adc11d05e70d','句','廖衡','宋','宋诗','song-poetry','','[]','淚多陳后愁離殿，浴出楊妃困倚闌。',16,'全唐诗/poet.song.253000.json','["淚多陳后愁離殿，浴出楊妃困倚闌。"]'),
('91f25647-64a0-4cba-9a61-788e016dcc48','題雲錦園','庾卜禮','宋','宋诗','song-poetry','','[]','我觀大瀛海，山與水相伴。',144,'全唐诗/poet.song.253000.json','["我觀大瀛海，山與水相伴。", "維茲山水麗，邈在西南畔。", "公如出岫雲，頃刻固已漫。", "倏爾轉晴空，化爲五色斕。", "三徑他山緝，萬里歸心斷。", "要從父老歸，不作兒女觀。", "蘇公金石心，坐閲歲時換。", "來赴林泉期，更覺雲錦煥。", "五采弄珠璣，八章誦雲漢。", "向來古使星，久未視龜篆。", "心貪汗漫遊，行無麋鹿亂。", "快哉天下樂，豈以寸心玩。"]'),
('9136d2a3-139e-4ef8-91ec-dc36ed8e20c6','句','劉弼','宋','宋诗','song-poetry','','[]','灘聲來席上，亭影落溪中。',12,'全唐诗/poet.song.253000.json','["灘聲來席上，亭影落溪中。"]'),
('395eee8f-3269-4d2b-918b-4d1d160d6003','題東流菊江亭','廖𠵨','宋','宋诗','song-poetry','','[]','陶公非是愛黄花，花與陶公本一家。',64,'全唐诗/poet.song.253000.json','["陶公非是愛黄花，花與陶公本一家。", "懶向春風競顔色，自甘秋露綴英華。", "寧知發早還先萎，到底開遲反耐賒。", "物理細推元不異，銜盃何惜月西斜。"]'),
('5fbfba70-1d10-4469-8d5e-f42c07813267','題順安樓','房芝蘭','宋','宋诗','song-poetry','','[]','窗含野色入平吞，極目漁樵江上村。',64,'全唐诗/poet.song.253000.json','["窗含野色入平吞，極目漁樵江上村。", "流出異香花堰水，放開老翠葉山雲。", "竹邊僧寺鷗沙繞，柳外人家驛路分。", "掛月參天蟠地脈，門前雙樹幾斜曛。"]'),
('173f2308-1458-4667-a556-864b2b867ce8','題梵天寺泉','房芝蘭','宋','宋诗','song-poetry','','[]','雲根流出瀉寒聲，冷沁禪關竹樹清。',64,'全唐诗/poet.song.253000.json','["雲根流出瀉寒聲，冷沁禪關竹樹清。", "氣泄化胎飛寶錫，巖開冰谷愧塵纓。", "鶴林月浪秋常浸，龍海波濤夜忽驚。", "分我一瓢甦旱歲，化爲霖雨澤蒼生。"]'),
('8685d7ca-9403-4363-8a9d-a785ad4cbc8b','梵天寺','房芝蘭','宋','宋诗','song-poetry','','[]','門前流水碧粼粼，禪定僧閑化復淳。',64,'全唐诗/poet.song.253000.json','["門前流水碧粼粼，禪定僧閑化復淳。", "攪夢半因詩作祟，破寒全藉酒生春。", "休教一切有爲法，誤着三生自在身。", "拂袖重來經五載，梵雲飛雨灑儒巾。"]'),
('8e81ca34-0872-4b82-ac97-5606e1634863','句  其一','何英','宋','宋诗','song-poetry','','[]','羊腸有路地多險，馬脊無人天一隅。',16,'全唐诗/poet.song.253000.json','["羊腸有路地多險，馬脊無人天一隅。"]'),
('3c927a82-3ba5-4f3d-b293-6b5e9ee44035','句  其二','何英','宋','宋诗','song-poetry','','[]','自從二水分新舊，南北烟波各自愁。',16,'全唐诗/poet.song.253000.json','["自從二水分新舊，南北烟波各自愁。"]'),
('e98686b6-a67f-44f3-afc4-8d465557cdb4','淵明祠  其一','顧祿','宋','宋诗','song-poetry','','[]','黄閣彤扉盡宋臣，歸來松菊伴閑身。',32,'全唐诗/poet.song.253000.json','["黄閣彤扉盡宋臣，歸來松菊伴閑身。", "舉頭誰識悠然意，只有南山是故人。"]'),
('0c4f5bd8-1242-4069-b6e9-310a9efce3a7','淵明祠  其二','顧祿','宋','宋诗','song-poetry','','[]','葛巾漉酒艷流霞，長向東籬醉菊花。',32,'全唐诗/poet.song.253000.json','["葛巾漉酒艷流霞，長向東籬醉菊花。", "不分宋公移晉祚，只將甲子紀年華。"]'),
('afae6278-338f-46f8-a3c2-42b1c79fe18a','金山','饒方','宋','宋诗','song-poetry','','[]','地將靈氣吐林巒，至寶曾淘瓦礫間。',32,'全唐诗/poet.song.253000.json','["地將靈氣吐林巒，至寶曾淘瓦礫間。", "若把圖經重校定，此山宜喚作金山。"]'),
('b9957110-b840-4838-96b8-79d9b74751c8','祝融峰','馮濬','宋','宋诗','song-poetry','','[]','手執筇敲結佩刀，直趨危頂一峰豪。',64,'全唐诗/poet.song.253000.json','["手執筇敲結佩刀，直趨危頂一峰豪。", "回頭朝市聲聲遠，接武烟霞步步高。", "天上召雷池水漲，人間禱雨穴風號。", "九千七百三十丈，翠壓江湖幾點濤。"]'),
('f3f6bdb4-bf10-4d9c-ac57-34284fc15ef8','憶秦人洞','張翠屏','宋','宋诗','song-poetry','','[]','溪上桃花無數開，花間秋水綠於苔。',64,'全唐诗/poet.song.253000.json','["溪上桃花無數開，花間秋水綠於苔。", "不因漁父尋源入，爭識仙家避世來。", "翠雨連雲流玉洞，丹霞護日抱瑶臺。", "幔亭亦有紅橋約，問我京華幾日回。"]'),
('a2bc8010-95f6-4f87-9d2d-f6789fd007f8','桃源','古汴高士','宋','宋诗','song-poetry','','[]','山前溪是當時水，源上桃非舊日花。',32,'全唐诗/poet.song.253000.json','["山前溪是當時水，源上桃非舊日花。", "多是漁郎露消息，洞門從此鎖烟霞。"]'),
('7b7e68fc-fd90-424d-9ba9-67c827955af8','楚山春曉','古汴高士','宋','宋诗','song-poetry','','[]','霧散雲收宿雨乾，秦桃落盡曉風寒。',32,'全唐诗/poet.song.253000.json','["霧散雲收宿雨乾，秦桃落盡曉風寒。", "晴山四望天開畫，啼鳥一聲人倚欄。"]'),
('d62ac720-41b7-43e2-aa9a-2e5168c6b952','潼坊晚渡','古汴高士','宋','宋诗','song-poetry','','[]','日落山前水漲時，有人拍掌笑嘻嘻。',32,'全唐诗/poet.song.253000.json','["日落山前水漲時，有人拍掌笑嘻嘻。", "篙師只管需把手，載過神仙不自知。"]'),
('2a9ba86e-85ed-400e-83da-6f2e94cd836b','淥羅晴晝','古汴高士','宋','宋诗','song-poetry','','[]','第一巖前景若何，江流瀲灧漾晴羅。',32,'全唐诗/poet.song.253000.json','["第一巖前景若何，江流瀲灧漾晴羅。", "遊仙道士無縈繫，也共白雲棲一窩。"]'),
('1f74804e-bbfc-4e30-a928-26eef39f17fb','潯陽古寺','古汴高士','宋','宋诗','song-poetry','','[]','潯陽古寺久荒凉，倒柱頹梁卧夕陽。',32,'全唐诗/poet.song.253000.json','["潯陽古寺久荒凉，倒柱頹梁卧夕陽。", "一盞佛燈猶未滅，霽天雲淡月華光。"]'),
('6c1c3756-7741-4485-8afb-9c18f9e39294','白馬雪濤','古汴高士','宋','宋诗','song-poetry','','[]','層瀾疊浪勢轟雷，怒雨號風湧雪堆。',32,'全唐诗/poet.song.253000.json','["層瀾疊浪勢轟雷，怒雨號風湧雪堆。", "半夜四天雲墨黑，恍疑白馬闖江來。"]'),
('5483bae1-8959-421c-818b-1a07bdcfc96e','煉丹臺','古汴高士','宋','宋诗','song-poetry','','[]','洞角丹砂吐錦雲，龜毛鉛彩瑞氤氳。',32,'全唐诗/poet.song.253000.json','["洞角丹砂吐錦雲，龜毛鉛彩瑞氤氳。", "我來收入縣胎鼎，煉到洪濛未剖分。"]'),
('03267d84-b830-4d9a-8414-cb80831b2fcc','懷霍山','藍喬','宋','宋诗','song-poetry','','[]','太乙峰前是我家，滿床書史足生涯。',32,'全唐诗/poet.song.253000.json','["太乙峰前是我家，滿床書史足生涯。", "春深带酒不歸去，老却碧桃無限花。"]'),
('dbf7604a-fbd2-485c-a2ed-99b37d9faf7a','題霍山巖','藍喬','宋','宋诗','song-poetry','','[]','人間富貴塵如海，虛度春三二月花。',32,'全唐诗/poet.song.253000.json','["人間富貴塵如海，虛度春三二月花。", "八表烟霞總一家，藍喬到此作生涯。"]'),
('0cdae336-5ea2-4a24-bff8-7e16123f8d71','君子巖','林應隆','宋','宋诗','song-poetry','','[]','石樓千丈鎖山南，青壁盤桓下有巖。',32,'全唐诗/poet.song.253000.json','["石樓千丈鎖山南，青壁盤桓下有巖。", "知是何年隠君子，清名留得在烟嵐。"]'),
('4eda6b03-2920-4f6a-ace9-ec1a812c2a7c','棲禪寺','崔放之','宋','宋诗','song-poetry','','[]','自從白馬馱經始，寶地紺園知有幾。',128,'全唐诗/poet.song.253000.json','["自從白馬馱經始，寶地紺園知有幾。", "今見逍遥巖洞深，啼猿塢接棲禪寺。", "嵯峨樓閣東西橋，掬水聞香景趣饒。", "講經雲外天花落，卓錫林邊暑氣消。", "塵埃不到松關口，僧老漸隨松影瘦。", "誰知好事眼能青，借與詩人信宿逗。", "山高地僻月空圓，晨鍾暮鼓驚龍眠。", "看來懶把無生學，長笑一聲歸釣船。"]'),
('d9242210-03b5-4c8f-b18b-5dca1121f8af','飛雲頂','葛某','宋','宋诗','song-poetry','','[]','飛雲頂上閣闌干，夜半南溟出玉盤。',32,'全唐诗/poet.song.253000.json','["飛雲頂上閣闌干，夜半南溟出玉盤。", "捲起水簾三百尺，松風吹度鐵橋寒。"]'),
('78289236-85c0-4850-986a-79ae729f25c3','寄寶應丘大夫攽','劉華','宋','宋诗','song-poetry','','[]','制閫今元帥，男邦舊大夫。',48,'全唐诗/poet.song.253000.json','["制閫今元帥，男邦舊大夫。", "受成無弊事，直上有夷塗。", "赤縣圖新入，蒼生喘欲蘇。", "底須勞戰士，城築守淮隅。"]'),
('271be322-d16b-4680-8c16-e3d17807ebed','芹溪八詠  其一','葉善夫','宋','宋诗','song-poetry','','[]','何人辟穀硯山隈，洞府藤蘿鎖不開。',32,'全唐诗/poet.song.253000.json','["何人辟穀硯山隈，洞府藤蘿鎖不開。", "煉就金丹乘鶴去，藥爐煙冷未歸來。"]'),
('392811dd-d292-4e69-b56e-c844c1dcfc37','芹溪八詠  其二','葉善夫','宋','宋诗','song-poetry','','[]','月光如水水連天，萬頃玻璃浸碧淵。',32,'全唐诗/poet.song.253000.json','["月光如水水連天，萬頃玻璃浸碧淵。", "一顆驪珠收不去，幾回驚起卧龍眠。"]'),
('4822b155-8812-4828-a7a7-75d988f6aea7','芹溪八詠  其三','葉善夫','宋','宋诗','song-poetry','','[]','雲谷山高列畫屏，晚來盡對更多情。',32,'全唐诗/poet.song.253000.json','["雲谷山高列畫屏，晚來盡對更多情。", "煙凝紫翠斜陽裏，一幅丹青寫不成。"]'),
('b7e8b51f-8554-41cd-8f7c-af2313400373','芹溪八詠  其四','葉善夫','宋','宋诗','song-poetry','','[]','芹溪處士古人風，寶劍塵埋未化龍。',32,'全唐诗/poet.song.253000.json','["芹溪處士古人風，寶劍塵埋未化龍。", "舊隠至今名不朽，扁題元出紫陽翁。"]'),
('8da42d25-55cb-4576-a518-cff14d2a5740','芹溪八詠  其五','葉善夫','宋','宋诗','song-poetry','','[]','高人棲隠向山林，林壑幽清絕俗塵。',32,'全唐诗/poet.song.253000.json','["高人棲隠向山林，林壑幽清絕俗塵。", "當日武陵人已老，誰知猶有種桃人。"]'),
('44735d65-8393-424d-8352-434fb2874950','芹溪八詠  其六','葉善夫','宋','宋诗','song-poetry','','[]','登樓眺望雪晴天，銀作高山玉作田。',32,'全唐诗/poet.song.253000.json','["登樓眺望雪晴天，銀作高山玉作田。", "最好夜深明月上，素娥滕六鬬嬋娟。"]'),
('38ccc613-2277-401d-aef4-ceb9193c610b','芹溪八詠  其七','葉善夫','宋','宋诗','song-poetry','','[]','數盡寒鴉日已昏，疏鍾隠隠隔林聞。',32,'全唐诗/poet.song.253000.json','["數盡寒鴉日已昏，疏鍾隠隠隔林聞。", "僧歸林下柴門靜，聲逐前村一片雲。"]'),
('01205834-3e33-4045-89d6-c002c8f2c3ea','芹溪八詠  其八','葉善夫','宋','宋诗','song-poetry','','[]','筆架三峰插碧虛，午來倒影落平湖。',32,'全唐诗/poet.song.253000.json','["筆架三峰插碧虛，午來倒影落平湖。", "凭高最好供吟笑，宜入王維畫裏圖。"]'),
('9e5cb37e-adb3-432d-b517-51945cc1acda','支提禪寺','王平國','宋','宋诗','song-poetry','','[]','群峰翠擁古禪關，夾道松篁五月寒。',32,'全唐诗/poet.song.253000.json','["群峰翠擁古禪關，夾道松篁五月寒。", "欲識天冠真隠處，白雲深鎖紫金壇。"]'),
('7a1b068e-5911-416a-83ed-01fb25ede741','東路赤嶺鋪','孫蕃','宋','宋诗','song-poetry','','[]','官路日長蝴蝶飛，豫章花落點征衣。',32,'全唐诗/poet.song.253000.json','["官路日長蝴蝶飛，豫章花落點征衣。", "江南江北牡丹過，腸斷春歸客未歸。"]'),
('3e715702-ce25-44dc-b36d-ae961ead1fb5','詠瑞粟  其一','周遇聖','宋','宋诗','song-poetry','','[]','瑞出雙蓮與九芝，何如瑞粟見明時。',64,'全唐诗/poet.song.253000.json','["瑞出雙蓮與九芝，何如瑞粟見明時。", "一根異彼禾同穎，四穗多於麥兩岐。", "紀載簡編前未有，獻諸郡國事非欺。", "三年宰邑書成績，悠久難磨頌德碑。"]'),
('6e06b1af-2411-4cbd-b4a1-349121f319a5','詠瑞粟  其二','周遇聖','宋','宋诗','song-poetry','','[]','淳居萬山巔，土瘠稀良田。',198,'全唐诗/poet.song.253000.json','["淳居萬山巔，土瘠稀良田。", "豐歉繫饑飽，民命懸於天。", "人憂庚子歉，我見爲豐年。", "蠶登百穀熟，箱萬倉盈千。", "異哉粟四穗，一幹生南阡。", "豈無連理木，亦有雙華蓮。", "維茲孕瑞粟，庶補民艱鮮。", "嘉生本協氣，此事非偶然。", "竊聞野老說，守令仁且賢。", "官清簡案牘，刑省空扉圜。", "農耕士力學，工肆商充廛。", "午鷄桑樹鳴，夜犬花村眠。", "君不見漁陽歌秀麥，善政青史編。", "又不見中牟書嘉禾，德化今古傳。", "猗歟際聖代，奇祥呈八埏。", "願言叫閶闔，入奏冕旒前。"]'),
('82165033-0fc2-4b21-b6ff-d9503af80382','題方仙翁點易圖','陸宗亮','宋','宋诗','song-poetry','','[]','雲鎖瑶扉童未起，樹摇凉露鶴初還。',32,'全唐诗/poet.song.253000.json','["雲鎖瑶扉童未起，樹摇凉露鶴初還。", "曲肱道士清溪水，心在羲皇未畫前。"]'),
('f8b2550b-1cca-44a0-b64d-0edb56548a4a','集句和太白水西韻','管向','宋','宋诗','song-poetry','','[]','絕景西溪寺，分明見城郭。',96,'全唐诗/poet.song.253000.json','["絕景西溪寺，分明見城郭。", "綠水纈清波，青苔照朱閣。", "石逕無纖塵，楊花共紛泊。", "香剎中天起，野泉當案落。", "蛇龍蟠古根，院竹翻夏籜。", "李侯金閨彥，頗多宛陵作。", "韻與金石諧，遺聲寄寥廓。", "何人繼其蹤，佳游屢前諾。"]'),
('8580a31a-5aa5-4fa8-b00a-b0ceeae2e5af','延真秋屏軒','張叔敏','宋','宋诗','song-poetry','','[]','鳥回山色隠如城，碧落人歸依舊青。',32,'全唐诗/poet.song.253000.json','["鳥回山色隠如城，碧落人歸依舊青。", "好向中間安一榻，何須更畫遶牀屏。"]'),
('14ef5c36-f525-44e1-94bb-acb3c24c7309','張桓侯廟','黎登','宋','宋诗','song-poetry','','[]','涿鹿雄威衮繡鄉，早從昭烈起樓桑。',64,'全唐诗/poet.song.253000.json','["涿鹿雄威衮繡鄉，早從昭烈起樓桑。", "眼空塞北萬夫特，名在巴西千古香。", "將蜀若教星不隕，吞吳未信策非良。", "興劉不盡英雄志，太息無由問彼蒼。"]'),
('cd21d45d-db27-4a9b-ba5f-0193bd15649b','宿護法寺','張勳','宋','宋诗','song-poetry','','[]','亂草織斜陽，天風結曉霜。',48,'全唐诗/poet.song.253000.json','["亂草織斜陽，天風結曉霜。", "摇鞭追馬足，投宿問僧房。", "望眼揮清淚，愁雲罩故疆。", "客帆更無數，不見祖生航。"]'),
('af9e047c-e9a4-456d-893c-1a4cab915d88','題太白五松書堂','阜民','宋','宋诗','song-poetry','','[]','江氛朝暮半晴陰，紺宇飛甍接翠岑。',64,'全唐诗/poet.song.253000.json','["江氛朝暮半晴陰，紺宇飛甍接翠岑。", "手摘匏瓜曾未遍，身從鷗鷺得相尋。", "千年舞袖雲崖冷，幾度桃花春水深。", "猶有門前舊題句，松風萬壑老龍吟。"]'),
('8f79ec81-55f3-4368-b197-a06e47192521','靈巖紀勝','王經','宋','宋诗','song-poetry','','[]','靈巖奇絕俯林埛，梯上層巒步一停。',64,'全唐诗/poet.song.253000.json','["靈巖奇絕俯林埛，梯上層巒步一停。", "朔意難欺芳樹色，佛頭濃抹遠山青。", "半泓藥水瘳民疾，兩硤雲峰展翠屏。", "壯我客懷瞻劍閣，寒烏飛處見蒼冥。"]'),
('0f96ad7c-1949-4287-a1fa-7db6c162d193','遊靈巖','王龍學','宋','宋诗','song-poetry','','[]','古寺山埛遠，蹻攀一逕斜。',48,'全唐诗/poet.song.253000.json','["古寺山埛遠，蹻攀一逕斜。", "洞深留碧靄，溪急蕩晴沙。", "殿接巖松影，堂鄰野客家。", "謁僧詢世事，無語指燈花。"]'),
('3e23da48-b5c7-49ca-b21a-622a35bcb3d1','靈巖感懷','盧剛','宋','宋诗','song-poetry','','[]','摩挲石刻拜方興，誤國從初恨老秦。',64,'全唐诗/poet.song.253000.json','["摩挲石刻拜方興，誤國從初恨老秦。", "十六州歸仍遺虜，百餘年事語誰人。", "出師表在今如始，墮泪碑存舊似新。", "江水江花豈終極，風光一任轉青春。"]'),
('52a458bd-ea8e-4a52-b4d8-d8956e91d1e1','月珠寺明月樓  其一','程少逸','宋','宋诗','song-poetry','','[]','秀爽盤空翠不收，陰晴俱好更宜秋。',32,'全唐诗/poet.song.253000.json','["秀爽盤空翠不收，陰晴俱好更宜秋。", "滄江也愛樓頭月，故抱青山月樣流。"]'),
('1130c6d3-6162-4f42-ade6-e2e0ea0de8d6','月珠寺明月樓  其二','程少逸','宋','宋诗','song-poetry','','[]','樓面環開紫翠屏，峨眉瓦屋共前楹。',32,'全唐诗/poet.song.253000.json','["樓面環開紫翠屏，峨眉瓦屋共前楹。", "莫嫌鷗鷺時來去，正要微雲滓太清。"]'),
('2f46f937-22a6-4e10-805c-a825dfd9afe2','月珠寺明月樓  其三','程少逸','宋','宋诗','song-poetry','','[]','江上群峰潑黛濃，水村烟渚夕陽紅。',32,'全唐诗/poet.song.253000.json','["江上群峰潑黛濃，水村烟渚夕陽紅。", "一聲啼鳥催耕去，何處龍歸急雨中。"]'),
('a0e46797-ebcb-4316-a1e5-d99b6bffd887','月珠寺明月樓  其四','程少逸','宋','宋诗','song-poetry','','[]','雲坼崖分邃景藏，更煩清樾護幽芳。',64,'全唐诗/poet.song.253000.json','["雲坼崖分邃景藏，更煩清樾護幽芳。", "林深草木四時潤，日薄窗櫺多半凉。", "睡過午陰茶乳白，醉餘霜檜蘚花蒼。", "兩旬來結僧房夏，贏得他年戒臘長。"]'),
('95cba81a-8057-4dac-9c5e-c0f7bea06891','月珠寺明月樓  其五','程少逸','宋','宋诗','song-poetry','','[]','風菜差差午暑清，眼明茶碗打花輕。',32,'全唐诗/poet.song.253000.json','["風菜差差午暑清，眼明茶碗打花輕。", "蒲團小歇誰驚起，簌簌楠花落雨聲。"]'),
('56a74ebf-f33a-4a96-8411-ced8d8ee5d48','月珠寺明月樓  其六','程少逸','宋','宋诗','song-poetry','','[]','飲罷茶甌未有言，各歸窗底默參禪。',32,'全唐诗/poet.song.253000.json','["飲罷茶甌未有言，各歸窗底默參禪。", "僧房睡息齁齁起，倒著繩床我亦眠。"]'),
('0346e993-3bf0-4c19-a824-99a62bd9c1df','月珠寺明月樓  其七','程少逸','宋','宋诗','song-poetry','','[]','秀壑陰崖列翠微，光風瑶草日暉暉。',32,'全唐诗/poet.song.253000.json','["秀壑陰崖列翠微，光風瑶草日暉暉。", "林深不放棋聲出，怕觸歸雲作雨飛。"]'),
('279363bc-3b17-4a97-88e8-7a04955e741c','慈航寺','謝興','宋','宋诗','song-poetry','','[]','渺渺烟波一釣舟，幾行歸雁白蘋洲。',32,'全唐诗/poet.song.253000.json','["渺渺烟波一釣舟，幾行歸雁白蘋洲。", "郭熙眼力今誰健，寫出江天烟雨秋。"]'),
('817af323-8602-4aef-9478-be5e4f4313b6','謁闕里  其一','高詡','宋','宋诗','song-poetry','','[]','帝王而下幾興亡，銷盡繁華作戰場。',32,'全唐诗/poet.song.253000.json','["帝王而下幾興亡，銷盡繁華作戰場。", "惟有東家詩禮在，子孫萬古讀書堂。"]'),
('6a8723ff-e6ce-43df-8ca3-ec530c351dac','謁闕里  其二','高詡','宋','宋诗','song-poetry','','[]','六經不幸火於秦，日月曾何礙片雲。',32,'全唐诗/poet.song.253000.json','["六經不幸火於秦，日月曾何礙片雲。", "用舍從來關治亂，皇天本不喪斯文。"]'),
('9dd522d6-e198-44c1-a506-7b161b1d90ba','廣福寺偶題','釋昭輯','宋','宋诗','song-poetry','','[]','涓涓碧水細通池，小雨廉纖未作泥。',32,'全唐诗/poet.song.253000.json','["涓涓碧水細通池，小雨廉纖未作泥。", "深炷爐烟濃著火，何須騎馬聽朝鷄。"]'),
('28fc7755-131b-4444-85ac-e5bee3194b3a','句','馮戴','宋','宋诗','song-poetry','','[]','荆軻一去不復返，易水東流無盡期。',16,'全唐诗/poet.song.253000.json','["荆軻一去不復返，易水東流無盡期。"]'),
('401ed27d-4402-4d73-a4b9-53b255ecd1ac','初一夜月詩','蘇福','宋','宋诗','song-poetry','','[]','氣朔盈虛又一初，嫦娥應事半分無。',32,'全唐诗/poet.song.253000.json','["氣朔盈虛又一初，嫦娥應事半分無。", "都於無處分明有，恰似先天太極圖。"]'),
('32c3823c-e72b-48e8-8a66-ad2072284f67','送蔣時舉歸養','黄無悔','宋','宋诗','song-poetry','','[]','秋風起兮白雲飛，南國遠兮心欲歸。',32,'全唐诗/poet.song.253000.json','["秋風起兮白雲飛，南國遠兮心欲歸。", "歸心切兮親庭闈，復相見兮在何時。"]'),
('6c8d78fa-2632-44fb-9a46-c5e8793f60c5','句','狄燠','宋','宋诗','song-poetry','','[]','翠色折不盡，離亭生更多。',12,'全唐诗/poet.song.253000.json','["翠色折不盡，離亭生更多。"]'),
('5c8629af-5210-4c8d-8d4f-dbbcb8e37d43','遊碧沼勝居','林杜娘','宋','宋诗','song-poetry','','[]','幽谷泉聲冷，鳥啼僧定深。',48,'全唐诗/poet.song.253000.json','["幽谷泉聲冷，鳥啼僧定深。", "好花叢古砌，寒瀑發高岑。", "遊客陸鴻漸，居人支道林。", "欲歸青嶂去，臨去復沈吟。"]'),
('1a451cd3-5e19-4358-9534-5660d482d63b','寄鞋襪','士人妻','宋','宋诗','song-poetry','','[]','細襪宮鞋巧樣新，殷勤寄語讀書人。',32,'全唐诗/poet.song.253000.json','["細襪宮鞋巧樣新，殷勤寄語讀書人。", "好將穩步青雲上，莫向平康漫惹塵。"]'),
('7f36f499-a46c-4487-93a3-b482f1110618','閨怨','賈蓬萊','宋','宋诗','song-poetry','','[]','露顆珠團團，冰肌玉釧寒。',48,'全唐诗/poet.song.253000.json','["露顆珠團團，冰肌玉釧寒。", "杏梁棲隻燕，菱鏡掩孤鸞。", "殘樹枯黄遍，圓荷濕翠乾。", "繡簾生色畫，窗下带羞看。"]'),
('d6fb0223-4b7b-4985-8975-f4cb42d1f72e','春曉','賈蓬萊','宋','宋诗','song-poetry','','[]','方池水影薄，曲檻鳥聲嬌。',48,'全唐诗/poet.song.253000.json','["方池水影薄，曲檻鳥聲嬌。", "鸞鏡紅綿冷，蛾眉翠黛消。", "冶容舒嫩萼，幽思結柔條。", "纖指收花露，輕將雪粉調。"]'),
('baa3fc7f-c365-4cb0-96be-f689d73ad8b6','秋夜','賈蓬萊','宋','宋诗','song-poetry','','[]','幽蘭露華重，羅幌凉風動。',48,'全唐诗/poet.song.253000.json','["幽蘭露華重，羅幌凉風動。", "木匣掩香紈，繡衾誰與共。", "螢影度疏簾，獸爐寥寥烟。", "銀缸芳焰滅，自脫翠花鈿。"]'),
('8b9a5216-250a-4667-8808-37f0035013b0','謝姊惠鞋','賈蓬萊','宋','宋诗','song-poetry','','[]','蓮瓣娟娟遠寄將，繡羅猶带指尖香。',32,'全唐诗/poet.song.253000.json','["蓮瓣娟娟遠寄將，繡羅猶带指尖香。", "弓彎著上無行處，獨立花陰看雁行。"]'),
('7d95c0f4-85b1-4ce7-82b5-4a7769d44c31','咏蝶','賈蓬萊','宋','宋诗','song-poetry','','[]','薄翅凝香粉，新衣染媚黄。',24,'全唐诗/poet.song.253000.json','["薄翅凝香粉，新衣染媚黄。", "風流誰得似，兩兩宿花房。"]'),
('403059ed-3a8d-4872-bba6-1f778c05cc15','閨情','賈蓬萊','宋','宋诗','song-poetry','','[]','燕子南來雁北飛，遠人何事竟忘歸。',64,'全唐诗/poet.song.253000.json','["燕子南來雁北飛，遠人何事竟忘歸。", "一腔心病難形口，萬斛愁情盡屬眉。", "試掠金釵臨曉鏡，潜垂玉筯漬春衣。", "鄰姬莫問容憔悴，只有西窗夜月知。"]'),
('7c6625e3-bfa3-4267-b8d4-c81117cc4a65','畫緋桃題詩','賈蓬萊','宋','宋诗','song-poetry','','[]','朱砂顔色瓣重臺，曾是劉郎舊看來。',32,'全唐诗/poet.song.253000.json','["朱砂顔色瓣重臺，曾是劉郎舊看來。", "只好天台雲裏種，莫教移近俗人栽。"]'),
('901173d8-efa5-44d3-b648-23eb15a438cf','述懷','梁意娘','宋','宋诗','song-poetry','','[]','蹤跡浮萍落五湖，一番相別一番疏。',32,'全唐诗/poet.song.253000.json','["蹤跡浮萍落五湖，一番相別一番疏。", "不知此去從何處，還許春風得見無。"]'),
('7dabe1e7-df39-4f7d-883e-45c24601e61c','詩一首','于本大','宋','宋诗','song-poetry','','[]','自從明府升仙後，出入塵寰直至今。',32,'全唐诗/poet.song.253000.json','["自從明府升仙後，出入塵寰直至今。", "不是藏名混時候，賣柴沽酒貴無心。"]'),
('21cc2b18-a152-4840-8bfb-babfc2dc1839','詩一首','于本大妻','宋','宋诗','song-poetry','','[]','醉舞狂歌踏落花，綠羅裙带有丹砂。',32,'全唐诗/poet.song.253000.json','["醉舞狂歌踏落花，綠羅裙带有丹砂。", "往來城市買山藥，那個西山是我家。"]'),
('da6bed9e-79f1-4c38-81d9-3476e1b7b9db','題壁','華春娘','宋','宋诗','song-poetry','','[]','燕子樓中燕子飛，芹泥一點悞沾衣。',32,'全唐诗/poet.song.253000.json','["燕子樓中燕子飛，芹泥一點悞沾衣。", "主人頻起嗔嫌意，垂下珠簾不放歸。"]'),
('b37d967e-1ea9-400f-93df-5641186f054d','寄華春娘','徐君亮','宋','宋诗','song-poetry','','[]','自從瞥見如花面，曉夜相思腸欲斷。',32,'全唐诗/poet.song.253000.json','["自從瞥見如花面，曉夜相思腸欲斷。", "分明咫尺遠如天，何似同心作方便。"]'),
('ab3b370d-c39b-4913-8485-d77c051f144e','張公洞','蔡中道','宋','宋诗','song-poetry','','[]','天上騾蹤竟不迴，洞門深閉密封苔。',64,'全唐诗/poet.song.253000.json','["天上騾蹤竟不迴，洞門深閉密封苔。", "神光夜燭燒丹竈，淑氣晴薰講易臺。", "瑶草春肥仙去遠，紫芝雲暖鶴歸來。", "清游喜挾三茅客，杖履凌空霧雨開。"]'),
('1eee0965-e3f5-43d6-8b4b-80d6feb07c75','題真源宮','方千里','宋','宋诗','song-poetry','','[]','萬歲丹霞府，千函蕊笈書。',48,'全唐诗/poet.song.253000.json','["萬歲丹霞府，千函蕊笈書。", "時時瞻絳節，往往下雲車。", "近與剛風接，高連上帝居。", "登前望南岳，清蹕徹空虛。"]'),
('23f033fd-48ac-47dc-9689-763624d2f9ec','楊休烈村居','馬定遠','宋','宋诗','song-poetry','','[]','籬落牽牛放晚花，西風吹葉滿人家。',32,'全唐诗/poet.song.253000.json','["籬落牽牛放晚花，西風吹葉滿人家。", "閉門久雨青苔滑，時見鴛鴦下白沙。"]'),
('4e81f91d-5492-46a4-8922-7da757ed9994','郢州城西','馬定遠','宋','宋诗','song-poetry','','[]','秋江白水浪花粗，墟落人歸鳥自呼。',32,'全唐诗/poet.song.253000.json','["秋江白水浪花粗，墟落人歸鳥自呼。", "新月高城三百雉，角聲吹徹小單于。"]'),
('af08afc2-16e6-4344-a735-1a4057f5a866','村居','馬定遠','宋','宋诗','song-poetry','','[]','溪頭梅是去年花，閒月初長竹逕斜。',32,'全唐诗/poet.song.253000.json','["溪頭梅是去年花，閒月初長竹逕斜。", "向晚孤烟三十里，不知樵唱落誰家。"]'),
('86b78bed-c9b2-47a6-80a2-7f1bcb67453d','秋日書事','馬定遠','宋','宋诗','song-poetry','','[]','井邊薏苡吐秋珠，舍下瓜區雜芋區。',32,'全唐诗/poet.song.253000.json','["井邊薏苡吐秋珠，舍下瓜區雜芋區。", "世道未夷聊小隠，不須辛苦著潜夫。"]'),
('b2761f9b-848c-411d-86e6-698f86d5de76','古離別','夏之中','宋','宋诗','song-poetry','','[]','郎上孤舟妾上樓，闌干未倚淚先流。',32,'全唐诗/poet.song.253000.json','["郎上孤舟妾上樓，闌干未倚淚先流。", "片帆漸遠郎回首，一種相思兩處愁。"]'),
('6c8943fa-3a2d-48af-8600-a2bb177e39f2','設醮靈仙觀','張仲威','宋','宋诗','song-poetry','','[]','瑞氣葱葱雨露邊，璧門金闕倚層巔。',64,'全唐诗/poet.song.253000.json','["瑞氣葱葱雨露邊，璧門金闕倚層巔。", "青霓絳節嚴中夜，綠蓋丹輿會九天。", "香染舊泥封寶洞，聲傳鳴鶴湛靈泉。", "分明步入烟霄上，何必餐霞駐少年。"]'),
('e48f9b17-2338-4e19-ade5-3e6a49402a5a','秋懷','路忱','宋','宋诗','song-poetry','','[]','落日留虛壁，秋風急戍樓。',48,'全唐诗/poet.song.253000.json','["落日留虛壁，秋風急戍樓。", "高歌鬼神夜，揮涕虎狼秋。", "豪貴少青眼，文章多白頭。", "何時掛長劍，天地一扁舟。"]'),
('7a1f5caf-c404-4e02-9adf-392ca2c37785','謝竹堂先生見過','王隠','宋','宋诗','song-poetry','','[]','學稼古寺側，結廬高柳陰。',48,'全唐诗/poet.song.253000.json','["學稼古寺側，結廬高柳陰。", "音書故交絕，歲月杜門深。", "新雪添衰鬢，寒灰死壯心。", "西州賢別駕，連日肯相尋。"]'),
('180edada-6de9-4bf2-a573-13e9db3ca608','次韻之秋日雨後韻','王隠','宋','宋诗','song-poetry','','[]','洺州秋雨後，幽勝可供閒。',48,'全唐诗/poet.song.253000.json','["洺州秋雨後，幽勝可供閒。", "白首留他縣，歸心繞故山。", "野泉來竹底，危磴入雲間。", "尚記登高會，重巖細菊斑。"]'),
('72abfafe-6210-44f8-8cf1-1db4a487caf1','周侯祠','釋印','宋','宋诗','song-poetry','','[]','將軍手持三尺劍，奮身直入蛟龍穴。',64,'全唐诗/poet.song.253000.json','["將軍手持三尺劍，奮身直入蛟龍穴。", "至今魚鼈不敢游，溪流上下皆腥血。", "千年廟食未足酬，問之父老何其憂。", "害人白額猶未盡，紛紛不獨南山頭。"]'),
('b117489d-83d9-4dfb-a5bc-4ca62075bede','送王山人歸千峰','釋思雅','宋','宋诗','song-poetry','','[]','舊居千萬岑，歸去獨携琴。',48,'全唐诗/poet.song.253000.json','["舊居千萬岑，歸去獨携琴。", "物外情難遏，雲中路再尋。", "花繁溪圃合，柳暗野橋深。", "想到垂綸處，和苔掃竹陰。"]'),
('8708c2b0-549d-4cb3-aef5-a174a3ad60ff','送王山人歸隠','釋惠渙','宋','宋诗','song-poetry','','[]','山人惟委命，豈戀世塵間。',48,'全唐诗/poet.song.253000.json','["山人惟委命，豈戀世塵間。", "干祿不得志，移家住遠山。", "醉眠溪石靜，吟倚草堂閒。", "到想無餘事，林僧日往還。"]'),
('4a28eede-e3a8-43bd-93ae-96be36a3d385','洛下別同志','釋善懃','宋','宋诗','song-poetry','','[]','歲暮遠交朋，携筇背洛城。',48,'全唐诗/poet.song.253000.json','["歲暮遠交朋，携筇背洛城。", "往來興廢地，今古別離情。", "疊翠嵩峰色，瀉寒伊水聲。", "他年再相會，却訝白髭生。"]'),
('fe78247c-d0a5-4c69-a0de-af4a3455307d','秋郊晚望','釋善懃','宋','宋诗','song-poetry','','[]','華郭外登臨，凝眸秋色深。',48,'全唐诗/poet.song.253000.json','["華郭外登臨，凝眸秋色深。", "樹凋分岳面，雲破露天心。", "斷雁當空續，殘陽隔隴沉。", "盤桓傷急景，回首動微吟。"]'),
('ee29c8ea-5138-4d95-bc97-ee708a897e8c','安濟橋','杜德源','宋','宋诗','song-poetry','','[]','駕石飛梁儘一虹，蒼龍驚蟄背磨空。',64,'全唐诗/poet.song.253000.json','["駕石飛梁儘一虹，蒼龍驚蟄背磨空。", "坦途箭直千人過，驛使馳驅萬國通。", "雲吐月輪高拱北，雨添春色去朝東。", "休誇世俗遺仙跡，自古神丁役此工。"]'),
('34af48c5-1158-481b-94ba-1e63d2d28c75','寄雲水禪師','文興','宋','宋诗','song-poetry','','[]','百丈傳衣後，棲心近沃洲。',48,'全唐诗/poet.song.253000.json','["百丈傳衣後，棲心近沃洲。", "道高歸毳侶，名重達凝旒。", "對話千峰雪，安禪萬木秋。", "仍聞有新偈，時向四方流。"]'),
('06a2ad55-8fa3-42ea-9c84-9248ad453921','垂虹亭','祝乂','宋','宋诗','song-poetry','','[]','冷浸三江碧，青圍四面山。',48,'全唐诗/poet.song.253000.json','["冷浸三江碧，青圍四面山。", "帆歸烟浪杪，人住水雲間。", "風颭波聲碎，虹垂雨意閒。", "無端動歸興，一棹喜輕還。"]'),
('1d667cc9-625c-4ecf-bdd2-cab0f4e21130','泗源','程企','宋','宋诗','song-poetry','','[]','泗源奇且怪，聲勢各喧豗。',240,'全唐诗/poet.song.253000.json','["泗源奇且怪，聲勢各喧豗。", "虎豹巖邊去，蛟龍窟裏來。", "稍流烟作陣，初激雪成堆。", "派必人疏導，源應鬼鑿開。", "乍深濤不起，漸遠浪相催。", "可把江心比，嘗將海眼猜。", "始微纔迸玉，終盛忽奔雷。", "澗爲寒無卉，丘因澗有苔。", "已觀離竇側，俄見過城隈。", "石勁崖難潄，沙虛岸易頹。", "邇雖逾濟漯，遐亦到蓬萊。", "洗鉢僧常至，乘槎客未迴。", "我從原際瞰，誰自谷中推。", "洶涌曾浮磬，潺湲好泛杯。", "狹寧容蟻穴，湍可暴魚鰓。", "劈華非天意，排淮廼力哉。", "傍如巫女峽，上類楚王臺。", "漏澤空神異，襄陵但水災。", "林幽多鳥雀，地僻少塵埃。", "重愛茲佳趣，題詩愧不才。"]'),
('fe53531f-16b5-40b5-905d-830d1005d2f1','百門泉','周百祿','宋','宋诗','song-poetry','','[]','光摇暗日動珠盤，汎汎輕風漾碧瀾。',32,'全唐诗/poet.song.253000.json','["光摇暗日動珠盤，汎汎輕風漾碧瀾。", "俯檻恍然驚醉眼，雲天却向鏡中看。"]'),
('09ffa5a4-3169-47a5-9643-d7607a8eeab9','句','黄晦叔','宋','宋诗','song-poetry','','[]','大安婦翁舍，時來枕流眠。',12,'全唐诗/poet.song.253000.json','["大安婦翁舍，時來枕流眠。"]'),
('19d5594d-00e7-4955-973a-adb7dc35c4d4','老僧','釋景雲','宋','宋诗','song-poetry','','[]','日照西山雪，老僧門始開。',48,'全唐诗/poet.song.253000.json','["日照西山雪，老僧門始開。", "凍瓶黏柱礎，宿火陷爐灰。", "童子病歸去，鹿麋寒入來。", "齋鐘知漸近，枝鳥下生臺。"]'),
('74da5aa3-2d40-440e-acc4-4625cb247807','夷陵即事','釋尚顔','宋','宋诗','song-poetry','','[]','不難饒白髪，相續是灘波。',48,'全唐诗/poet.song.253000.json','["不難饒白髪，相續是灘波。", "避世嫌身晚，思家乞夢多。", "暑衣經雪著，凍研向陽呵。", "豈能臨岐路，還聞聖主過。"]'),
('a9f42056-f6a4-4197-a8b5-7c6f95760599','句  其一','釋尚顔','宋','宋诗','song-poetry','','[]','海島和濤望。',6,'全唐诗/poet.song.253000.json','["海島和濤望。"]'),
('3ccfae9b-9c95-4b6b-9ac2-a6c1d0cd7798','句  其二','釋尚顔','宋','宋诗','song-poetry','','[]','一十二三年。',6,'全唐诗/poet.song.253000.json','["一十二三年。"]'),
('f306c677-08b3-43fc-8882-2bc7cb7d62c1','句  其三','釋尚顔','宋','宋诗','song-poetry','','[]','山僧带雪期。',6,'全唐诗/poet.song.253000.json','["山僧带雪期。"]'),
('f3841ddd-5017-400c-9a9c-9398b7a918c0','釣臺','釋北野','宋','宋诗','song-poetry','','[]','自過羊裘七里灘，尋思欲見故人難。',32,'全唐诗/poet.song.253000.json','["自過羊裘七里灘，尋思欲見故人難。", "殷勤借問溪邊叟，近日誰來把釣竿。"]'),
('ea5aa475-80f7-4621-9ff8-866a86b5fe74','題釣臺','潘中父','宋','宋诗','song-poetry','','[]','焚坑禍作逃園綺，明哲保身寧餓死。',160,'全唐诗/poet.song.253000.json','["焚坑禍作逃園綺，明哲保身寧餓死。", "溺冠嫚駡又一春，織畚鼓刀恬不恥。", "子房託疾封留歸，齊魯大臣那可知。", "此意寥寥二百載，阿諛往往居帝師。", "中興天幸有光武，下士謙恭冠千古。", "布衣本以道義交，不問故人登九五。", "朅來過我路幾程，征衫猶作戰血腥。", "睡餘伸足稍加腹，安得細事關天星。", "歸與宜審苞桑戒，勿念潔身增嘆慨。", "君持柔道理乾坤，我把絲綸老湍瀨。"]'),
('cae2acbe-2e9d-480f-a4fd-ec5f00b61066','題釣臺  其一','陳疇','宋','宋诗','song-poetry','','[]','綠竹叢邊繫客船，釣臺千古薄雲天。',32,'全唐诗/poet.song.253000.json','["綠竹叢邊繫客船，釣臺千古薄雲天。", "區區寇鄧功如許，何以高風獨凜然。"]'),
('ea949087-0e89-4bf9-9475-7554660b3fb1','題釣臺  其二','陳疇','宋','宋诗','song-poetry','','[]','故人已了中興事，贏得溪頭一釣竿。',32,'全唐诗/poet.song.253000.json','["故人已了中興事，贏得溪頭一釣竿。", "喚起先生同一笑，青山自在白雲閑。"]'),
('3a9b3289-5724-43a4-8443-b0d18f23b31c','石禪床','胡梅所','宋','宋诗','song-poetry','','[]','空山危石平如掌，雲嶺苔封自昔時。',32,'全唐诗/poet.song.253000.json','["空山危石平如掌，雲嶺苔封自昔時。", "不識山僧曾坐處，幾回彈舌雨龍歸。"]'),
('c375a78a-e25b-4c2d-9e3d-1474a6319e97','桃園','胡梅所','宋','宋诗','song-poetry','','[]','洞門無鎖白雲深，同日閑表一問津。',32,'全唐诗/poet.song.253000.json','["洞門無鎖白雲深，同日閑表一問津。", "安待霄時𥜐桃者，相逢花下說前因。"]'),
('bc177432-69ac-486b-a3f0-cfdca2279f2f','誦經石','胡梅所','宋','宋诗','song-poetry','','[]','昔人曾此月明中，掃石焚香禮碧空。',32,'全唐诗/poet.song.253000.json','["昔人曾此月明中，掃石焚香禮碧空。", "千載臺空人不見，野花啼鳥自春風。"]'),
('c74caf8c-44db-43b4-8f8b-0ed4c9c451fb','千人洞','胡梅所','宋','宋诗','song-poetry','','[]','天生巖穴受千人，隠隠巒深隔□塵。',32,'全唐诗/poet.song.253000.json','["天生巖穴受千人，隠隠巒深隔□塵。", "不識人間經幾劫，洞門依舊鎖閉雲。"]'),
('0fa64e27-4611-4d64-a984-f73a39b5f70c','仙亭巖','胡梅所','宋','宋诗','song-poetry','','[]','仙子高棲海上山，一塵不到石臺間。',64,'全唐诗/poet.song.253000.json','["仙子高棲海上山，一塵不到石臺間。", "鶴隨仙客收棋去，龍伴山僧採藥還。", "風送白雲歸洞口，鐘隨明月到人間。", "不須再問神仙事，花落花開暑又寒。"]'),
('11cb5739-45c3-4cfe-975b-cfffa65f94b0','南明山','石亨之','宋','宋诗','song-poetry','','[]','祇因尋勝到林泉，四抱回峰萬景連。',64,'全唐诗/poet.song.253000.json','["祇因尋勝到林泉，四抱回峰萬景連。", "僧過不知山隠寺，客來方見洞開天。", "浮屠照水光相映，古木臨崖影倒懸。", "風露了非人世界，恍疑身似洞中仙。"]'),
('c1af0278-117d-495b-904a-4d08c0dc5f5f','自寬','邱一中','宋','宋诗','song-poetry','','[]','仙都有敕到林泉，誰信祠官無俸錢。',64,'全唐诗/poet.song.253000.json','["仙都有敕到林泉，誰信祠官無俸錢。", "陶醉猶能麾客去，顔饑何至乞人憐。", "鹿蕉已是今無夢，枸芑曾傳昔有仙。", "餓死亦堪垂不朽，無緣個個珥貂蟬。"]'),
('8b86d4e4-334d-46c3-bb30-613500596e9e','浮槎山','釋用孫','宋','宋诗','song-poetry','','[]','山爲浮來海莫沈，蕭梁曾此布黄金。',64,'全唐诗/poet.song.253000.json','["山爲浮來海莫沈，蕭梁曾此布黄金。", "梵僧親指耆闍路，帝女歸傳達磨心。", "地控好峰排萬仞，澗餘流水落千尋。", "靈蹤斷處人何在，日夕雲霞望轉深。"]'),
('9151d0d2-5c55-4a6b-bba8-7f15f065e163','山居','釋志芝','宋','宋诗','song-poetry','','[]','千峰頂上一間屋，老僧半間雲半間。',32,'全唐诗/poet.song.253000.json','["千峰頂上一間屋，老僧半間雲半間。", "昨夜雲隨風雨去，回頭方羨老僧閑。"]'),
('76410392-7a3f-416c-940a-cd96114b95a2','偈','釋志芝','宋','宋诗','song-poetry','','[]','茶芽蔍䔩初離焙，筍角狼忙又吐泥。',32,'全唐诗/poet.song.253000.json','["茶芽蔍䔩初離焙，筍角狼忙又吐泥。", "山舍一年春事辦，得閑誰管板頭低。"]'),
('82106d7b-739c-48f7-8cea-a59c5aca4b65','詠魚籃觀音','釋朋','宋','宋诗','song-poetry','','[]','徒整春風兩鬢垂，子規啼徧落花枝。',32,'全唐诗/poet.song.253000.json','["徒整春風兩鬢垂，子規啼徧落花枝。", "龍門上客家家是，錦鯉提來賣與誰。"]'),
('e21d8a0b-b750-4610-a67f-84e88d1bd7a9','遊臺感興古風','李師聖','宋','宋诗','song-poetry','','[]','梵書五頂清凉府，冬冰夏雪無炎暑。',272,'全唐诗/poet.song.253000.json','["梵書五頂清凉府，冬冰夏雪無炎暑。", "我來七月秋正寒，何况蕭蕭巖谷雨。", "偶爾雲開煦氣生，溶溶滿目烟光聚。", "真容古基鷲峰寺，高山之麓雄今古。", "西方樓觀縹緲間，粲然金碧蓮華宇。", "懸崖峻嶺架大木，神物所持憑險阻。", "金璫垂空殿簷響，森森鐵鳳相交舞。", "憶昔文殊出火宅，金剛寶窟通真土。", "牽牛老人飲玉泉，二子一犬隨貧女。", "變化無方利有情，知是西天七佛祖。", "重聞清凉境界真，無窮陳迹書妙語。", "我有誠心頗出群，瑞應神奇目親臯。", "須臾光相現咫尺，玉洞金燈明可數。", "松影摇空山谷中，夜寂太陰隠龍虎。", "丹樓碧閣香案前，敬畏生心誰敢侮。", "從來昏迷如夢迴，前三後三慎莫取。", "我今不作前後想，香烟稽首清凉主。"]'),
('4fd7ac11-d25b-4b72-86e6-fe6edfece352','題江湖偉觀','趙元清','宋','宋诗','song-poetry','','[]','鳳舞龍飛王氣蟠，兩都賦在一闌干。',64,'全唐诗/poet.song.253000.json','["鳳舞龍飛王氣蟠，兩都賦在一闌干。", "伍員不死江潮壯，西子如生越水寒。", "春日百花連上苑，秋風落葉滿長安。", "錢塘盡占東南美，河洛何人著眼看。"]'),
('de34ce5b-6fe0-4a05-a35c-ff43e9d9b158','答清江錢大尹問閤皁山中景','陳孟陽','宋','宋诗','song-poetry','','[]','形如閤皁對清江，吳漢神仙古道場。',192,'全唐诗/poet.song.253000.json','["形如閤皁對清江，吳漢神仙古道場。", "玉像靈多民受賜，天書歲久墨猶香。", "絳霞密鎖靈仙館，碧霧輕籠正一堂。", "蒼蘚斕斑雙鯉石，寒泉澄湛九龍塘。", "著衣臺上三冬暖，鳴水亭前六月凉。", "擣藥鳥聲喧夜榻，昇天馬跡印西岡。", "葛憩源深生異草，凌雲峰峻染瑶光。", "丹井雖存人杳漠，松巢空見鶴飛翔。", "屏粧水墨誇陶弼，門斷塵埃憶孟昌。", "風來松檜笙簫地，春入園林錦繡鄉。", "箇中自少紅塵到，閑裏惟知白晝長。", "景物敢吟成實錄，願憑賢宰一稱揚。"]'),
('c0088b3f-2ce0-4f1e-8b0c-ded76b7f2023','題馬遠四景圖  其一','內院官','宋','宋诗','song-poetry','','[]','花前靜榻閒眠處，竹下明窗獨坐時。',32,'全唐诗/poet.song.253000.json','["花前靜榻閒眠處，竹下明窗獨坐時。", "著甚語言名定泰，林間自有翠禽知。"]'),
('f67b76d0-2069-44b6-a4e1-7a6d7822f8ad','題馬遠四景圖  其二','內院官','宋','宋诗','song-poetry','','[]','一霎催花細雨回，集芳堂下錦千堆。',32,'全唐诗/poet.song.253000.json','["一霎催花細雨回，集芳堂下錦千堆。", "浪紅狂紫渾爭發，不待商量細細開。"]'),
('166392b8-f44d-4179-a320-118fac3de5c1','題馬遠四景圖  其三','內院官','宋','宋诗','song-poetry','','[]','初晴月向松間出，盛暑風從水面來。',32,'全唐诗/poet.song.253000.json','["初晴月向松間出，盛暑風從水面來。", "已比他人多數倍，况能時復舉尊罍。"]'),
('a190ce64-5372-4469-a057-db840bdd7d6b','題馬遠四景圖  其四','內院官','宋','宋诗','song-poetry','','[]','同雲漠漠雪霏霏，安樂園中賞玩時。',32,'全唐诗/poet.song.253000.json','["同雲漠漠雪霏霏，安樂園中賞玩時。", "酒放半醺簾半捲，此情無使外人知。"]'),
('22b8c8df-9144-474f-bc74-bf02bca3d6a3','偈二首  其一','釋道英','宋','宋诗','song-poetry','','[]','南北東西住險巘，古巖寒桂冷依依。',32,'全唐诗/poet.song.253000.json','["南北東西住險巘，古巖寒桂冷依依。", "無人到我經行地，明月清風擬付誰。"]'),
('514b0dec-b234-47c0-989b-2e08f1c3eb96','偈二首  其二','釋道英','宋','宋诗','song-poetry','','[]','每把葫蘆椀放欹，從教天下浪猜疑。',32,'全唐诗/poet.song.253000.json','["每把葫蘆椀放欹，從教天下浪猜疑。", "秋風擺落園林後，始信寒松格不卑。"]'),
('20b7f001-df78-4dee-8170-2a98491a52ec','姑蘇懷古','釋義傳','宋','宋诗','song-poetry','','[]','西南山水佳，清游何款款。',72,'全唐诗/poet.song.253000.json','["西南山水佳，清游何款款。", "白雲無定蹤，飛入長洲苑。", "空臺誰與登，麋鹿去人遠。", "啼月城頭烏，風悲易淒斷。", "爛開木芙蓉，寒塘弄清淺。", "憑虛一徘徊，西飛日何短。"]'),
('0fb0e8fc-941b-4776-92a8-1fdf584ac420','龍湫','郭君舉','宋','宋诗','song-poetry','','[]','絕頂龍君宅，深疑與海連。',48,'全唐诗/poet.song.253000.json','["絕頂龍君宅，深疑與海連。", "飛來千丈瀑，下潤幾桑田。", "噀日虹霓壯，隨風雪霰圓。", "高寒吟未穩，欲去復迴旋。"]'),
('7eb321c3-9ac5-4e72-96d2-c9d6ca5a2298','觀音巖','郭君舉','宋','宋诗','song-poetry','','[]','上得馬鞍嶺，奇峰應接頻。',48,'全唐诗/poet.song.253000.json','["上得馬鞍嶺，奇峰應接頻。", "遥看孤絕處，分現普陀身。", "納月瓶泉冷，嬌春柳黛新。", "却疑吳道子，貌出此巖真。"]'),
('51e54691-adc6-45e0-9506-61a7ff8b6d37','天聰洞','郭君舉','宋','宋诗','song-poetry','','[]','混沌何年鑿，天聰亦强名。',48,'全唐诗/poet.song.253000.json','["混沌何年鑿，天聰亦强名。", "我疑龍窟宅，人說鬼經營。", "梯向巖邊接，雲從洞裏生。", "此行頑健甚，脚力十分輕。"]'),
('e6ea19d5-4d7b-4697-b1ef-8d548a806c65','維摩室','郭君舉','宋','宋诗','song-poetry','','[]','來問維摩室，因參不二門。',48,'全唐诗/poet.song.253000.json','["來問維摩室，因參不二門。", "一龕間日月，方丈別乾坤。", "風落巖花暖，雨晴山鳥喧。", "何當分半席，默坐聽潺湲。"]'),
('dcd1b984-3c58-4c2f-856a-bd174a60d5af','題桃源  其一','無名氏','宋','宋诗','song-poetry','','[]','忽入桃源景可猜，莫非道士亦曾栽。',64,'全唐诗/poet.song.253000.json','["忽入桃源景可猜，莫非道士亦曾栽。", "舟行泝水沿溪進，花映清流夾岸開。", "石澗有岐封碧草，洞門無俗長蒼苔。", "方知此景非人世，岩谷幽深少客來。"]'),
('bdd02357-bb96-4ebc-8012-b631ecc4b46f','題桃源  其二','無名氏','宋','宋诗','song-poetry','','[]','捨舟入洞夕陽斜，得見方村八九家。',64,'全唐诗/poet.song.253000.json','["捨舟入洞夕陽斜，得見方村八九家。", "林鎖山環藏屋宇，雞鳴犬吠隠烟霞。", "寧知門有今朝客，可使燈開昨夜花。", "共喜相邀詢動止，呼童汲水煮仙茶。"]'),
('119348ab-a803-4b24-93f7-b609ff50731e','題桃源  其三','無名氏','宋','宋诗','song-poetry','','[]','遠近人家盡見招，小童環立總垂髫。',64,'全唐诗/poet.song.253000.json','["遠近人家盡見招，小童環立總垂髫。", "玄冰滿椀侵肌爽，絳雪堆盤入口消。", "山內不知今晉代，座中猶自問秦朝。", "夜深時向花前立，遥見雙株合鳳簫。"]'),
('367dbd89-e625-476c-b850-746a62aadffb','題桃源  其四','無名氏','宋','宋诗','song-poetry','','[]','憶前復入武陵溪，野水微茫烟樹迷。',64,'全唐诗/poet.song.253000.json','["憶前復入武陵溪，野水微茫烟樹迷。", "巖閉不聞仙犬吠，山深惟聽鷓鴣啼。", "神仙懸隔今非昔，烏兔循環東復西。", "應向洞中存隠跡，芳名留與後人題。"]'),
('70b709b5-adea-4fc2-873f-9c670c8fb7ab','雲巖次朱晦庵韻','羅禧','宋','宋诗','song-poetry','','[]','陟彼中和山，無人不感仰。',48,'全唐诗/poet.song.253000.json','["陟彼中和山，無人不感仰。", "庭中檀麝盈，洞裏珍珠滿。", "兩腋清風生，一腔春意爽。", "焚香祝聖回，袖带爐烟暖。"]'),
('016c3a9d-39da-40e2-a9b8-88309c0791a9','詠雪巖','羅禧','宋','宋诗','song-poetry','','[]','山迴百折路難躋，遠望樓臺烟樹迷。',64,'全唐诗/poet.song.253000.json','["山迴百折路難躋，遠望樓臺烟樹迷。", "滿地白雲封洞口，一輪紅日照天梯。", "龜蛇伏氣時難老，鸞鶴歸來夜倦飛。", "萬壑千巖遊不盡，且將詞句壁頭題。"]'),
('06134aac-aa9c-4fd8-ad62-74724651d82d','詠宗統','羅禧','宋','宋诗','song-poetry','','[]','豫章譜系派流長，積德貽謀百世昌。',64,'全唐诗/poet.song.253000.json','["豫章譜系派流長，積德貽謀百世昌。", "子孝臣忠昭史冊，人文士義著名邦。", "根源有自支流盛，辭賦無窮翰墨香。", "一閲此書一興嘆，令人千古仰餘光。"]'),
('fc5102b2-0a6f-4fbb-9a5d-642031a0f413','分水嶺','李柘','宋','宋诗','song-poetry','','[]','東西水去吼雷霆，左右山排劍戟陳。',64,'全唐诗/poet.song.253000.json','["東西水去吼雷霆，左右山排劍戟陳。", "天固無心開宇宙，地如有意限江閩。", "榆關北辨夷兼夏，劍閣西分蜀與秦。", "到底乾坤同一視，舟車何處不通津。"]'),
('4906da14-668d-4b0e-b353-d004bcc09aab','題敬榮堂','李柘','宋','宋诗','song-poetry','','[]','周君築室東南隅，訓友仲季勤詩書。',160,'全唐诗/poet.song.253000.json','["周君築室東南隅，訓友仲季勤詩書。", "求名於我我不語，爲君邈取棠棣圖。", "棠棣詩成喻恩義，鄭氏箋詩寓深意。", "上華下萼兩相扶，枝干光華能覆庇。", "兄弟本是同枝生，譬諸華萼齊敷榮。", "蔓草難圖段不弟，尺布可縫嗟爾兄。", "君家昆仲俱秀敏，願篤萱堂眉壽慶。", "勉旃覆弟有餘榮，戒爾事兄須盡敬。", "數椽雅談標新題，爲君更作敬榮詩。", "敬榮之善不可獨，餘波亦詔吾癡兒。"]'),
('bd77a089-21cf-4ac8-8e8b-1fb60c944b7b','清湖','王庭','宋','宋诗','song-poetry','','[]','萬頃靈湫带碧煙，源泉混混自山前。',64,'全唐诗/poet.song.253000.json','["萬頃靈湫带碧煙，源泉混混自山前。", "四時每漲空中雨，一片常涵鏡裏天。", "星斗轉時銀漢近，芙蓉開處彩屏連。", "魚龍久躍平深處，變化應知在異年。"]'),
('551c1eed-e5c8-4916-a6e5-0682d1bedf8c','陸羽井','司馬允中','宋','宋诗','song-poetry','','[]','百尺寒泉浸崖腹，蘚蝕題名不堪讀。',32,'全唐诗/poet.song.253000.json','["百尺寒泉浸崖腹，蘚蝕題名不堪讀。", "只今此味屬誰論，自把銅瓶汲新淥。"]'),
('ce881537-49c3-45d3-8493-a98675f41bf8','陳公樓','司馬允中','宋','宋诗','song-poetry','','[]','陳公汲深實奇計，轉向人間作豐歲。',32,'全唐诗/poet.song.253000.json','["陳公汲深實奇計，轉向人間作豐歲。", "轆轤聲曉潜虬寒，玄猨啼在深深樹。"]'),
('851dd496-690b-47bd-9d2e-6c8f858be37f','千頃雲','司馬允中','宋','宋诗','song-poetry','','[]','且與祖龍相頡頏，大施霖雨謾悠揚。',32,'全唐诗/poet.song.253000.json','["且與祖龍相頡頏，大施霖雨謾悠揚。", "歸來好護安禪石，莫作巫山一夢長。"]'),
('467119b7-e253-401e-8699-7fe7d42560b6','武丘寺','釋興肇','宋','宋诗','song-poetry','','[]','高僧危閣侵雲際，盡日披襟濯好風。',32,'全唐诗/poet.song.253000.json','["高僧危閣侵雲際，盡日披襟濯好風。", "極目長川人不見，萬株烟樹接遥空。"]'),
('f27b225c-5739-4fb4-8ec2-7a2711811697','遊虎丘','釋興肇','宋','宋诗','song-poetry','','[]','滄海何年湧，秦傳虎踞丘。',48,'全唐诗/poet.song.253000.json','["滄海何年湧，秦傳虎踞丘。", "池空劍光冷，墳缺鬼吟愁。", "石礙樓臺仄，烟深草木稠。", "吳人貪勝概，春盡亦來游。"]'),
('e3aa6409-cdfa-48e3-859a-6c19afcadaaa','遊虎丘  其一','林拱中','宋','宋诗','song-poetry','','[]','白虎巖前秋已闌，黑雲疏雨洗林巒。',64,'全唐诗/poet.song.253000.json','["白虎巖前秋已闌，黑雲疏雨洗林巒。", "鐵花烟落石泉冷，羽井苔深霜月寒。", "隠浦疾帆風去飽，疏寮森木曉催丹。", "清齋不許盤餐入，辜負湖山冷淡看。"]'),
('a90821e6-a428-4da6-b20d-fcb4e9dcdead','遊虎丘  其二','林拱中','宋','宋诗','song-poetry','','[]','我來一榻羨危亭，倦步支頤竹杖輕。',64,'全唐诗/poet.song.253000.json','["我來一榻羨危亭，倦步支頤竹杖輕。", "僧聽鐘聲歸寺急，鴉爭林宿壓枝鳴。", "禪機擊撥如鋒起，塵袂驅除似水清。", "風定夜虛聲轉寂，杯茶精舍一燈明。"]'),
('3b7d75d4-b394-4cd7-8220-78591771addb','遊虎丘','楊頤','宋','宋诗','song-poetry','','[]','盡日凭高步臺閣，意氣飄然擺羈縛。',240,'全唐诗/poet.song.253000.json','["盡日凭高步臺閣，意氣飄然擺羈縛。", "靈蹤絕跡萬千狀，群玉排青插寥廓。", "點頭巨石勢欲動，突立試劍峭如削。", "劍池在嶺不憚浚，造化神工巧鎸鑿。", "寒湫耿耿浸雲根，大旱燒雲源不涸。", "跳珠噴激瑩無痕，百斛珠璣綴疏箔。", "丹青妙手畫不到，一點塵埃無處著。", "僧居占盡佳山景，樓殿高低半丹雘。", "午齋寂寂山風幽，續斷風摇四簷鐸。", "始疑東海轉鼇背，蓬萊弱流在西角。", "千巖萬壑看不厭，自謂它山盡糟粕。", "我來因作神仙尉，得捨塵寰少盤礴。", "不因仙客爲先容，爭得看山這一脚。", "乃知世俗徒擾擾，不若甘心處恬薄。", "長嘯拂衣歸去來，舊山亦有雲泉約。"]'),
('f0dfb1b3-d71c-45f4-afa0-185306811656','遊虎丘','蔡令將','宋','宋诗','song-poetry','','[]','佳時結勝遊，與子棹蘭舟。',48,'全唐诗/poet.song.253000.json','["佳時結勝遊，與子棹蘭舟。", "路近雲烟霽，巖深水木秋。", "臨風傷遠日，感慨發詩愁。", "樂事真難偶，年光若轉頭。"]'),
('056dbc30-790a-4850-b199-365c10904c86','黄山雜詠 桃花峰','鄧宗度','宋','宋诗','song-poetry','','[]','劉阮辭世塵，桃花誰復主。',24,'全唐诗/poet.song.253000.json','["劉阮辭世塵，桃花誰復主。", "無計殢春風，一夜零紅雨。"]'),
('e7aa771c-0e8a-4366-a425-3353a2cc2c72','黄山雜詠 石牀峰','鄧宗度','宋','宋诗','song-poetry','','[]','原非人力建，造化琢磨成。',24,'全唐诗/poet.song.253000.json','["原非人力建，造化琢磨成。", "一枕遊仙夢，蟾波白晝生。"]'),
('a032a44d-1b83-4d12-b83c-89c16c213573','黄山雜詠 祥符寺','鄧宗度','宋','宋诗','song-poetry','','[]','雲水最饒處，輪蹄無到時。',24,'全唐诗/poet.song.253000.json','["雲水最饒處，輪蹄無到時。", "夜蟾生佛面，春雪印僧眉。"]'),
('06fa1dbf-9ba3-49c0-b091-449c34321d68','黄山雜詠 石門峰','鄧宗度','宋','宋诗','song-poetry','','[]','暮雲無意鎖，春草豈能關。',24,'全唐诗/poet.song.253000.json','["暮雲無意鎖，春草豈能關。", "何事棲霞客，從茲去不還。"]'),
('0ad48e75-7738-4331-a0b3-27500782062c','黄山雜詠 丹霞峰','鄧宗度','宋','宋诗','song-poetry','','[]','綺段堆青壁，點綴秋顔色。',24,'全唐诗/poet.song.253000.json','["綺段堆青壁，點綴秋顔色。", "幾使曉來風，縱橫裁不得。"]'),
('e9eca2a8-4b6e-4214-b8f6-772d76a39118','黄山雜詠 滴水巖','鄧宗度','宋','宋诗','song-poetry','','[]','石壁碎寒流，行人暮已愁。',24,'全唐诗/poet.song.253000.json','["石壁碎寒流，行人暮已愁。", "更傾風月耳，無水不生秋。"]'),
('66e01960-9c5f-41b6-a550-cf624c978901','黄山雜詠 蒼豹','鄧宗度','宋','宋诗','song-poetry','','[]','却隠他山霧，來眠此洞雲。',24,'全唐诗/poet.song.253000.json','["却隠他山霧，來眠此洞雲。", "區區麛鹿輩，戰栗敢子群。"]'),
('07bb0c60-205f-4f05-a818-fc1e10603d54','遊黄山留題','趙日巖','宋','宋诗','song-poetry','','["\u534e\u5c71"]','半空嵐翠滴樓臺，物象冥搜入翦裁。',64,'全唐诗/poet.song.253000.json','["半空嵐翠滴樓臺，物象冥搜入翦裁。", "雲散峭峰殊華嶽，仙留靈跡勝天台。", "丹砂水暖巖前湧，紫朮花香洞口開。", "爲問神仙住何處，寄詩還許到蓬萊。"]'),
('5b8a96d1-ceed-4e6f-bcc6-8a46ce8d08db','登樓望黄山','徐師','宋','宋诗','song-poetry','','[]','黄山樓上望黄山，水石雲霞未得攀。',32,'全唐诗/poet.song.253000.json','["黄山樓上望黄山，水石雲霞未得攀。", "三十六峰應笑我，紛紛塵事幾時閒。"]'),
('41e15088-e192-4d99-a0c7-a8c289fafaae','浮丘廟','陳巨川','宋','宋诗','song-poetry','','[]','浮丘羽化幾經年，千仞青溪有洞天。',32,'全唐诗/poet.song.253000.json','["浮丘羽化幾經年，千仞青溪有洞天。", "丹竈石牀依舊在，雲深何處問神仙。"]'),
('6a16fc25-97c5-4b11-84f1-0965767f1fda','謁麻衣祠','陳山泉','宋','宋诗','song-poetry','','[]','雨晴泥路滑，杖履豈徒勞。',48,'全唐诗/poet.song.253000.json','["雨晴泥路滑，杖履豈徒勞。", "雙檜塔前老，一峰天外高。", "錫泉通殿砌，巖瀑起波濤。", "欲問麻衣意，風林作怒號。"]'),
('ce91a550-b7ca-4242-a2ad-4a087d0ad45e','遊黄山留題','張冠卿','宋','宋诗','song-poetry','','[]','路盡清谿逼畫圖，亂雲深處插天都。',64,'全唐诗/poet.song.253000.json','["路盡清谿逼畫圖，亂雲深處插天都。", "霧開虎豹文姿出，松隠龍蛇怪狀孤。", "吐焰香砂收火齊，凌虛精舍礙靈烏。", "我來爲訪容成侶，試問丹丘果有無。"]'),
('1f9ca91d-9e2a-4ed1-968e-0a1f6d132607','湯泉','焦靜山','宋','宋诗','song-poetry','','[]','渟渟靈水養靈珠，籟定波生注玉壺。',32,'全唐诗/poet.song.253000.json','["渟渟靈水養靈珠，籟定波生注玉壺。", "洗盡塵勞多少客，不知還解洗心無。"]'),
('3e89ea6b-fb14-47c4-bc96-3e3213f50dca','游黄山留題','焦本心','宋','宋诗','song-poetry','','[]','自有乾坤不記年，山中紫翠尚依然。',64,'全唐诗/poet.song.253000.json','["自有乾坤不記年，山中紫翠尚依然。", "百千萬世留今日，三十六峰橫暮烟。", "怪石矬松名嶽上，神仙天子一人傳。", "桃花流水丹罏畔，欲往從游洗俗緣。"]'),
('e1a7e284-ad48-434a-82ed-57078c30d24d','石人峰','焦翠峰','宋','宋诗','song-poetry','','[]','石爲肌骨應成假，鐵作肝腸未必真。',32,'全唐诗/poet.song.253000.json','["石爲肌骨應成假，鐵作肝腸未必真。", "當日容成丹就處，何當點化作仙人。"]'),
('6919c9fe-7c2d-4bb2-a0da-507e5c2f5d9a','花山寺','程楠','宋','宋诗','song-poetry','','[]','雨過群峰翠欲飛，白雲松徑鳥聲微。',32,'全唐诗/poet.song.253000.json','["雨過群峰翠欲飛，白雲松徑鳥聲微。", "山僧閒卧鳴鐘起，共話無生醉月歸。"]'),
('284bbd62-1bac-4f02-a2a5-f4dc0b85ee0e','黄山遇雨  其一','汪兼山','宋','宋诗','song-poetry','','[]','誰能鍊得媧皇石，我亦叫開閶闔門。',32,'全唐诗/poet.song.253000.json','["誰能鍊得媧皇石，我亦叫開閶闔門。", "早起蒙天微一笑，依然雲氣薄崑崙。"]'),
('1231519f-d075-4344-8b0d-692ec1885222','黄山遇雨  其二','汪兼山','宋','宋诗','song-poetry','','[]','碑翻薦福雷轟碎，舟近蓬萊風勒回。',32,'全唐诗/poet.song.253000.json','["碑翻薦福雷轟碎，舟近蓬萊風勒回。", "山意有餘還不盡，青鞋留待後遊來。"]'),
('c9c3031d-b361-4b7d-a347-21d4fc3b1531','黄山遇雨  其三','汪兼山','宋','宋诗','song-poetry','','[]','乾坤老我頭先白，山水無情眼自青。',32,'全唐诗/poet.song.253000.json','["乾坤老我頭先白，山水無情眼自青。", "三十六峰藏不得，小窗趺坐看圖經。"]'),
('eb3c3c1d-8e22-41b4-b893-61ee48fbf8f9','遊黄山','釋巖隠','宋','宋诗','song-poetry','','[]','芒鞋踏遍翠微中，拭目群峰勢插空。',64,'全唐诗/poet.song.253000.json','["芒鞋踏遍翠微中，拭目群峰勢插空。", "石罅迸泉珠跳白，山花落澗錦浮紅。", "一天星澹猿啼曉，萬壑雲生虎嘯風。", "藥臼丹罏經世遠，軒皇曾此駕飛虹。"]'),
('f7f2761e-8df3-41a9-98da-6e5eac8f0053','遊黄山留題  其一','方月澗','宋','宋诗','song-poetry','','[]','笑擬愚公恨力綿，無窮眼力到危巔。',64,'全唐诗/poet.song.253000.json','["笑擬愚公恨力綿，無窮眼力到危巔。", "天黏青嶂蒸嵐霧，池湧丹砂費酒泉。", "高下瀑聲多是雨，去來雲氣半非烟。", "仙家日月長閒在，纔得心閒也是仙。"]'),
('fd134835-ba08-4965-a847-9d94f6a45bcb','遊黄山留題  其二','方月澗','宋','宋诗','song-poetry','','[]','金蓉綠水插層層，嵐氣浮浮直上蒸。',64,'全唐诗/poet.song.253000.json','["金蓉綠水插層層，嵐氣浮浮直上蒸。", "丹竈幾千年尚火，泉崖五六月猶冰。", "鹿銜烟草陪仙友，鶴睡雲松伴定僧。", "失笑紅塵奔走者，見山佳處幾人曾。"]'),
('5c4b01b3-91cb-4351-a9e2-1a826285ee80','題荆浩畫青山白雲卷','薛琦','宋','宋诗','song-poetry','','[]','渺渺山上山，隠隠樹邊樹。',56,'全唐诗/poet.song.253000.json','["渺渺山上山，隠隠樹邊樹。", "鷄犬不聞聲，居人在何處。", "扁舟載酒來相尋，古木蒼苔一徑深。", "白雲不飛青山舞，誰悟荆生點筆心。"]'),
('0d03c2e2-4440-41b1-afc5-a9eb18a44b12','舟泊五聖祠前','薛琦','宋','宋诗','song-poetry','','[]','葉落古祠前，村安許宿船。',48,'全唐诗/poet.song.253000.json','["葉落古祠前，村安許宿船。", "人聲齊到客，月色獨歸禪。", "野火明秋渚，山鐘出寺煙。", "推蓬不成寐，霜氣覽江天。"]'),
('bbc40910-1eb9-4dda-9118-91df44b4f189','贈樊川長老','釋清尚','宋','宋诗','song-poetry','','[]','瘦顔諸骨現，滿面雪毫垂。',48,'全唐诗/poet.song.253000.json','["瘦顔諸骨現，滿面雪毫垂。", "坐石鳥疑死，出門人謂癡。", "照身潭入楚，浸影檜生隋。", "太白曾經夏，清風凉四肢。"]'),
('1fbbe008-0c2b-4d2d-98e2-cd44712e09d5','題采蓮美人圖','孟淑卿','宋','宋诗','song-poetry','','[]','綠槐蟬靜日偏長，懶爇金爐百和香。',32,'全唐诗/poet.song.253000.json','["綠槐蟬靜日偏長，懶爇金爐百和香。", "莫摘池中蓮子看，箇中多半是空房。"]'),
('87c740ea-8bae-4148-ae76-57e83644eb5e','春歸','孟淑卿','宋','宋诗','song-poetry','','[]','落盡棠梨水拍堤，凄凄芳草望中迷。',32,'全唐诗/poet.song.253000.json','["落盡棠梨水拍堤，凄凄芳草望中迷。", "無情最是枝頭鳥，不管人愁只顧啼。"]'),
('dcd26630-d474-4b31-8bb7-0bf6c8bcf9dc','賦情','慧姞','宋','宋诗','song-poetry','','[]','自憐新髻好，對鏡久夷猶。',72,'全唐诗/poet.song.253000.json','["自憐新髻好，對鏡久夷猶。", "回首瞥見郎，含羞整搔頭。", "花間並郎行，低說夜來話。", "蝴蝶學嬌癡，飛來傍裙带。", "羨殺葉底花，色嬌香不漏。", "安得郎如葉，長將玉肌覆。"]'),
('91acfd9b-87d8-42d3-8acf-eb5f39ae6c9d','題趙子固水仙圖','翠屏道人','宋','宋诗','song-poetry','','[]','翠带懸璫重，凌波步步輕。',24,'全唐诗/poet.song.253000.json','["翠带懸璫重，凌波步步輕。", "春深不成怨，錦瑟夜無聲。"]'),
('439afb21-9350-4627-9d73-cd27cfabcd78','題韓幹馬','龔復','宋','宋诗','song-poetry','','[]','奚官小臣職奚爲，馬饑則秣渴飲之。',207,'全唐诗/poet.song.253000.json','["奚官小臣職奚爲，馬饑則秣渴飲之。", "龍媒八尺千里姿，雪花被身雲陸離。", "洼之異種來天池，乘輿重惜閒驅馳。", "河清海晏無盤嬉，壯士老死不得騎。", "御柳春深白日遲，寒甃淨汲冰花漪。", "目光注電吻沫脂，振迅欲掣青絡絲。", "奚官小臣謹厥司，猶恐若後呵譴施。", "不必前身作馬通馬語，人心物性在善推。", "嗚呼奚官小臣身賤卑，馬不如人愚亦知。", "奈何爲人牧，重爵厚祿不卹民渴饑。", "{夋刂}刮膏血剔肉肌，坐令溝壑轉老羸。", "今之龔黄卓魯誰，雲林藂社時所師，爲出馬圖陳詩爲。"]'),
('42103e09-d796-4088-b8e2-a0a65c452265','題韓幹馬','呂量','宋','宋诗','song-poetry','','[]','何年供奉仙，寫此真乘黄。',156,'全唐诗/poet.song.253000.json','["何年供奉仙，寫此真乘黄。", "矯矯天骨起，爛爛隅目光。", "豈無萬里姿，御者非王良。", "青衫老奚官，肉眼空倀倀。", "飲秣不以時，羈馽無繇驤。", "昂首思渥洼，浩蕩充虛腸。", "何來斗斛水，似是出尚方。", "雖霑金井恩，未效和鸞鏘。", "蹭蹬十二閑，何異古道傍。", "迴首萬駑駘，飽食馳康莊。", "朝飲華清流，暮垂紫游韁。", "此馬獨棄捐，物理良可傷。", "君王倘惠養，請試苜蓿長。"]'),
('65b8cdfe-8c76-4c82-a0f5-d10deeb4f43d','題韓幹馬','岑津','宋','宋诗','song-poetry','','[]','左輔周垣隠白沙，龍媒絕種進天家。',64,'全唐诗/poet.song.253000.json','["左輔周垣隠白沙，龍媒絕種進天家。", "驕嘶玉勒憐豐草，渴飲冰泉带落花。", "西狩還經千里棧，東巡會駕五雲車。", "權奇滅沒猶驚電，漫許拳毛世特誇。"]'),
('2a057451-aa56-4a95-84a7-d717f444c556','題韓幹馬','謝采','宋','宋诗','song-poetry','','[]','圉人唐衣冠，天閑畜神駿。',120,'全唐诗/poet.song.253000.json','["圉人唐衣冠，天閑畜神駿。", "雖非金日磾，不忝張景順。", "飽食無嫌身賤卑，時其渴燥張飲之。", "長年牧養瘠者肥，龍鬐鳳臆誇權奇。", "韓幹仙翁揮翰手，毫端幻出渴烏首。", "氣不凋喪骨肉勻，藝精端繼王裴後。", "遥想騰驤析木津，銜勒難拘自在身。", "斗水底用求他人，淥波沄沄易水春。"]'),
('66b555fc-9c30-4da4-9fbe-830242f32789','題范寬臨流獨坐圖','何權','宋','宋诗','song-poetry','','[]','茅堂結構背江干，日日愛看江上山。',32,'全唐诗/poet.song.253000.json','["茅堂結構背江干，日日愛看江上山。", "箕踞盤陀吟未穩，不知身在畫圖間。"]'),
('e633bda2-0c3c-4148-a6d8-ff17a715036e','嘉魚池','甯某','宋','宋诗','song-poetry','','[]','四百峰巒隠畫屏，翠光樓閣起山溟。',64,'全唐诗/poet.song.253000.json','["四百峰巒隠畫屏，翠光樓閣起山溟。", "高侔太嶽千山小，勢鎮乾坤萬古青。", "石洞猿啼烟月落，嘉池龍起水雲腥。", "臨流磯上誰遺跡，隠約仙人竇子明。"]'),
('77cff493-3bff-4601-b7fd-b4abfe26ce72','地藏塔','羅少微','宋','宋诗','song-poetry','','[]','還嶺峰頭霽色清，知微曾此學無生。',64,'全唐诗/poet.song.253000.json','["還嶺峰頭霽色清，知微曾此學無生。", "鳥從青壁屏邊過，人在白雲天際行。", "一片晴霞迎曉日，萬年松檜起秋聲。", "箇中仙景真奇絕，寶塔玲瓏最得名。"]'),
('0772510a-5623-49ee-bca3-fc6122fba2df','李白書堂','柯敬之','宋','宋诗','song-poetry','','[]','久欲華山訪謫仙，謫仙書舍尚依然。',64,'全唐诗/poet.song.253000.json','["久欲華山訪謫仙，謫仙書舍尚依然。", "青松翠柏疑無路，流水高山別有天。", "千片浮雲飛碧漢，一聲啼鳥破蒼烟。", "扶筇直上中峰頂，一看千山在眼前。"]'),
('6f6188e3-3f0e-4ab3-ac86-37bbb4c787fa','龍池','高子洪','宋','宋诗','song-poetry','','[]','九朵芙蓉天琢開，烟霞靜處翠成堆。',64,'全唐诗/poet.song.253000.json','["九朵芙蓉天琢開，烟霞靜處翠成堆。", "鹿銜花向林邊過，龍带雲從樹杪來。", "最愛山中閒日月，何須海上訪蓬萊。", "翛然自覺清風爽，直欲臨風翹上台。"]'),
('58197615-9d6c-4c48-99e0-b95967857489','沖虛觀','單縣君','宋','宋诗','song-poetry','','[]','雄峰峻峙煥朱明，元聖清虛此耀真。',64,'全唐诗/poet.song.253000.json','["雄峰峻峙煥朱明，元聖清虛此耀真。", "地靜無心閒日月，山高舉首近星辰。", "金壇露冷青鸞舞，丹竈風清白鶴馴。", "時有仙人綠雲上，九霄飄忽響韶鈞。"]'),
('cbdb61b3-98f9-43cb-888a-d756da5654b5','題明福法堂壁','雲章真人','宋','宋诗','song-poetry','','[]','一望羅浮聳萬山，畫圖曾進悅天顔。',64,'全唐诗/poet.song.253000.json','["一望羅浮聳萬山，畫圖曾進悅天顔。", "金爐飛篆乘鸞去，玉笈翻經引鶴還。", "棋洞落花春寂寂，藥槽流水夜潺潺。", "人來共道修仙易，誰肯安心學坐圜。"]'),
('460786e4-3e2e-449a-94b1-14c7b1696a0c','遊羅浮','莫洞觀','宋','宋诗','song-poetry','','[]','嵯峨千仞控炎陬，鐵作橋梁石作樓。',64,'全唐诗/poet.song.253000.json','["嵯峨千仞控炎陬，鐵作橋梁石作樓。", "五嶺衆山皆拱附，三神一島自漂流。", "氣凌滄海遥相視，看入青雲勢未休。", "借問穉川今在否，待飛雙燕結真遊。"]'),
('3c762eca-d4da-4023-881b-1d34194dde01','石淙','張仲武','宋','宋诗','song-poetry','','[]','二室盤游日，三陽宴喜心。',48,'全唐诗/poet.song.253000.json','["二室盤游日，三陽宴喜心。", "分流來萬壑，巨石擬千岑。", "玉殿煙蕪在，金碑雨蘚侵。", "翠華何處問，山水自清音。"]'),
('d3190770-58ea-470b-a585-1b851aaba4be','石淙','王贊','宋','宋诗','song-poetry','','[]','磴道山巖下，茅楹竹樹中。',48,'全唐诗/poet.song.253000.json','["磴道山巖下，茅楹竹樹中。", "深潭魚可見，攢石路纔通。", "坐聽潺湲碧，縣思爛熳紅。", "平生丘壑志，覽此興何窮。"]'),
('b72e6d97-d513-4f4e-a9a2-ff49302684b0','逍遥樓','建都思','宋','宋诗','song-poetry','','[]','逍遥留古迹，勝景浩無窮。',48,'全唐诗/poet.song.253000.json','["逍遥留古迹，勝景浩無窮。", "霧鎖山城市，煙藏水府宮。", "峰巒霄漢外，棟宇畫圖中。", "百草叢深綠，群花綻淺紅。"]'),
('99663850-8a2c-4e55-9c3a-4459704a5047','潭畔芙蓉','浣花女','宋','宋诗','song-poetry','','[]','芙蓉花發滿江紅，盡道芙蓉勝妾容。',32,'全唐诗/poet.song.253000.json','["芙蓉花發滿江紅，盡道芙蓉勝妾容。", "昨日妾從堤上過，如何人不看芙蓉。"]'),
('c00aff70-83f6-46c0-b13f-424a3b4bcb67','涇州懷古','郭瑄','宋','宋诗','song-poetry','','[]','危坡下盡見殘墉，勢扼長川萬古雄。',64,'全唐诗/poet.song.253000.json','["危坡下盡見殘墉，勢扼長川萬古雄。", "涇水無泥分畎澮，回山有脈自崆峒。", "唐文曾祀龍君廟，漢武猶存阿母宮。", "更喜筆峰青翠處，雨餘疑是畫圖中。"]'),
('06100cb8-1357-48cc-9e3f-331779b22ed9','寶林寺','王潤之','宋','宋诗','song-poetry','','[]','支公曾駐錫，規矩舊叢林。',48,'全唐诗/poet.song.253000.json','["支公曾駐錫，規矩舊叢林。", "飛鼠殿堂古，靈鰻井穴深。", "磬聲來竹外，塔影卧池陰。", "幸有相知客，時時過我吟。"]'),
('f9383b00-0316-4598-93f3-3cd92ec6b334','宿濠州高唐館','閻欽愛','宋','宋诗','song-poetry','','[]','借問襄王安在哉，山川此地勝陽臺。',32,'全唐诗/poet.song.253000.json','["借問襄王安在哉，山川此地勝陽臺。", "今朝寓宿高唐館，神女何曾入夢來。"]'),
('5b9ea1ed-fa82-4308-8114-9557d27c9c95','句','楊符','宋','宋诗','song-poetry','','[]','吏道官官惡，田家事事賢。',12,'全唐诗/poet.song.253000.json','["吏道官官惡，田家事事賢。"]'),
('ab215301-d564-40c3-b677-2d9bb666fa4b','題雲安下巖','令狐慶譽','宋','宋诗','song-poetry','','[]','地遠塵寰絕點埃，懸崖屈曲寄層臺。',64,'全唐诗/poet.song.253000.json','["地遠塵寰絕點埃，懸崖屈曲寄層臺。", "山頭玉溜隨檐滴，巖下金容就石開。", "寺影不妨流水過，松香長逐好風來。", "徧游未盡無窮景，爲報舟人且莫催。"]'),
('b54ed0d2-b4fc-4881-bc92-e0a9ba8581da','雨中自萬壽宮歸','張瓊','宋','宋诗','song-poetry','','[]','草草登臨未擬回，烟昏雨溼賦歸哉。',64,'全唐诗/poet.song.253000.json','["草草登臨未擬回，烟昏雨溼賦歸哉。", "山寒未放遷鶑出，地勝先聞駕鶴來。", "老去春光都是夢，嬾邊心事總如灰。", "歸尋藥裹扶筋力，准擬東風得屢陪。"]'),
('0e4b5778-8ad7-44fe-821a-7a7816a348c2','遊金精山','黎宙','宋','宋诗','song-poetry','','[]','不到金精久，山空花自香。',48,'全唐诗/poet.song.253000.json','["不到金精久，山空花自香。", "殿梁唐歲月，石鼓漢文章。", "洞杳多雲氣，崖高易夕陽。", "酌泉消世慮，吾亦正徜徉。"]'),
('7d1e6bd8-3ab2-4e47-b0d6-3b399be0b36c','曹娥江','邵梅溪','宋','宋诗','song-poetry','','[]','客舟艤盡江頭月，忍聽寒潮聲哽噎。',32,'全唐诗/poet.song.253000.json','["客舟艤盡江頭月，忍聽寒潮聲哽噎。", "那知江上無情波，總是曹娥眼中血。"]'),
('0264350d-bbef-4111-b767-76cee8cb7a0e','題梅壇','甘邦俊','宋','宋诗','song-poetry','','[]','火德中微否未傾，朝陽一疏鳳先鳴。',64,'全唐诗/poet.song.253000.json','["火德中微否未傾，朝陽一疏鳳先鳴。", "如公忠論能旋聽，彼莽姦謀未易成。", "萬古仙名香宇宙，幾人遺臭腐公卿。", "至今風吼松聲怒，似爲先生訴不平。"]'),
('fffdff2d-c64c-40bc-8ebb-06919ab45840','句  其一','賈仲穎','宋','宋诗','song-poetry','','[]','燈花寒影裏，詩句雨聲中。',12,'全唐诗/poet.song.253000.json','["燈花寒影裏，詩句雨聲中。"]'),
('0956ae9f-a415-46bf-bf81-151692d9dcac','句  其二','賈仲穎','宋','宋诗','song-poetry','','[]','盡開窗戶容秋月，遍倚闌干看晚山。',16,'全唐诗/poet.song.253000.json','["盡開窗戶容秋月，遍倚闌干看晚山。"]'),
('0bc61555-1e40-480c-83ea-f9b77aca8ab0','吳民女','陳潤道','宋','宋诗','song-poetry','','[]','吳民嗜錢如嗜飴，天屬之愛亦可移。',144,'全唐诗/poet.song.253000.json','["吳民嗜錢如嗜飴，天屬之愛亦可移。", "養女日夜望成長，長成未必爲民妻。", "百金求師教歌舞，便望將身贍門戶。", "一家飽暖不自憐，傍人視之方垂涎。", "朱門列屋爭妍麗，百計逢迎主人意。", "常時疏棄自悲啼，一旦承恩多妒忌。", "古人怕爲蕩子婦，夜夜孤眠淚如雨。", "今人甘爲貴人妾，得意失意花上月。", "蕩子不歸寧空房，主人喜怒多不常。"]'),
('80cb3e5a-8725-409a-a9ab-760d369497aa','游金精山陳千峰索和','彭昌詩','宋','宋诗','song-poetry','','[]','仙去時移境尚同，巖花開落爲誰容。',64,'全唐诗/poet.song.253000.json','["仙去時移境尚同，巖花開落爲誰容。", "歌沈石鼓泉空響，局冷紋枰霧半封。", "山上丹桃無核種，甑頭青䭀自機舂。", "翠眉不是人間儷，笑殺王孫不再逢。"]'),
('6da2cc02-710d-454b-8396-8985bb31e588','游金精山','胡平仲','宋','宋诗','song-poetry','','[]','人去壇空幾歷年，塵埃難沒漢山川。',64,'全唐诗/poet.song.253000.json','["人去壇空幾歷年，塵埃難沒漢山川。", "竇門深入壺中地，環壁遥開甕外天。", "致雨土龍如解化，隨時木鶴亦能仙。", "要知萬劫長生處，古篆惟存石鼓篇。"]'),
('4accd163-a7f0-4c43-bdc7-ca513db90258','學古體','侯丹','宋','宋诗','song-poetry','','[]','桐風吹月烏啼井，碧波濕露沈雲影。',64,'全唐诗/poet.song.253000.json','["桐風吹月烏啼井，碧波濕露沈雲影。", "素絲牽玉轉泉華，美人睡覺燕支冷。", "銀鉤挂簾北窗曉，翠鬟臨鏡雙鸞小。", "黄衫少年望不來，寂寂庭階滿春草。"]'),
('8a6a0987-9c62-4c94-8d93-e7ef33b0c740','題廣州光孝寺','林衢','宋','宋诗','song-poetry','','[]','開池曾記虞翻苑，列樹今存建德門。',64,'全唐诗/poet.song.253000.json','["開池曾記虞翻苑，列樹今存建德門。", "無客不觀丞相硯，有人曾悟祖師幡。", "舊煎訶子泉猶冽，新種菩提葉又繁。", "無奈益州經卷好，千絲絲縷未消痕。"]'),
('0fb53f94-0d06-48a1-824d-14b5035ff8d6','遊齊山寺','蘇元鼎','宋','宋诗','song-poetry','','[]','秋浦齊山寺，峰巒楚楚長。',120,'全唐诗/poet.song.253000.json','["秋浦齊山寺，峰巒楚楚長。", "巖根堆雁塔，溪角架虹梁。", "雨過聞幽磬，雲開見上方。", "苔侵石磴滑，花擁洞門香。", "禪客探玄切，騷人覓句忙。", "汲泉寒井廢，觀郡古樓荒。", "白鳥巢危樹，孤猿叫斷岡。", "碑珉黄閣相，詩板紫薇郎。", "蹤跡依稀在，文章大半亡。", "登臨正吟賞，惆悵見斜陽。"]'),
('0dd53785-6c84-41b6-8e8f-00eae08f1ade','閑居','甄圭','宋','宋诗','song-poetry','','[]','深塢人稀到，重門晝亦關。',48,'全唐诗/poet.song.253000.json','["深塢人稀到，重門晝亦關。", "白雲秋舍靜，明月夜窗閑。", "徑掩花開落，簾通燕往還。", "窮居聊自適，却憶謝東山。"]'),
('51626654-a195-4bd0-8df7-559aff274537','題西巖院','吳宣德','宋','宋诗','song-poetry','','[]','幽村分野徑，勝地絕浮埃。',48,'全唐诗/poet.song.253000.json','["幽村分野徑，勝地絕浮埃。", "殿閉烟霞靜，門臨水石開。", "日斜山影背，泉落雨聲來。", "故里經年別，祇園首重回。"]'),
('948c1688-6b36-4181-b583-cdcc9c7cdfae','答外','王瓊奴','宋','宋诗','song-poetry','','[]','茜色霞箋照面赬，玉郎何事太多情。',32,'全唐诗/poet.song.253000.json','["茜色霞箋照面赬，玉郎何事太多情。", "風流不是無佳句，兩字相思寫不成。"]'),
('2defa7fa-343f-4553-9bd7-6cf980be1e19','永安驛題柱','無名女子','宋','宋诗','song-poetry','','[]','無人解妾心，日夜長如醉。',24,'全唐诗/poet.song.253000.json','["無人解妾心，日夜長如醉。", "妾不是瓊奴，意與瓊奴會。"]'),
('f419a9ad-6410-43fe-b7b2-6649af0cac00','歌','裴道人','宋','宋诗','song-poetry','','[]','好酒吃三盞，好花插一枝。',24,'全唐诗/poet.song.253000.json','["好酒吃三盞，好花插一枝。", "思量今古事，安樂是便宜。"]'),
('c9f85e3c-f213-4af0-ad43-a981c79abc9f','絕句','洛浦道士','宋','宋诗','song-poetry','','[]','一水穿崖走碧沙，崖前樛木偃龍蛇。',32,'全唐诗/poet.song.253000.json','["一水穿崖走碧沙，崖前樛木偃龍蛇。", "分明便是桃源洞，不見溪中流落花。"]'),
('f91ef8a6-2beb-4f64-b83e-4cb650b701d1','句','惠津','宋','宋诗','song-poetry','','[]','饑殘夷叔丰姿瘦，泣盡娥英粉淚乾。',16,'全唐诗/poet.song.253000.json','["饑殘夷叔丰姿瘦，泣盡娥英粉淚乾。"]'),
('1b989e96-d8eb-408d-992d-4b3100398c2a','謁曹娥廟','釋及甫','宋','宋诗','song-poetry','','[]','輟棹江頭謁孝娥，斷碑枯柏尚嵯峨。',64,'全唐诗/poet.song.253000.json','["輟棹江頭謁孝娥，斷碑枯柏尚嵯峨。", "生爲女子既如此，身是男兒又若何。", "千古美名昭日月，一軀靈骨葬藤蘿。", "沈魂欲酹不知處，無限西風起碧波。"]'),
('562f9e3c-f554-45e6-86b8-149c88add03b','曹娥江','石林','宋','宋诗','song-poetry','','[]','一點冥通未兆前，乾坤虛鑑已昭然。',32,'全唐诗/poet.song.253000.json','["一點冥通未兆前，乾坤虛鑑已昭然。", "爛銀宮裏擎屍出，萬古傳聲浪拍天。"]'),
('1d558b3c-40a6-4c99-8445-c5beaaeef306','送夫從軍','楊氏婦','宋','宋诗','song-poetry','','[]','海壇門外浪滔天，妾上城樓君上船。',32,'全唐诗/poet.song.253000.json','["海壇門外浪滔天，妾上城樓君上船。", "回首西風深巷底，梅花霜月夜如年。"]'),
('5fddceb5-f5b0-4dc6-89cc-fd5f175d9a41','天衣故寺','宗瑩','宋','宋诗','song-poetry','','[]','園廟深關春寂寂，雨杉風檜翠蕭蕭。',32,'全唐诗/poet.song.253000.json','["園廟深關春寂寂，雨杉風檜翠蕭蕭。", "山中舊事無人說，碎疊唐碑補石橋。"]'),
('7e51b9b5-578a-4eb7-a850-42c0b1ba9868','絕句三首  其一','余知閣','宋','宋诗','song-poetry','','[]','幾年魂繞浙城西，十里荷花漾錦陂。',32,'全唐诗/poet.song.253000.json','["幾年魂繞浙城西，十里荷花漾錦陂。", "踏遍兩峰三竺路，又隨青嶂入雲棲。"]'),
('51d4068a-f4b8-4993-bb12-c246e42dd84d','絕句三首  其二','余知閣','宋','宋诗','song-poetry','','[]','洛邑名園歌舞沈，亂鴉啼破幾深林。',32,'全唐诗/poet.song.253000.json','["洛邑名園歌舞沈，亂鴉啼破幾深林。", "何人學得香山老，千載精廬有梵音。"]'),
('8e34e3ba-2aa2-4d9f-8005-f8b4ad33376b','絕句三首  其三','余知閣','宋','宋诗','song-poetry','','[]','千里旌旗擁六飛，投簪欲上釣魚磯。',32,'全唐诗/poet.song.253000.json','["千里旌旗擁六飛，投簪欲上釣魚磯。", "無端忽被閑雲引，迴耀峰前掩竹扉。"]'),
('0afd9096-4606-48fa-bd91-949789a77a1c','書園契上趙尚書','常省元','宋','宋诗','song-poetry','','[]','乾坤到處是吾亭，機械從來未必真。',64,'全唐诗/poet.song.253000.json','["乾坤到處是吾亭，機械從來未必真。", "覆雨翻雲成底事，清風明月冷看人。", "蘭亭禊事今非晉，桃洞神仙也笑秦。", "園是主人身是客，問君還有幾年身。"]'),
('431ae600-9f8a-40f5-ab5c-5907425ee694','石刻詩','無名氏','宋','宋诗','song-poetry','','[]','雨滴空階曉，無心換心香。',24,'全唐诗/poet.song.253000.json','["雨滴空階曉，無心換心香。", "井桐花落盡，一半在銀牀。"]'),
('2e2d0a77-21d9-4ed1-9f75-4962bb669643','宮詞二首  其一','無名氏','宋','宋诗','song-poetry','','[]','迎春燕子尾纖纖，拂柳穿花掠翠簷。',32,'全唐诗/poet.song.253000.json','["迎春燕子尾纖纖，拂柳穿花掠翠簷。", "聞道蘂宮三十六，美人爭爲捲珠簾。"]'),
('41c25423-ac48-40eb-a7fc-08b449040a64','宮詞二首  其二','無名氏','宋','宋诗','song-poetry','','[]','蓬萊風促水紋斑，月甃風廊數百間。',32,'全唐诗/poet.song.253000.json','["蓬萊風促水紋斑，月甃風廊數百間。", "雲外蹕聲穿嶺去，行宮簇馬望驪山。"]'),
('60c2f040-fef3-4bb6-aee8-45f884bad889','題太和樓壁','無名氏','宋','宋诗','song-poetry','','["\u897f\u6e56"]','太和酒樓三百間，大槽晝夜聲潺潺。',192,'全唐诗/poet.song.253000.json','["太和酒樓三百間，大槽晝夜聲潺潺。", "千夫承糟萬夫甕，有酒如海糟如山。", "銅鍋鎔盡龍山雪，金波湧出西湖月。", "星宮瓊漿天下無，九醖仙方誰漏泄。", "皇都春色滿錢塘，蘇小當壚酒倍香。", "席分珠履三千客，後列金釵十二行。", "一座行觴歌一曲，樓東聲斷樓西續。", "就中茜袖擁紅牙，春葱不露人如玉。", "今年和氣光華夷，遊人不醉終不歸。", "金貂玉塵寧論價，對月逢花能幾時。", "有箇酒仙人不識，幅巾大袖豪無敵。", "醉後題詩自不知，但見龍蛇滿東壁。"]'),
('6a1d1813-efee-4bee-8e77-0170380e1bdf','代意','無名氏','宋','宋诗','song-poetry','','[]','懊惱鴛鴦未白頭，却尋遺翠失芳洲。',64,'全唐诗/poet.song.253000.json','["懊惱鴛鴦未白頭，却尋遺翠失芳洲。", "離魂暗逐明珠佩，遠目偏傷紫桂樓。", "湘水渺瀰歸別渚，隴雲容與澹新秋。", "菖花若有重開日，得見菖花亦自羞。"]'),
('c6169979-7276-42ba-a4e9-17207e2cef9c','書西湖雷峰雲講主草書','無名氏','宋','宋诗','song-poetry','','["\u897f\u6e56"]','雲師一生耽作草，銀鐵蟠空覷天巧。',160,'全唐诗/poet.song.253000.json','["雲師一生耽作草，銀鐵蟠空覷天巧。", "老來逸氣未全平，筆底鋒鋩猶獨掃。", "開關勇士爭赴敵，劍戟弓戈奮相繚。", "睡龍沒起求頷珠，劃木抓巖紛怒爪。", "風雷喧豗撼坤軸，飛電交橫印清沼。", "忽然天宇變空澄，千丈孤峰立寒峭。", "張顛驚號智永泣，剝筋椎骨爲君飽。", "恨予不習草書訣，九轉枯腸祇自攪。", "雲師雲師汝誠能，春蚓秋蛇幾時了。", "何如認取主人翁，破衲蒙頭紙窗曉。"]'),
('7cca23c7-c435-410c-84a8-f8eec8f9abc3','白鶴觀題壁','無名氏','宋','宋诗','song-poetry','','[]','仙人未必皆仙去，還在人間人不知。',32,'全唐诗/poet.song.253000.json','["仙人未必皆仙去，還在人間人不知。", "手把白髦從兩鹿，相逢聊問姓名誰。"]'),
('1ece2eea-f129-4cba-ad6a-a54ceb73b947','裴公亭','無名氏','宋','宋诗','song-poetry','','[]','裴相亭成未退身，空煩舞袖與歌塵。',32,'全唐诗/poet.song.253000.json','["裴相亭成未退身，空煩舞袖與歌塵。", "至今亭上蕭蕭竹，似對西風怨主人。"]'),
('806ce9e7-6f3b-48dd-8196-493d8d204fc7','句','胡文媛','宋','宋诗','song-poetry','','[]','却有一端宜恨處，開花相背有何功。',16,'全唐诗/poet.song.253000.json','["却有一端宜恨處，開花相背有何功。"]'),
('97a2f9fa-0de8-43d9-82f3-83fad583418d','桂花','楚娘','宋','宋诗','song-poetry','','[]','丹桂迎風蓓蕾開，摘來斜插竟相偎。',32,'全唐诗/poet.song.253000.json','["丹桂迎風蓓蕾開，摘來斜插竟相偎。", "清香不與群芳並，仙種原從月裏來。"]'),
('13a4b977-b5ab-48bf-9a7c-c7d8c1bda5f7','答趙生紅梨花詩','謝金蓮','宋','宋诗','song-poetry','','[]','本分天然白雪香，誰知今日却濃妝。',32,'全唐诗/poet.song.253000.json','["本分天然白雪香，誰知今日却濃妝。", "秋千院落溶溶月，羞臯紅脂睡海棠。"]'),
('889e7806-6d39-4c44-a4d6-470609d6923d','絕句','謝慧卿','宋','宋诗','song-poetry','','[]','尋得桃源可學仙，丹書唯恐鳳飛傳。',32,'全唐诗/poet.song.253000.json','["尋得桃源可學仙，丹書唯恐鳳飛傳。", "雨收峰頂雲歸洞，風到池塘月滿天。"]'),
('f93b9f57-2367-4597-a4ad-b3147ec97d06','汎太湖','羅處純','宋','宋诗','song-poetry','','["\u592a\u6e56"]','三萬六千頃，湖侵海內田。',48,'全唐诗/poet.song.253000.json','["三萬六千頃，湖侵海內田。", "逢山方得地，見月始知天。", "南國吞將盡，東溟勢欲連。", "何當灑爲雨，無處不豐年。"]'),
('9d6f79db-f600-4b49-b703-dd684db33403','偃松','釋道章','宋','宋诗','song-poetry','','[]','得地久蟠踞，參天多晦冥。',48,'全唐诗/poet.song.253000.json','["得地久蟠踞，參天多晦冥。", "月通深夜白，雪壓歲寒青。", "獨擁虬腰大，疑聞雨甲腥。", "深根動坤軸，蕭瑟挂疏星。"]'),
('973082bf-0f5f-4ade-9ab2-7fd794aa6aec','登黄花亭遺址','錢元鼎','宋','宋诗','song-poetry','','[]','隔城舒晚嘯，信步得高臺。',48,'全唐诗/poet.song.253000.json','["隔城舒晚嘯，信步得高臺。", "亭去名猶在，霜遲菊未開。", "浮雲西日下，明月大江來。", "逸思飛難禁，昏鐘何處催。"]'),
('f4b81f11-6eba-4450-b108-323a1a6b6a1e','小孤山','傅文翁','宋','宋诗','song-poetry','','[]','灧澦拓瞿塘，二孤障瀾蠡。',24,'全唐诗/poet.song.253000.json','["灧澦拓瞿塘，二孤障瀾蠡。", "大哉神禹功，天地相終始。"]'),
('0fa44cd9-833a-4991-92b3-0358a4c3d3b1','綠波亭','衡泌','宋','宋诗','song-poetry','','[]','清淚斑斑灑綠波，年來轉覺別離多。',32,'全唐诗/poet.song.253000.json','["清淚斑斑灑綠波，年來轉覺別離多。", "扁舟南浦分携處，水遠山長愁奈何。"]'),
('70999385-e136-4147-a8a2-d013fdae3cc1','甘陂寺','董曇','宋','宋诗','song-poetry','','[]','曉發山間寺，籃輿冒朔風。',48,'全唐诗/poet.song.253000.json','["曉發山間寺，籃輿冒朔風。", "雪融溪漲碧，雲漏日穿紅。", "歲月塵埃裏，江山醉夢中。", "人生要家處，浪出笑龐公。"]'),
('be45d66c-7a5e-4787-ad62-1eab9c87d36d','龍巖寺','俞鼒','宋','宋诗','song-poetry','','[]','虬鬚公子真奇物，曾把英靈寄此山。',32,'全唐诗/poet.song.253000.json','["虬鬚公子真奇物，曾把英靈寄此山。", "鼓鬣掀髯天上去，空留遺跡在人間。"]'),
('2f2e9251-d478-45b3-b533-8d5a791349af','過至孝墓','吳城','宋','宋诗','song-poetry','','[]','過爲世希氏，史牒鮮著名。',192,'全唐诗/poet.song.253000.json','["過爲世希氏，史牒鮮著名。", "孰謂吾之邦，有以至孝稱。", "想其事雙親，誠恪通神明。", "身後一抔土，世猶不敢輕。", "樂公誠樂善，記名誓遺氓。", "偶讀靈禽碑，得之嘉不勝。", "吾邦有盛德，豈宜久沉冥。", "恨不訪遺冢，下拜涕泣零。", "又恨失名字，無以附汗青。", "自傷無贏貲，傍建旌孝亭。", "當使孝者見，事親堅其誠。", "且令頑悖兒，內愧面頰頳。", "因茲或改行，爲國省繁刑。", "徒將拙言句，頌詠播芳馨。", "蒿茨莫浪剪，牛羊勿妄登。", "過者宜下馬，呵護煩山靈。"]'),
('69e139c8-fbb0-4075-bd07-912f57eb6926','石䂬','熊邦彥','宋','宋诗','song-poetry','','[]','萬壑雲霾凝不消，橫空突起老龍腰。',32,'全唐诗/poet.song.253000.json','["萬壑雲霾凝不消，橫空突起老龍腰。", "虛皇未放拏雲去，留與金仙作石橋。"]'),
('812e73c3-18f7-43b2-957c-db5e78da62ea','筆架山','辛好禮','宋','宋诗','song-poetry','','[]','清秋山水無不宜，筆架之峰天下奇。',64,'全唐诗/poet.song.253000.json','["清秋山水無不宜，筆架之峰天下奇。", "高蟠斗極鳥先却，幽測珠光龍未知。", "天清鐘磬度霄轉，月黑星河當戶垂。", "却念浮丘應識我，滿空風雨遴新詩。"]'),
('aaad29e6-ffa0-4e47-9856-2b35e4b737eb','明水寺','章藻之','宋','宋诗','song-poetry','','[]','環山清淺一溪水，夾逕高低十里松。',32,'全唐诗/poet.song.253000.json','["環山清淺一溪水，夾逕高低十里松。", "煙鎖石門疑路斷，斜陽影裏忽聞鐘。"]'),
('b4c1b68c-2edf-4f5d-b7b0-134f849b523a','曹山寺','黄漳','宋','宋诗','song-poetry','','[]','晚宿曹山寺，僧房半劫灰。',48,'全唐诗/poet.song.253000.json','["晚宿曹山寺，僧房半劫灰。", "參差惟古柏，潦倒有寒梅。", "行役經年邁，勞形覺鬢頹。", "閒情原不減，空憶菊花杯。"]'),
('468600b7-cf29-458b-9b67-55805c1ba02e','卓望山','黄漳','宋','宋诗','song-poetry','','[]','簿領紛迷日不閒，偶因佳節一登山。',64,'全唐诗/poet.song.253000.json','["簿領紛迷日不閒，偶因佳節一登山。", "風飄木葉雁初到，霜度巖籬菊漸班。", "與客不妨長送酒，對時聊爾暫開顔。", "凭欄萬頃黄雲熟，猶恐民生尚苦艱。"]'),
('123a7144-3413-4f18-8357-b36941bfd48e','鳳山','黄漳','宋','宋诗','song-poetry','','[]','鳳山之嶺高岧嶢，上有仙人吹洞簫。',64,'全唐诗/poet.song.253000.json','["鳳山之嶺高岧嶢，上有仙人吹洞簫。", "俯瞰衆流浩無際，縱觀萬壑亦來朝。", "衣冠幸際承明日，壺矢況逢拔俗標。", "長嘯一聲海天闊，凌風毛髪故蕭蕭。"]'),
('1d5ff37f-3ba3-4c99-9638-29fbe464d540','曹山','鄒毅','宋','宋诗','song-poetry','','[]','白雲深處到林丘，曹洞根深地更幽。',64,'全唐诗/poet.song.253000.json','["白雲深處到林丘，曹洞根深地更幽。", "聖隠巖前山杳杳，迴龍亭下水悠悠。", "凉侵客枕秋風活，光抱禪關桂影秋。", "塵足未堪康樂屐，得閒聊伴省郎遊。"]'),
('bf6571c2-faa0-4a94-800e-189859631f23','玉山觀','李北之','宋','宋诗','song-poetry','','[]','巒岡經亙翠環中，中有山形如覆鏞。',227,'全唐诗/poet.song.253000.json','["巒岡經亙翠環中，中有山形如覆鏞。", "晉仙王郭曾登眺，名形婺女金華同。", "懸崖積鐵數百尺，輪囷老木參天碧。", "時有金雞擊膊鳴，鏗鍧響通石屋石。", "石屋去山三里餘，潭潭若有神龍居。", "漁人爬{瓜少}入深處，聞得山椒奏步虛。", "山趾有觀名玉山，黄冠分得葛仙班。", "家無擔石四壁立，披風切月陪往還。", "我師率庵龐眉老，故園跨鶴迷仙島。", "道號艮齋曾品題，椽筆特書爲摛藻。", "千載一遇邑大夫，來問勝境形何模。", "片言擬作詩中句，羞獻人家水墨圖。", "倚風太息來何暮，入境發揮方得路。", "願言葺理芰荷衣，青天白日披雲霧。"]'),
('07ceed31-0761-4ef9-a689-d5047e30c7cc','曹山寺','釋晦山','宋','宋诗','song-poetry','','[]','千年荷玉紫雲蟠，偶翳浮塵影欲寒。',32,'全唐诗/poet.song.253000.json','["千年荷玉紫雲蟠，偶翳浮塵影欲寒。", "不是老人重着力，雨花洞口棘漫漫。"]'),
('0fcd7742-c739-4454-8c08-85634a716ab8','禪峰寺','饒南强','宋','宋诗','song-poetry','','[]','禪山喬木飽蒼烟，柿葉能來老鄭虔。',32,'全唐诗/poet.song.253000.json','["禪山喬木飽蒼烟，柿葉能來老鄭虔。", "樓閣暮寒風鐵定，與僧分展對牀眠。"]'),
('c92225e0-23b9-4d23-81d2-640c0d136111','游裴公亭  其一','趙恒','宋','宋诗','song-poetry','','[]','昔年曾此遠風塵，盤谷烟霞每見分。',64,'全唐诗/poet.song.253000.json','["昔年曾此遠風塵，盤谷烟霞每見分。", "萬里江河還壯觀，一時冠蓋屬元勳。", "海鷗春暖眠沙草，遼鶴秋高度嶺雲。", "今日重來倍惆悵，草堂應是勒移文。"]'),
('9510eb3e-bee5-43e6-90c2-e859b5fdc6da','游裴公亭  其二','趙恒','宋','宋诗','song-poetry','','[]','溶溶春水碧生池，上相臨觀許從隨。',64,'全唐诗/poet.song.253000.json','["溶溶春水碧生池，上相臨觀許從隨。", "萬姓歌呼喜遊豫，幾人出處佩安危。", "雨餘空谷雲歸早，風滿長林鳥下遲。", "笳鼓明當催曉發，柳烟花露溼旌旗。"]'),
('a5503354-dcdb-4828-844b-e284e6680de9','汲水詩','李氏','宋','宋诗','song-poetry','','[]','汲水佳人立曉風，青絲輾盡轆轤空。',32,'全唐诗/poet.song.253000.json','["汲水佳人立曉風，青絲輾盡轆轤空。", "銀瓶觸破殘粧影，零亂桃花滿井紅。"]'),
('48046088-eb96-4ebe-813a-76bb87d138d8','書懷','李氏','宋','宋诗','song-poetry','','[]','門對雲霄碧玉流，數聲漁笛一江秋。',32,'全唐诗/poet.song.253000.json','["門對雲霄碧玉流，數聲漁笛一江秋。", "衡陽雁斷楚天闊，幾度潮來問故舟。"]'),
('985de6db-e0f3-428a-99c9-6fcb5897dce2','句','李氏','宋','宋诗','song-poetry','','[]','清朝富貴利名在，結髪夫妻日月長。',16,'全唐诗/poet.song.253000.json','["清朝富貴利名在，結髪夫妻日月長。"]'),
('0abf4862-fafc-4927-b890-2bf951f17131','碧沼寺','丁倣','宋','宋诗','song-poetry','','[]','萬峰翠插鎖縈紆，一沼光涵湛碧虛。',64,'全唐诗/poet.song.253000.json','["萬峰翠插鎖縈紆，一沼光涵湛碧虛。", "馴虎舊聞輸野鹿，化龍俄已失金魚。", "白蓮尚結高僧社，古木全荒隠士廬。", "襥被須期借禪榻，盡穿犖确與崎嶇。"]'),
('0ddd2f46-c03e-4ebe-870e-08728afca88b','瀫波亭  其一','徐慥','宋','宋诗','song-poetry','','[]','瀫波亭下晚維舟，縹緲烟屏翠欲流。',64,'全唐诗/poet.song.253000.json','["瀫波亭下晚維舟，縹緲烟屏翠欲流。", "忽地驚雷過溪面，連天吹雪下山頭。", "汀洲瑟縮藏鷗鷺，涯涘瀰漫失馬牛。", "自笑勞生日蒼鬢，不知來往竟何求。"]'),
('e55b74aa-1eb5-4611-93ad-81f69a580fe1','瀫波亭  其二','徐慥','宋','宋诗','song-poetry','','[]','古縣幽亭勝景多，青春啼鳥每相過。',64,'全唐诗/poet.song.253000.json','["古縣幽亭勝景多，青春啼鳥每相過。", "林間石磬風敲竹，水面金蛇日漾波。", "得友且須頻載酒，愛山何必更捫蘿。", "我來欲作無何醉，爲子敲盤試一歌。"]'),
('c7829998-5f1c-4e86-99b2-52f0fef531b2','龍邱山','陳舉愷','宋','宋诗','song-poetry','','[]','九峰濕翠秋光凝，亭亭出水芙蓉凈。',96,'全唐诗/poet.song.253000.json','["九峰濕翠秋光凝，亭亭出水芙蓉凈。", "崔巍怪石距若虎，合沓奇峰馳八駿。", "山深古寺隔紅塵，時有天風度幽磬。", "豈惟清賞玩心目，况有高人寄真隠。", "自慚奔走紅塵客，何由得遂山林性。", "長歌聊復賦重游，不用懸巖刻名姓。"]'),
('38f4c953-aebf-4da0-a217-1c26c7801c4a','過姑蔑道中','陳舉愷','宋','宋诗','song-poetry','','[]','姑蔑古城暮，山川近不同。',48,'全唐诗/poet.song.253000.json','["姑蔑古城暮，山川近不同。", "草黄秋過雨，樹暗晚生風。", "流水中分郭，飛橋下應虹。", "未須追往事，回首送冥鴻。"]'),
('1bbbfb13-3e94-4e8f-b341-145e73be48a5','翠光巖','鄭得彝','宋','宋诗','song-poetry','','[]','一棹巨川舟，相隨物外遊。',48,'全唐诗/poet.song.253000.json','["一棹巨川舟，相隨物外遊。", "芳塵曾未逐，春興若爲酬。", "酌石花陰濕，題巖蘚墨浮。", "沙鷗應笑我，留住瀫溪頭。"]'),
('fe60516d-be06-4bd5-a831-2fd42b103264','龍游八景','鄭得彝','宋','宋诗','song-poetry','','[]','雨急林花第幾峰，層層巖翠沐嵌空。',32,'全唐诗/poet.song.253000.json','["雨急林花第幾峰，層層巖翠沐嵌空。", "回頭萬象皆生意，綠遍天涯造化功。"]'),
('13fd70fb-6f68-4fb4-a255-5108f7a9eba4','龍游八景 瀫水晴風','鄭得彝','宋','宋诗','song-poetry','','[]','鮫鮹藍色染初勻，風皺粼粼渺水雲。',32,'全唐诗/poet.song.253000.json','["鮫鮹藍色染初勻，風皺粼粼渺水雲。", "安得此溪還姓冉，名高千載柳州文。"]'),
('68734fad-2d30-400f-a49c-418afba54cdb','龍游八景 雙港明月','鄭得彝','宋','宋诗','song-poetry','','[]','沄沄逝水夾滄洲，金耀浮光碎碧流。',32,'全唐诗/poet.song.253000.json','["沄沄逝水夾滄洲，金耀浮光碎碧流。", "夜半漁歌聲再起，一天明月兩溪秋。"]'),
('2d24c657-a54f-437e-bb92-a7a4786f79c4','龍游八景 半山殘雪','鄭得彝','宋','宋诗','song-poetry','','[]','寒峰蒼削露痕晴，殘雪遥疑宿凍雲。',32,'全唐诗/poet.song.253000.json','["寒峰蒼削露痕晴，殘雪遥疑宿凍雲。", "茶話尚餘清絕趣，半甌真味許僧分。"]'),
('19728c45-0eb0-4b66-a921-5a1a2ed9988f','龍游八景 漁村夕照','鄭得彝','宋','宋诗','song-poetry','','[]','小艇穿魚醉夕陽，柔條猶可折殘楊。',32,'全唐诗/poet.song.253000.json','["小艇穿魚醉夕陽，柔條猶可折殘楊。", "數家網罟孤村外，漁唱一聲烟水長。"]'),
('c102b33f-1156-41d9-a07d-65bc91e94816','龍游八景 別浦歸帆','鄭得彝','宋','宋诗','song-poetry','','[]','望斷烟波眼欲空，霞光明襯暮天紅。',32,'全唐诗/poet.song.253000.json','["望斷烟波眼欲空，霞光明襯暮天紅。", "水高數尺舟歸急，幅幅蒲帆飽受風。"]'),
('26cbb34a-e365-485d-860f-e90d1ca4ab71','龍游八景 斷岸浮梁','鄭得彝','宋','宋诗','song-poetry','','[]','輕舠簇簇水溶溶，影落空江萬丈虹。',32,'全唐诗/poet.song.253000.json','["輕舠簇簇水溶溶，影落空江萬丈虹。", "溱洧更無人病涉，浮梁千載紀成功。"]'),
('38ae8f12-b076-4b21-9007-2d29fde1b09d','龍游八景 村市曉烟','鄭得彝','宋','宋诗','song-poetry','','[]','微茫村市隠江湄，三兩人家欲早炊。',32,'全唐诗/poet.song.253000.json','["微茫村市隠江湄，三兩人家欲早炊。", "翠箔樓臺烟半濕，不知紅日上花枝。"]'),
('412cd843-fb88-48be-a746-74c764a83445','剡溪','倪光蘭','宋','宋诗','song-poetry','','[]','東山山下海潮通，一片江流出鏡中。',64,'全唐诗/poet.song.253000.json','["東山山下海潮通，一片江流出鏡中。", "度嶺拾薪歌稚子，和烟牧犢走村翁。", "千年橋鎖高人跡，百丈巖垂烈女風。", "此去天台知幾許，桃花深處失西東。"]'),
('0c9478e0-1cfa-4b51-a649-0d76a5cc60cd','寶積寺','過守約','宋','宋诗','song-poetry','','[]','層楹寶勢壓禪扃，俗眼塵昏到易醒。',64,'全唐诗/poet.song.253000.json','["層楹寶勢壓禪扃，俗眼塵昏到易醒。", "千幰樹排車蓋翠，萬螺山矗佛頭青。", "夜將溪月澄心鏡，春把巖花作畫屏。", "我欲期師不須出，世途今險甚東溟。"]'),
('c118d62e-185b-43ca-a072-cf654705314e','咏月桂峰桂子','釋慈永','宋','宋诗','song-poetry','','[]','丹桂生瑶寶，千年會一時。',72,'全唐诗/poet.song.253000.json','["丹桂生瑶寶，千年會一時。", "偏從天竺落，祇向月宮知。", "出海冰輪滿，當軒玉樹遲。", "清暉含遠嶠，接影下空墀。", "金氣風初勁，銀河露恐垂。", "嬋娟應悵望，果爾見蛾眉。"]'),
('1ea872af-1a91-4b23-b1db-4a3ba83db52a','錢塘','邱道源','宋','宋诗','song-poetry','','[]','南屏高瞰府城西，畫舸千艘共醉迷。',64,'全唐诗/poet.song.253000.json','["南屏高瞰府城西，畫舸千艘共醉迷。", "四柱臺邊烟是幕，百花橋畔葑連堤。", "龍壇咽路迎轝隼，綺繡登山汙粉題。", "暮色沉沉郊郭閉，寶燈輝映梵天低。"]'),
('2d456a78-3368-4699-9e18-05c0f65e13b0','龍華山','懶漁','宋','宋诗','song-poetry','','[]','梵王宮倚市廛開，波劫何曾斷俗埃。',64,'全唐诗/poet.song.253000.json','["梵王宮倚市廛開，波劫何曾斷俗埃。", "百萬源流歸海會，三千世界屬如來。", "老龍收雨藏香缽，野鶴聽經繞法臺。", "聞道題名還有塔，熙寧四老總多才。"]'),
('4adce904-4bd7-4761-b169-7ea8357ce93b','過蕪留詠','南野','宋','宋诗','song-poetry','','[]','湖山夢不到襄闈，六載沈酣一出遲。',64,'全唐诗/poet.song.253000.json','["湖山夢不到襄闈，六載沈酣一出遲。", "漁子能言飛渡處，市翁親見潰師時。", "權臣貴戚戈相藉，北槳南檣風背馳。", "事逐孤鴻今已矣，年年水落荻芽肥。"]'),
('0fd71908-6322-4b8d-a423-d480694a0e86','游延福寺','趙曾頀','宋','宋诗','song-poetry','','[]','行行出西郊，稍覺囂塵遠。',216,'全唐诗/poet.song.253000.json','["行行出西郊，稍覺囂塵遠。", "風景既已殊，磽确頗忘倦。", "南安古雄州，今亦壯哉縣。", "九日一佳景，居然在郊甸。", "地高瞰川原，林杪露堂殿。", "晉朝松百章，存者才一見。", "歲月不我留，寒暑幾更變。", "當年秦隠君，軒冕非所羨。", "間關剡溪來，至此獲勝踐。", "結廬巢其巔，穴石爲之硯。", "城市不到足，公卿罕窺面。", "邂逅有至交，相從情繾綣。", "緬懷興元年，致位在台鉉。", "扶持公道開，不絕幾如綫。", "一言才見疏，斥逐遽遭譴。", "天教流落餘，乃遂山林願。", "當年築室處，遺址了難辨。", "獨有高士峰，千載猿鶴怨。"]'),
('e2ffe75f-348c-4b52-8d34-6454ba8e8598','九日山中宴集','趙源','宋','宋诗','song-poetry','','[]','九日登臨老奈何，强將幽恨寄悲歌。',64,'全唐诗/poet.song.253000.json','["九日登臨老奈何，强將幽恨寄悲歌。", "疲欹巾帽愁風動，病著饑腸厭酒多。", "東嶺荒榛藏馬鬣，西岩空榻鎖蜂窠。", "獨憐堂下千章木，跨歷齊梁未改柯。"]'),
('1f4cd6ab-711c-4bdf-a319-70fec3a436b7','顧王遺址','易時敏','宋','宋诗','song-poetry','','[]','遠樹芊芊暮靄平，顧王曾此保孤城。',64,'全唐诗/poet.song.253000.json','["遠樹芊芊暮靄平，顧王曾此保孤城。", "雷封已并田同井，烟爨猶疑竈滿營。", "當代貔貅誰削迹，芳春杜宇自呼名。", "黍離行邁應相似，倍感詩家咏嘆情。"]'),
('0969b173-221f-4161-83cd-76c17b338ed6','陽樂故城','易時敏','宋','宋诗','song-poetry','','[]','典午河山尚有名，興從陽樂故城生。',64,'全唐诗/poet.song.253000.json','["典午河山尚有名，興從陽樂故城生。", "夕陽門巷丘墟久，春草池塘野水平。", "廢堞棲烏啼夜月，閑壕留雁叫寒更。", "人民非處桃花在，一度東風一度榮。"]'),
('6222612d-a374-4cb3-8914-095c8b66e185','聖濟院','況師點','宋','宋诗','song-poetry','','[]','迢迢幽徑入松關，四面雲藍分外寒。',32,'全唐诗/poet.song.253000.json','["迢迢幽徑入松關，四面雲藍分外寒。", "長嘯一聲山谷應，洞深驚起老龍蟠。"]'),
('9aded692-0237-48f0-b11e-f10b7359d4d5','遊枋口','姜正','宋','宋诗','song-poetry','','[]','山如削玉水涵秋，人在冰壺月底遊。',32,'全唐诗/poet.song.253000.json','["山如削玉水涵秋，人在冰壺月底遊。", "劫火半空塵世換，不知此處幾登舟。"]'),
('dc706f8f-07d7-44f4-847c-bb64f70f3bec','裴公亭二首  其一','孫翥','宋','宋诗','song-poetry','','[]','太行王屋群峰上，秦晉關河望處分。',64,'全唐诗/poet.song.253000.json','["太行王屋群峰上，秦晉關河望處分。", "猿鶴幾年懷舊隠，乾坤百戰重儒勳。", "龍歸洞府暮將雨，僧過浮橋曉度雲。", "萬里中原無事日，不妨尊酒細論文。"]'),
('f3f20a44-adac-4c40-afd1-811b952d9f6e','裴公亭二首  其二','孫翥','宋','宋诗','song-poetry','','[]','風有亭臺月有池，春深猿鶴喜追隨。',64,'全唐诗/poet.song.253000.json','["風有亭臺月有池，春深猿鶴喜追隨。", "水從王屋泉初旺，山過秦關勢欲危。", "仙樂靜依林鳥奏，浮雲輕伴海鷗遲。", "斜陽不盡登臨興，遠樹微茫入酒旗。"]'),
('4df109db-a2bf-42e2-b45a-b2c40ceb34ae','春日遊盤谷','孫翥','宋','宋诗','song-poetry','','[]','旌斾朝驅入翠微，東風閑訪故山薇。',64,'全唐诗/poet.song.253000.json','["旌斾朝驅入翠微，東風閑訪故山薇。", "金龜換酒留僧住，白鶴穿雲伴客歸。", "月影坐移棲鳳竹，泉聲靜繞釣魚磯。", "中原那似開元日，得學巢由遠是非。"]'),
('2c1833f0-f2b0-46b5-aec3-412ca98de970','登九華山','曹清','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','浮生江路水茫茫，彭澤原非令故鄉。',64,'全唐诗/poet.song.253000.json','["浮生江路水茫茫，彭澤原非令故鄉。", "爲訪子明尋玉澗，也因太白宿雲房。", "詩摩古壁搜遺韻，井煉丹砂辨舊方。", "從此欲歸情復結，擬移亭舍築山傍。"]'),
('e72e548e-3053-4a7a-8a88-6136c0d8128c','毘陵太平院壁間畫山水熟視之有飛動勢殆仙筆也','林景清','宋','宋诗','song-poetry','','[]','山風不動雲四寂，萬頃波濤生素壁。',128,'全唐诗/poet.song.253000.json','["山風不動雲四寂，萬頃波濤生素壁。", "三峽夜怒摇星河，九溟晝沸卷霹靂。", "誰將江海一筆吞，華陽入硯玄波翻。", "靈鼇東轉坤軸動，驚浪出沒蛟與黿。", "毫端分寸千萬里，人心之險亦如此。", "老僧閲世如閲畫，面壁凝然悟玄理。", "嗟余老作汗漫游，寒光飛動六月秋。", "乃知瞿唐在平陸，安得竹葉吹成舟。"]'),
('1446e13c-fb06-428d-b5a8-30027df95b05','蔡琰歸漢圖','林景清','宋','宋诗','song-poetry','','[]','文姬別子地，一騎輕南馳。',192,'全唐诗/poet.song.253000.json','["文姬別子地，一騎輕南馳。", "傷哉賢王北，一騎挾二兒。", "二兒抱父啼，問母何所之。", "停鞭屢回首，重會知無期。", "孰謂天壤內，野心無人彝。", "萬物以類偶，濕化猶相隨。", "穹廬况萬里，日暮驚沙吹。", "惜哉辨琴智，不辨華與夷。", "縱憐形勢迫，難掩節義虧。", "獨有思漢心，寫入哀絃知。", "一朝天使至，千金贖蛾眉。", "雨露洗腥瘢，陽和變愁姿。", "出關拜漢月，照妾心苦悲。", "妾心儻未白，何以覲彤墀。", "狐死尚丘首，越鳥終南枝。", "如何李都尉，沒齒陰山陲。"]'),
('e405f212-b0d7-4c27-b512-a9b8b8d70cab','菊花  其一','方九功','宋','宋诗','song-poetry','','[]','露冷江蘋雁度時，蕭蕭黄菊滿疏籬。',64,'全唐诗/poet.song.253000.json','["露冷江蘋雁度時，蕭蕭黄菊滿疏籬。", "寒枝带雨開仍艷，晚節凌霜賞未遲。", "移傍小簷承綺席，從觀深夜倒金巵。", "摘來冉冉香盈把，共泛西風醉莫辭。"]'),
('baaff1e7-39c8-4835-bd59-701feae4eaac','菊花  其二','方九功','宋','宋诗','song-poetry','','[]','莫惜寒花開太晚，孤懷深喜客來雙。',64,'全唐诗/poet.song.253000.json','["莫惜寒花開太晚，孤懷深喜客來雙。", "疏枝最耐存霜圃，晚節偏宜映月窗。", "同調自應蘭是籍，濁醪何有玉爲缸。", "籬邊無限陶潜興，倒著綸巾醉未降。"]'),
('35c6346e-33f2-411a-8559-82f90752a464','柳絮','孫文叔','宋','宋诗','song-poetry','','[]','宮柳垂垂拂苑牆，啼鶑驚夢暗心傷。',32,'全唐诗/poet.song.253000.json','["宮柳垂垂拂苑牆，啼鶑驚夢暗心傷。", "起來羞見空中絮，也得隨風入御牀。"]'),
('545b371f-b3f3-4523-b9cd-7e8b38ae0398','浮萍','劉師邵','宋','宋诗','song-poetry','','[]','乍因輕浪疊晴沙，又趁迴風擁釣槎。',32,'全唐诗/poet.song.253000.json','["乍因輕浪疊晴沙，又趁迴風擁釣槎。", "莫怪狂蹤易飄泊，前身不合是楊花。"]'),
('8e3e8be4-36c4-432c-8d3a-28ad16b810c0','遊靈隠寺','道諫','宋','宋诗','song-poetry','','[]','長吟遊古寺，九里入青松。',48,'全唐诗/poet.song.253000.json','["長吟遊古寺，九里入青松。", "鳥向花間語，僧從月下逢。", "陰廊連碧殿，清磬雜疏鐘。", "回首夕陽晚，烟霞鎖亂峰。"]'),
('d2b782da-9cf7-4a14-a0b9-515ced546026','詠花扇','崖州女子','宋','宋诗','song-poetry','','[]','團扇畫方新，金花照席茵。',24,'全唐诗/poet.song.253000.json','["團扇畫方新，金花照席茵。", "那緣燈下見，更值月中人。"]'),
('8063efe9-aa5b-4f06-ae8e-4c5d9c4fec5a','無弦琴','止翁','宋','宋诗','song-poetry','','[]','月作金徽風作弦，清音不在指端傳。',32,'全唐诗/poet.song.253000.json','["月作金徽風作弦，清音不在指端傳。", "有時彈罷無生曲，露滴松梢鶴未眠。"]'),
('dd26b7c2-d3a5-44fd-8549-4d62f6e39c4c','寄元驤卿','朱逸仙','宋','宋诗','song-poetry','','[]','郎今多病如家令，妾自拚躬怨楚王。',32,'全唐诗/poet.song.253000.json','["郎今多病如家令，妾自拚躬怨楚王。", "斜壓玉釵成獨夢，低垂玄髪繫柔腸。"]'),
('5b297751-b4c4-4815-86b3-b266b627ca0f','寄衣','鄧氏','宋','宋诗','song-poetry','','[]','欲寄寒衣上帝都，連宵裁剪眼模糊。',32,'全唐诗/poet.song.253000.json','["欲寄寒衣上帝都，連宵裁剪眼模糊。", "可憐寬窄無人試，淚逐西風灑去途。"]'),
('ab913b13-4b7c-4d49-99e0-494c936d764d','棲雲閣','無名氏','宋','宋诗','song-poetry','','[]','倚天危閣貼重岡，細路縈紆石磴長。',32,'全唐诗/poet.song.253000.json','["倚天危閣貼重岡，細路縈紆石磴長。", "曲磵碧流疏宿雨，夾山紅葉助斜陽。"]'),
('8733f100-7c5a-45cc-b7c4-cdeeb1e0b81e','詠酒','徐文瀾','宋','宋诗','song-poetry','','[]','才傾一盞碧澄澄，自是山妻手法成。',64,'全唐诗/poet.song.253000.json','["才傾一盞碧澄澄，自是山妻手法成。", "不遣水多防味薄，要令麴少得香清。", "凉從荷葉風邊起，暖向梅花月裏生。", "世味總無如此味，深知此味即淵明。"]'),
('624d85ff-ae96-46b7-843d-8f64dd9361d2','首陽山行','郭士道','宋','宋诗','song-poetry','','[]','首陽山，青巃嵷。',242,'全唐诗/poet.song.253000.json','["首陽山，青巃嵷。", "上聳紫蓋凌瑶空，下周林壑盤蒼龍。", "嵯峨自太古，崒嵂鎮寰中。", "黄河西來遶其下，日夕雲氣開鴻濛。", "恍疑鬼神護，又似丹青工。", "諸峰不敢並，蒼翠光玲瓏。", "我生癖性愛山水，見此奇絕摩雙瞳。", "忽憶武王收諸夏，夷齊叩馬來山東。", "風雲變化適際會，恥逐龍虎爭奇功。", "歸來守岩穴，鬰鬰抱孤忠。", "朝采山上蕨，暮拾山下蓬。", "渴飲澗中水，熱眠雲外松。", "既不學赤松子，又不侶商山翁。", "丹誠耿耿照白日，勁節凜凜摩蒼穹。", "首陽青青萬古色，不改夷齊之心胸，直與天地相始終。", "千載扶名教，二子功無窮。", "我歌首陽歌未歇，泠然八表生清風。"]'),
('667d91a3-68ac-4d84-b66c-8b1778792070','凉軒','王秠','宋','宋诗','song-poetry','','[]','異政豐餘暇，新軒雅構成。',48,'全唐诗/poet.song.253000.json','["異政豐餘暇，新軒雅構成。", "雲成簷外落，魂自座中清。", "盡日松風響，通宵花月明。", "琴觴暫舒嘯，才用即登瀛。"]'),
('e3e75ad8-fcfe-42a1-bf3f-d9ed76941f89','凌雲臺','李中立','宋','宋诗','song-poetry','','[]','山圍平野四迴環，天迥臺高眼界寬。',64,'全唐诗/poet.song.253000.json','["山圍平野四迴環，天迥臺高眼界寬。", "雲漏殘陽明遠岫，濤翻急雨漲前灘。", "一川勝趣四時好，千里雄風三伏寒。", "誰見凌雲清絕處，夜凉空翠濕闌干。"]'),
('60e6ca65-a7ce-4330-bbe0-2f1c70cca9a5','廣勝寺','新若通','宋','宋诗','song-poetry','','[]','吾黨登臨興，亭高眼更明。',48,'全唐诗/poet.song.253000.json','["吾黨登臨興，亭高眼更明。", "雲深山斷續，川闊路縱橫。", "突兀媧皇塚，荒蕪簡子城。", "古來那可問，林外晚風生。"]'),
('846d8c48-deb0-4faf-9069-d38c60b5e58a','廣勝寺','王淵亭','宋','宋诗','song-poetry','','[]','春嶺碧嵯峨，公餘載酒過。',48,'全唐诗/poet.song.253000.json','["春嶺碧嵯峨，公餘載酒過。", "紅塵隨地少，野意近山多。", "泉溜寒鳴玉，楊花碎剪羅。", "歸衫未能著，斜日上松坡。"]'),
('b573f5c4-8e24-41bc-8366-ae974f83faed','魏侯故城','袁藏雲','宋','宋诗','song-poetry','','[]','獨向條陽翠靄行，杖藜徐步愴吟情。',64,'全唐诗/poet.song.253000.json','["獨向條陽翠靄行，杖藜徐步愴吟情。", "長河漫有懷山迹，故國空傳讓畔名。", "遠樹半遮干木廟，斷雲猶鎖魏侯城。", "可憐列土繁華地，祇是寥寥作釣耕。"]'),
('f4c23099-7fa8-4c1f-a167-5079dfd5ed4e','堯廟','孫景文','宋','宋诗','song-poetry','','[]','帝廟乘山勢，巍巍古柏中。',48,'全唐诗/poet.song.253000.json','["帝廟乘山勢，巍巍古柏中。", "治雖爲日遠，仁尚與天同。", "堂陛嚴遺像，川原隠舊風。", "時時有靈異，此語出田翁。"]'),
('d01b16db-dd2d-41ab-8db8-7514b134b377','登洪慶觀河亭','高昌','宋','宋诗','song-poetry','','[]','霜旄行郡試尋幽，一曲圍垣遶縣周。',64,'全唐诗/poet.song.253000.json','["霜旄行郡試尋幽，一曲圍垣遶縣周。", "山色迎人來黛嵋，河聲驚夢撼黄流。", "禹門水逈鄉關月，濟廟烟連草樹秋。", "遥指天南嵩洛近，烟雲何處望神州。"]'),
('d7b6b28b-9264-423c-ad6b-748767712ce2','冬日觀河清','馬世德','宋','宋诗','song-poetry','','[]','邑宰崇明祀，侵晨苦見邀。',48,'全唐诗/poet.song.253000.json','["邑宰崇明祀，侵晨苦見邀。", "未能乘快騎，且復御輕軺。", "瑞應黄流碧，晴清戾氣消。", "今朝風日暖，臨水且逍遥。"]'),
('a391123b-40a6-4856-b066-ffb613e56314','五臺山和韻','史監','宋','宋诗','song-poetry','','[]','群峰歷盡到巔巒，極目清凉境界寬。',64,'全唐诗/poet.song.253000.json','["群峰歷盡到巔巒，極目清凉境界寬。", "山入雁門真設險，地藏佛國即長安。", "雨來絕澗自成響，雲渡遠溪時作團。", "花落經臺鐘梵寂，袈裟香靄翠雲蟠。"]'),
('ab130bbc-6fd0-4eba-90e1-a9961aecbac4','登洪慶觀','適宜','宋','宋诗','song-poetry','','[]','行到蓬萊第一宮，却慚仙路印塵蹤。',64,'全唐诗/poet.song.253000.json','["行到蓬萊第一宮，却慚仙路印塵蹤。", "界開形勢崑崙水，送過烟嵐黛嵋峰。", "經夏定知非暑氣，乘時猶逮看秋容。", "不才佳景難爲賦，空立斜陽倚瘦筇。"]'),
('ca3ac8a3-e412-4e5a-8f81-4a22b2df961e','廣勝寺','藍諫礬','宋','宋诗','song-poetry','','[]','一上危亭倚翠微，曠然懷抱失塵機。',64,'全唐诗/poet.song.253000.json','["一上危亭倚翠微，曠然懷抱失塵機。", "天遥流水分明去，野闊輕雲自在飛。", "歲景又看梅已落，鄉心還見雁將歸。", "紛紛戰國無窮事，今日誰能說是非。"]'),
('0db3e9e8-d294-4094-be2a-50dfbae9e28a','題迎薰閣','張硯','宋','宋诗','song-poetry','','[]','解慍風來處，朱甍起舊城。',120,'全唐诗/poet.song.253000.json','["解慍風來處，朱甍起舊城。", "條山供偃蹇，鹽澤借澄泓。", "龍廟疑飛出，蓮宮若化成。", "亂雲堆素彩，遠溜集幽聲。", "逸驥騰前路，鳴鳶激去程。", "散眸襟抱爽，翹首骨毛清。", "歡席多嘉客，豐郊少困氓。", "鼓琴歌渙澤，擊石樂承平。", "鉅肇重華榜，高吟刻萃瑛。", "雖無丹雘構，三絕足垂名。"]'),
('b849118d-dc4a-4944-9f2a-cdb7a9b116b2','和詣巖祈雨','皇甫韶','宋','宋诗','song-poetry','','[]','路盡山尤勝，溪深水愈豪。',24,'全唐诗/poet.song.253000.json','["路盡山尤勝，溪深水愈豪。", "寺樓今不見，依舊五峰高。"]'),
('d6034e4f-38e9-4210-ab89-17a5d7270fa2','王官瀑布','雷臨','宋','宋诗','song-poetry','','[]','區區奔走漫華顛，一別王官十四年。',32,'全唐诗/poet.song.253000.json','["區區奔走漫華顛，一別王官十四年。", "綠玉峽中噴白玉，溉田澆竹滿平川。"]'),
('f331d431-a7f0-47be-abe7-80ef8bbe7c26','羅漢寺','段讓','宋','宋诗','song-poetry','','[]','解職歸來謝世譁，東風閒步到僧家。',32,'全唐诗/poet.song.253000.json','["解職歸來謝世譁，東風閒步到僧家。", "何時許我棲雲榻，夜掃寒爐煮雪花。"]'),
('1027a511-a9db-4643-86f2-26673799a7eb','吳山縣','丁带','宋','宋诗','song-poetry','','[]','瀟灑吳山縣，居民近百家。',48,'全唐诗/poet.song.253000.json','["瀟灑吳山縣，居民近百家。", "孤城連阜起，小市枕溪斜。", "土潤宜栽竹，泉甘好試茶。", "公餘無一事，何處息紛華。"]'),
('d4a1d630-5faf-4041-8b2c-19a9b85a3a2b','祁山堡','胡明善','宋','宋诗','song-poetry','','[]','卧龍扶漢室，躍馬阨秦原。',48,'全唐诗/poet.song.253000.json','["卧龍扶漢室，躍馬阨秦原。", "星落干戈死，山空雲鳥存。", "昏鴉啼古戍，秋水咽孤村。", "愁讀出師表，凄凄傷我魂。"]'),
('0ecaec31-6132-431b-a3ab-23b52d3927b5','岳陽','張天啟','宋','宋诗','song-poetry','','[]','天入平湖遠，樓深納霽華。',48,'全唐诗/poet.song.253000.json','["天入平湖遠，樓深納霽華。", "青山藏福地，碧樹記人家。", "水落魚龍蟄，風高雁鶩斜。", "古來形勝地，何事憶長沙。"]'),
('8d20ee53-ec16-4c31-abb5-4bdb016b52b2','通天巖','歐演','宋','宋诗','song-poetry','','[]','每逢勝境便留神，一路桃花別漢秦。',64,'全唐诗/poet.song.253000.json','["每逢勝境便留神，一路桃花別漢秦。", "繞剎苔封高士蹟，臨溪客問野人津。", "紆回松竹看非俗，羅列山川識有真。", "踏遍嶺頭天尺五，飄飄已覺迥風塵。"]'),
('e3c5ace2-c6b9-4a51-bf64-9dd2655d06d7','滕王閣','釋晦機','宋','宋诗','song-poetry','','["\u957f\u6c5f", "\u6ed5\u738b\u9601"]','檻外長江去不迴，檻前楊柳後人栽。',32,'全唐诗/poet.song.253000.json','["檻外長江去不迴，檻前楊柳後人栽。", "當時唯有西山在，曾見滕王歌舞來。"]'),
('81a993e8-4ec9-496f-bcff-36aa9fdcb748','羅霄洞','釋德最','宋','宋诗','song-poetry','','[]','江南三月春無邊，谿竹十里花爭妍。',32,'全唐诗/poet.song.253000.json','["江南三月春無邊，谿竹十里花爭妍。", "兒童且莫吹羌管，我欲臨流枕石眠。"]'),
('5a212e60-b89d-4a59-9edd-f90a52e5eb58','東皋彈琴','釋愻','宋','宋诗','song-poetry','','[]','落葉秋滿庭，夜深月臨沼。',24,'全唐诗/poet.song.253000.json','["落葉秋滿庭，夜深月臨沼。", "獨坐彈素琴，知音有魚鳥。"]'),
('c695cba1-a519-4146-b642-133b9dbc29d6','澹山巖','釋紹瑶','宋','宋诗','song-poetry','','[]','使君得佳句，簡存如猗那。',24,'全唐诗/poet.song.253000.json','["使君得佳句，簡存如猗那。", "着之巖石中，千古不可磨。"]'),
('7e8acac3-e456-4b25-a1e6-f06c66a91e50','詩一首','王時','宋','宋诗','song-poetry','','[]','□□□□□□□，□□□□□□□。',64,'全唐诗/poet.song.253000.json','["□□□□□□□，□□□□□□□。", "□□□□□□□，旋復東秦舊版圖。", "動若汾陽年最少，戰如廣固勢同符。", "掀天勛業磨崖勒，萬古英烈隘八區。"]'),
('a6c1279c-0a88-4819-9a97-cd611a24b21e','題翟公','崔某','宋','宋诗','song-poetry','','[]','三仕寧爲喜，一閑當自修。',24,'全唐诗/poet.song.253000.json','["三仕寧爲喜，一閑當自修。", "世情今似古，何必謝交游。"]'),
('76700d5a-4d84-4cfd-8c79-1d63183779a7','詠曹彬','馬某','宋','宋诗','song-poetry','','[]','王師競下九天來，□甕江城一戰開。',32,'全唐诗/poet.song.253000.json','["王師競下九天來，□甕江城一戰開。", "蓋世榮華□不□，滿船同籍送軍臺。"]'),
('9d56054f-5288-49ce-bff7-44c65459602a','秋江漁樂圖爲邑人宗正純撰','姜德明','宋','宋诗','song-poetry','','[]','楓樹蕭蕭霜葉紅，蘆花瑟瑟鳴西風。',226,'全唐诗/poet.song.253000.json','["楓樹蕭蕭霜葉紅，蘆花瑟瑟鳴西風。", "漁翁舉網秋江上，輕舟一葉波溶溶。", "群魚遊泳影相續，密網收來心易足。", "赤鱗素質影跳空，玉尺金梭光炫目。", "鼓枻歸來日未斜，腥風吹入比鄰家。", "家人出戶歡相迓，笑舉魚筐還自誇。", "老妻汲泉向江口，稚子攀條折楊柳。", "汲泉炊水待烹鱗，貫柳携魚去沽酒。", "黄昏燈火羅盤餐，妻兒笑語娛團欒。", "況值時清少徵稅，一生未解愁饑寒。", "却笑商人輕遠別，寒帳孤眠怨妻妾。", "更憐農父在西疇，年豐則喜荒則憂。", "何如漁者生涯寄江水，取之無窮用不已。", "朝復暮兮醉復醒，長年嘯傲烟波裏。"]'),
('7f8e5dd5-5dc5-4df3-afa3-947081d262dc','自題歲寒堂','余瀚','宋','宋诗','song-poetry','','[]','書堂高構歲寒巔，水秀山明隔市廛。',32,'全唐诗/poet.song.253000.json','["書堂高構歲寒巔，水秀山明隔市廛。", "兩岸柳風吹道骨，一溪梧月浸心天。"]'),
('58bf0c31-3b76-4777-847b-d903c267e0bf','設醮洞霄因以古詩記其事','章承道','宋','宋诗','song-poetry','','[]','鶴鳴在野聲聞天，靈壇夜醮朝群仙。',72,'全唐诗/poet.song.253000.json','["鶴鳴在野聲聞天，靈壇夜醮朝群仙。", "群仙乘風駕雲軿，一一來自虛皇前。", "玉鑪不散香凝煙，火中金縷光相連。", "仙官謂我帝所憐，百拜向帝臣有言，願乞臣母千斯年。"]'),
('6d7f28eb-bcc3-4e7a-ba6b-570caf4a567c','秋日渡江','黄極','宋','宋诗','song-poetry','','[]','雁落平沙一雨收，淡烟斜日荻花洲。',32,'全唐诗/poet.song.253000.json','["雁落平沙一雨收，淡烟斜日荻花洲。", "憑誰與作王摩詰，爲寫江南水墨秋。"]'),
('ac84fc60-9cd5-4558-b035-10647d28bff8','江上','吳叔元','宋','宋诗','song-poetry','','[]','獨坐江之涘，高秋葉落時。',48,'全唐诗/poet.song.253000.json','["獨坐江之涘，高秋葉落時。", "風狂疑水立，雲動覺天移。", "浦遠孤鷗沒，溪平小艇遲。", "徘徊待月上，把酒寄遐思。"]'),
('239783c4-b63c-4978-9cb4-6f633f92cbde','宋武帝廟','楊雯','宋','宋诗','song-poetry','','[]','溪聲答松風，巨石出老拳。',180,'全唐诗/poet.song.253000.json','["溪聲答松風，巨石出老拳。", "古樹不知名，岌岌蛟龍纏。", "夕陰互出沒，秋華带芳鮮。", "葱葱帝王氣，棟宇垂千年。", "虎賁秉霜戟，慘淡生雲烟。", "宮人翠龍駕，手持玉連蜷。", "昌明坐恍惚，精神雷在天。", "大呼司雍間，旬月無秦燕。", "昔爲萬夫特，今受衆目憐。", "石馬亦埋沒，歲時草芊芊。", "小臣異代士，見之淚迸泉。", "齊人思爽鳩，蜀人哀杜鵑。", "江東舊正朔，禮奉敢不虔。", "但願君王心，不忘載荻船。", "下山又再拜，白日當空懸。"]'),
('54fcfc8c-772b-4328-87bb-c5002785b36a','迢迢空同山','楊雯','宋','宋诗','song-poetry','','[]','迢迢空同山，乃在西極巔。',84,'全唐诗/poet.song.253000.json','["迢迢空同山，乃在西極巔。", "玉泉蔭靈芝，上有千歲仙。", "安得凌風翼，相從白雲間。", "神仙本冥漠，天運乃推遷。", "不如酌我酒，或得成自然。", "田父要我語，飲者亦非賢。", "願君長獨醒，加餐足高年。"]'),
('ad7c2efa-12b5-41dc-8af3-f97d18c0fa42','北客','楊雯','宋','宋诗','song-poetry','','[]','北客相催發，一日舉千帆。',24,'全唐诗/poet.song.253000.json','["北客相催發，一日舉千帆。", "遥憐庾開府，歲晚望江南。"]'),
('77e25462-0711-4e0c-b260-c3938d6a4d87','宿峽市','楊雯','宋','宋诗','song-poetry','','[]','人烟正摇落，樓笛頗清圓。',48,'全唐诗/poet.song.253000.json','["人烟正摇落，樓笛頗清圓。", "老樹依山驛，東風上峽船。", "江湖萬里外，燈火十年前。", "世路能令老，吾生且醉眠。"]'),
('1b41bc2f-5ecb-42d1-993d-3efcdbaf742c','早春','楊雯','宋','宋诗','song-poetry','','[]','不知何處碧雲鄉，冉冉平生可斷腸。',64,'全唐诗/poet.song.253000.json','["不知何處碧雲鄉，冉冉平生可斷腸。", "怪底乾坤惟夢短，老來歲月更心長。", "城頭急鼓千家怨，江上殘梅一水香。", "自作醉侯開醉國，笑人奔走爲誰忙。"]'),
('536b1c52-b9f9-489c-a88b-f79dc3b98bf1','遊觀山','楊雯','宋','宋诗','song-poetry','','[]','古寺隠山腹，蒼苔行地衣。',72,'全唐诗/poet.song.253000.json','["古寺隠山腹，蒼苔行地衣。", "岑寂少人迹，路纔一線微。", "問誰促公行，一句山谷詩。", "閒來就湯沐，聊叩幽人扉。", "相投一杯水，氣味如曹溪。", "興盡即云返，重到還無期。"]'),
('c69e49dd-e4f4-4afd-a345-346ff01a7f59','玉山','楊雯','宋','宋诗','song-poetry','','[]','霞衣玉珮去飄飄，控鶴仙人不可招。',32,'全唐诗/poet.song.253000.json','["霞衣玉珮去飄飄，控鶴仙人不可招。", "難信嶺頭頑石畔，分明有路入青霄。"]'),
('1fa0232f-83ff-4755-b892-fb8ce23d3aaf','大滌洞  其一','洪師中','宋','宋诗','song-poetry','','[]','搗藥禽啼雨後山，千巖萬谷鎖蒼寒。',32,'全唐诗/poet.song.253000.json','["搗藥禽啼雨後山，千巖萬谷鎖蒼寒。", "一溪春水高三尺，書畫船中更好看。"]'),
('49bbc2f2-2b52-45a6-8f30-d907c846047c','大滌洞  其二','洪師中','宋','宋诗','song-poetry','','[]','九曲青山一曲溪，仙人住處自春遲。',32,'全唐诗/poet.song.253000.json','["九曲青山一曲溪，仙人住處自春遲。", "筍輿切莫匆匆返，要作春行卷裏詩。"]'),
('93e57df5-74af-4ae3-b53c-4e7919595a8a','題玉壺洞','玉壺洞客','宋','宋诗','song-poetry','','[]','洞前流水碧于苔，洞口桃花撲面開。',32,'全唐诗/poet.song.253000.json','["洞前流水碧于苔，洞口桃花撲面開。", "轉頭望斷意不斷，長嘯一聲須再來。"]'),
('ed61afc2-6539-4938-9c4d-08143223f126','義試詩 孔明草廬圖','無名氏','宋','宋诗','song-poetry','','[]','南陽高卧屈將軍，往事流傳水墨昏。',32,'全唐诗/poet.song.253000.json','["南陽高卧屈將軍，往事流傳水墨昏。", "莫訝軸閑茅屋小，箇中藏得漢乾坤。"]'),
('94f97cec-292e-4582-a4d9-d0460a8f3497','義試詩 葡萄月','無名氏','宋','宋诗','song-poetry','','[]','春藤上架翠成窩，顆顆圓光得月多。',32,'全唐诗/poet.song.253000.json','["春藤上架翠成窩，顆顆圓光得月多。", "疑是蘂珠開夕宴，結成珠帳待常娥。"]'),
('ca0891cd-5ba0-4510-bc39-9c1ef8c793c8','逍遥觀','無名氏','宋','宋诗','song-poetry','','[]','昔設黄婆舊酒壚，如何今日似蓬壺。',32,'全唐诗/poet.song.253000.json','["昔設黄婆舊酒壚，如何今日似蓬壺。", "只因王郭仙人過，化作青城上帝都。"]'),
('f19de8c0-86d3-4a48-934f-7b16f80f5d7c','題龍居寺','王敖道','宋','宋诗','song-poetry','','[]','靈剎倚山光，無塵染洞房。',48,'全唐诗/poet.song.253000.json','["靈剎倚山光，無塵染洞房。", "雲籠金地暖，龍噴玉泉香。", "松竹分幽逕，樓臺聳上方。", "蓬壺人到此，僧伴遶迴廊。"]'),
('56fcc039-3f47-4585-b1c8-a25f27a8966a','寄道友','趙子甄','宋','宋诗','song-poetry','','[]','秦川蟬蛻已三回，明月清風任去來。',32,'全唐诗/poet.song.253000.json','["秦川蟬蛻已三回，明月清風任去來。", "寄語沖虛諸道友，芒鞋竹杖不須埋。"]'),
('6c6faabf-1960-44c5-b275-0bc6d52a3ea8','句','吳夢陽','宋','宋诗','song-poetry','','[]','氣蒸不待薪，水活可烹鼎。',12,'全唐诗/poet.song.253000.json','["氣蒸不待薪，水活可烹鼎。"]'),
('700ffb59-9f57-430c-b04e-c878ea4884fb','題桃花源','龔桂馨','宋','宋诗','song-poetry','','[]','碧樹花開醉晚春，靈槎幾度汎天津。',32,'全唐诗/poet.song.253000.json','["碧樹花開醉晚春，靈槎幾度汎天津。", "可憐太守仙緣薄，不是衣冠不屬秦。"]'),
('640cd6ac-dc0e-4271-a22d-2222ee0f4c75','樵川江行','李公晦','宋','宋诗','song-poetry','','[]','避人忘井邑，躭靜步郊原。',48,'全唐诗/poet.song.253000.json','["避人忘井邑，躭靜步郊原。", "落葉風能掃，寒花霜更繁。", "山空樵響答，灘淺楫聲喧。", "願結山陽伴，長年共灌園。"]'),
('a5583156-d855-40d3-b55c-2e9c8d21f647','鏡湖','張惟中','宋','宋诗','song-poetry','','[]','昔年曾過賀家湖，今日烟波太半無。',32,'全唐诗/poet.song.253000.json','["昔年曾過賀家湖，今日烟波太半無。", "惟有一天秋夜月，不隨田畝入官租。"]'),
('1469ac26-4a64-422a-a5a1-47c9b54896e9','遊瑞巖','林誠仲','宋','宋诗','song-poetry','','[]','巖半松門敞不關，芒鞋竹杖重躋攀。',64,'全唐诗/poet.song.253000.json','["巖半松門敞不關，芒鞋竹杖重躋攀。", "天涵鑑水澄清裏，人入披雲杳藹間。", "燒藥爐寒烟草碧，鎸詩石古雨苔斑。", "干戈滿目何從適，日日青山共往還。"]'),
('6cd22510-b9de-43b2-8fdd-776bc98bb7fb','玉山聽泉','吳孔錡','宋','宋诗','song-poetry','','[]','鳴泉出澗潔而瑩，盡日鏘鏘解佩聲。',32,'全唐诗/poet.song.253000.json','["鳴泉出澗潔而瑩，盡日鏘鏘解佩聲。", "絕俗不須頻洗耳，試聽餘響自心清。"]'),
('e79e815f-5872-4ca1-af92-565d85c85b25','遺愛祠','陳成己','宋','宋诗','song-poetry','','[]','水自湖心一派分，高低晚望稻垂雲。',32,'全唐诗/poet.song.253000.json','["水自湖心一派分，高低晚望稻垂雲。", "侵魚爭畔人如鬼，莫向祠前聽祭文。"]'),
('cd4cbdbd-b4f1-488c-8421-937283fcc9cb','秀峰院','鮑承議','宋','宋诗','song-poetry','','[]','平田千頃綠秧稠，水繞山阿出澗流。',32,'全唐诗/poet.song.253000.json','["平田千頃綠秧稠，水繞山阿出澗流。", "門掩落花春自晚，畫簷時聽鳥聲幽。"]');
